"""
FastAPI entry point — clean architecture.
- Admin panel at /admin  (FastAPI router, Jinja2)
- Chainlit chat at /      (mount_chainlit)

CHAINLIT_ROOT_PATH must be "" so frontend JS gets correct rootPath (not null).
Run: uvicorn main:app --host 0.0.0.0 --port 8080
"""
import sys
import os
from pathlib import Path

# ── Path setup — must happen before any local imports ──────────────────────
BASE_DIR = Path(__file__).parent
MCP_SERVER_DIR = BASE_DIR / "mcp-server"
sys.path.insert(0, str(MCP_SERVER_DIR))

from dotenv import load_dotenv
load_dotenv(BASE_DIR / ".env", override=True)

# ── CRITICAL: set before ANY chainlit import ────────────────────────────────
# Without this, chainlit sends rootPath=null to the frontend → startsWith crash
os.environ["CHAINLIT_ROOT_PATH"] = ""

# Also unify API keys so google-genai SDK picks the right one
_api_key = os.environ.get("GOOGLE_API_KEY") or os.environ.get("GEMINI_API_KEY", "")
if _api_key:
    os.environ["GOOGLE_API_KEY"] = _api_key
    os.environ["GEMINI_API_KEY"] = _api_key

from fastapi import FastAPI, Request as _AuthRequest, Response as _AuthResponse
from fastapi.responses import RedirectResponse
try:
    from chainlit.utils import mount_chainlit
except ImportError:
    mount_chainlit = None  # Chainlit optional — custom chat page at / is used instead

from shared.db import init_admin_tables
from admin.router import router as admin_router

init_admin_tables()

app = FastAPI(title="Alex Insurance Broker")

# ── Dashboard authentication ──────────────────────────────────────────────
_DASHBOARD_PASSWORD = os.environ.get("DASHBOARD_PASSWORD", "alex2026")

def _check_dashboard_auth(request: _AuthRequest) -> bool:
    """Check if request is authenticated for dashboard access."""
    if request.cookies.get("alex_auth") == _DASHBOARD_PASSWORD:
        return True
    if request.query_params.get("key") == _DASHBOARD_PASSWORD:
        return True
    return False

@app.get("/login")
async def login_page(error: str = ""):
    from fastapi.responses import HTMLResponse as _LoginHTML
    err_msg = '<p style="color:#d14545;margin-top:8px">Falsches Passwort</p>' if error else ""
    return _LoginHTML(content=f"""<!DOCTYPE html>
<html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>Alex — Login</title>
<style>*{{box-sizing:border-box;margin:0;padding:0}}body{{font-family:'Inter',system-ui,sans-serif;background:#f5f7fa;display:flex;justify-content:center;align-items:center;min-height:100vh}}
.login-card{{background:white;border-radius:16px;padding:40px;width:360px;box-shadow:0 4px 24px rgba(0,0,0,0.08)}}
h1{{font-size:1.3em;color:#172a45;text-align:center;margin-bottom:20px}}
input{{width:100%;padding:10px 14px;border:1px solid #d8dde5;border-radius:8px;font-size:0.95em;margin-bottom:12px}}
button{{width:100%;padding:10px;border:none;border-radius:8px;background:linear-gradient(135deg,#29a088,#33b89a);color:white;font-weight:600;font-size:0.95em;cursor:pointer}}
button:hover{{opacity:0.9}}</style></head><body>
<div class="login-card">
<h1>🔐 Alex Dashboard</h1>
<form method="POST" action="/login">
<input type="password" name="password" placeholder="Passwort" autofocus>
<button type="submit">Anmelden</button>
</form>{err_msg}
</div></body></html>""")

@app.post("/login")
async def login_submit(request: _AuthRequest):
    form = await request.form()
    pw = form.get("password", "")
    if pw == _DASHBOARD_PASSWORD:
        resp = RedirectResponse("/dashboard", status_code=302)
        resp.set_cookie("alex_auth", _DASHBOARD_PASSWORD, max_age=86400 * 7, httponly=True, samesite="lax")
        return resp
    return RedirectResponse("/login?error=1", status_code=302)

@app.get("/logout")
async def logout():
    resp = RedirectResponse("/login", status_code=302)
    resp.delete_cookie("alex_auth")
    return resp

from starlette.middleware.base import BaseHTTPMiddleware as _BaseMiddleware

class _DashboardAuthMiddleware(_BaseMiddleware):
    """Protect /dashboard/* and /admin/* routes with cookie/key auth."""
    async def dispatch(self, request, call_next):
        path = request.url.path
        if path.startswith("/dashboard") or path.startswith("/admin"):
            if not _check_dashboard_auth(request):
                return RedirectResponse("/login", status_code=302)
        return await call_next(request)

app.add_middleware(_DashboardAuthMiddleware)

# ── Admin routes — BEFORE mount_chainlit ───────────────────────────────────
app.include_router(admin_router, prefix="/admin")

@app.get("/admin")
async def admin_redirect():
    return RedirectResponse("/admin/", status_code=302)


# ── Unified 5-tab navigation ─────────────────────────────────────────────────
def _nav_html(active="dashboard"):
    """Render the unified 5-tab navigation bar for all dashboard pages."""
    tabs = [
        ("chat", "\U0001F4AC", "Chat", "/"),
        ("dashboard", "\U0001F4CA", "Dashboard", "/dashboard"),
        ("cases", "\U0001F4CB", "Fälle", "/dashboard/cases"),
        ("inbox", "\U0001F4E7", "Inbox", "/dashboard/inbox"),
        ("templates", "\U0001F527", "Templates", "/dashboard/templates"),
        ("settings", "\u2699\uFE0F", "Einstellungen", "/dashboard/settings"),
        ("help", "❓", "Hilfe", "/dashboard/help"),
    ]
    items = ""
    for tid, icon, label, href in tabs:
        cls = ' class="active"' if tid == active else ""
        items += f'<a href="{href}"{cls}>{icon} {label}</a>'
    return f'''<style>
.dash-nav{{display:flex;gap:0;background:linear-gradient(135deg,#0f1f35,#172a45,#1e3652);padding:0 16px;position:sticky;top:0;z-index:100;box-shadow:0 2px 8px rgba(0,0,0,0.15)}}
.dash-nav a{{color:rgba(240,244,248,0.65);text-decoration:none;padding:14px 18px;font-size:13px;font-weight:500;transition:all 150ms;border-bottom:2px solid transparent;font-family:'Inter',system-ui,sans-serif}}
.dash-nav a:hover{{color:#f0f4f8;background:rgba(255,255,255,0.06)}}
.dash-nav a.active{{color:#ffffff;border-bottom-color:#29a088;font-weight:600;background:rgba(41,160,136,0.08)}}
</style>
<nav class="dash-nav">{items}</nav>'''



