# ── German date formatting helper ────────────────────────────────────────────
def _format_date_de(iso_str: str) -> str:
    """Convert ISO date string to DD.MM.YYYY or DD.MM.YYYY HH:MM format."""
    if not iso_str:
        return ""
    try:
        from datetime import datetime as _dt_fmt
        # Handle various ISO formats
        s = str(iso_str).replace("Z", "+00:00")
        for fmt in ("%Y-%m-%dT%H:%M:%S.%f%z", "%Y-%m-%dT%H:%M:%S%z", "%Y-%m-%dT%H:%M:%S.%f", "%Y-%m-%dT%H:%M:%S", "%Y-%m-%dT%H:%M", "%Y-%m-%d"):
            try:
                dt = _dt_fmt.strptime(s[:len(fmt)+5], fmt)
                if "T" in iso_str and ":" in iso_str.split("T")[-1]:
                    return dt.strftime("%d.%m.%Y %H:%M")
                return dt.strftime("%d.%m.%Y")
            except (ValueError, IndexError):
                continue
        # Fallback: manual parse
        parts = iso_str[:10].split("-")
        if len(parts) == 3:
            return f"{parts[2]}.{parts[1]}.{parts[0]}"
    except Exception:
        pass
    return iso_str

