@app.get("/health")
@app.get("/api/health")
async def health():
    import datetime as _hdt
    try:
        _sched_ok = _scheduler.running if '_scheduler' in globals() and _scheduler else False
        _sched_jobs = len(_scheduler.get_jobs()) if '_scheduler' in globals() and _scheduler else 0
    except: _sched_ok = False; _sched_jobs = 0
    return {
        "status": "ok",
        "version": "rev-00129-cover-conditional",
        "timestamp": _hdt.datetime.utcnow().isoformat() + "Z",
        "scheduler_running": _sched_ok,
        "scheduler_jobs": _sched_jobs,
        "firestore_connected": bool(_fs_db),
        "smtp_configured": bool(os.environ.get("SMTP_USER")),
        "imap_configured": bool(os.environ.get("IMAP_USER")),
    }

@app.get("/api/dashboard/kpis")
async def api_dashboard_kpis():
    """Server-side KPI computation (avoids downloading all submissions client-side)."""
    import datetime as _kdt
    try:
        subs = _cached_fs_all("form_submissions")
        today = _kdt.datetime.utcnow().date().isoformat()
        total = len(subs)
        complete = sum(1 for s in subs if (s.get("completeness_pct") or s.get("completeness") or 0) >= 100)
        incomplete = sum(1 for s in subs if s.get("status") in ("incomplete", "incomplete_resent", "sent"))
        today_new = sum(1 for s in subs if today in str(s.get("created_at", "")))
        total_compl = sum((s.get("completeness_pct") or s.get("completeness") or 0) for s in subs)
        avg = int(total_compl / max(total, 1))
        # Overdue = incomplete cases older than 4 days
        overdue = 0
        _now = _kdt.datetime.utcnow()
        for s in subs:
            if s.get("status") in ("incomplete", "incomplete_resent"):
                try:
                    _c = str(s.get("created_at", "")).replace("Z", "").split(".")[0]
                    if _c:
                        _cd = _kdt.datetime.fromisoformat(_c)
                        if (_now - _cd).days > 4:
                            overdue += 1
                except: pass
        return {
            "total": total,
            "complete": complete,
            "incomplete": incomplete,
            "today_new": today_new,
            "avg_completeness": avg,
            "overdue": overdue,
        }
    except Exception as _e:
        return {"error": str(_e), "total": 0, "complete": 0, "incomplete": 0, "today_new": 0, "avg_completeness": 0, "overdue": 0}

# ── API endpoints for n8n / external automation ─────────────────────────────
# These endpoints expose broker tools as REST API for workflow automation.
# n8n connects via HTTP Request nodes to trigger renewals, reports, etc.

from fastapi import Query
from fastapi.responses import JSONResponse
import json
import logging as _logging

_log = _logging.getLogger("alex-broker")

# ── Firestore PRIMARY storage helpers ─────────────────────────────────────
from google.cloud import firestore as _firestore_mod

_fs_project = os.environ.get("FIRESTORE_PROJECT", "project-79fa7e7d-5de7-4c32-b09")
try:
    _fs_db = _firestore_mod.Client(project=_fs_project)
    _log.info("Firestore connected (PRIMARY storage)")
except Exception as _fs_init_err:
    _log.error(f"Firestore init failed: {_fs_init_err}")
    _fs_db = None


def _fs_get(collection: str, doc_id: str) -> dict | None:
    """Get a document from Firestore."""
    doc = _fs_db.collection(collection).document(doc_id).get()
    return doc.to_dict() if doc.exists else None


def _fs_set(collection: str, doc_id: str, data: dict, merge: bool = True):
    """Set/update a document in Firestore."""
    _fs_db.collection(collection).document(doc_id).set(data, merge=merge)


def _fs_add(collection: str, data: dict) -> str:
    """Add a document with auto-generated ID."""
    _, ref = _fs_db.collection(collection).add(data)
    return ref.id


def _fs_query(collection: str, filters: list = None, order_by: tuple = None,
              limit: int = 100) -> list[dict]:
    """Query documents from a collection.
    filters: list of (field, op, value) tuples
    order_by: (field_name,) or (field_name, direction)
    """
    ref = _fs_db.collection(collection)
    if filters:
        for field, op, value in filters:
            ref = ref.where(filter=_firestore_mod.FieldFilter(field, op, value))
    if order_by:
        direction = order_by[1] if len(order_by) > 1 else _firestore_mod.Query.DESCENDING
        ref = ref.order_by(order_by[0], direction=direction)
    docs = ref.limit(limit).stream()
    return [{**doc.to_dict(), '_id': doc.id} for doc in docs]


def _fs_delete(collection: str, doc_id: str):
    """Delete a document."""
    _fs_db.collection(collection).document(doc_id).delete()


def _fs_count(collection: str, filters: list = None) -> int:
    """Count documents in a collection (with optional filters)."""
    ref = _fs_db.collection(collection)
    if filters:
        for field, op, value in filters:
            ref = ref.where(filter=_firestore_mod.FieldFilter(field, op, value))
    result = ref.count().get()
    return result[0][0].value if result and result[0] else 0


def _fs_update(collection: str, doc_id: str, data: dict):
    """Update specific fields on an existing document."""
    _fs_db.collection(collection).document(doc_id).update(data)


def _fs_all(collection: str, limit: int = 1000) -> list[dict]:
    """Get all documents from a collection."""
    docs = _fs_db.collection(collection).limit(limit).stream()
    return [{**doc.to_dict(), '_id': doc.id} for doc in docs]


# ── Firestore Cache with TTL ────────────────────────────────────────────────
import time as _time_mod
_data_cache = {}

def _cached_fs_all(collection, ttl=60):
    now = _time_mod.time()
    key = collection
    if key not in _data_cache or now - _data_cache[key].get("ts", 0) > ttl:
        _data_cache[key] = {"data": _fs_all(collection), "ts": now}
    return _data_cache[key]["data"]

def _invalidate_cache(collection=None):
    if collection:
        _data_cache.pop(collection, None)
    else:
        _data_cache.clear()


# ── Token Counter + Stats ────────────────────────────────────────────────────
_daily_tokens = {"date": "", "input": 0, "output": 0, "calls": 0, "cost_usd": 0.0}
_daily_tokens_loaded = False

def _token_stats_load():
    """Hydrate _daily_tokens from Firestore for today (cold-start resilient)."""
    global _daily_tokens_loaded
    if _daily_tokens_loaded: return
    try:
        today = __import__("datetime").datetime.utcnow().strftime("%Y-%m-%d")
        _row = _fs_get("token_stats", today)
        if _row and isinstance(_row, dict):
            _daily_tokens["date"] = today
            _daily_tokens["input"] = int(_row.get("input", 0) or 0)
            _daily_tokens["output"] = int(_row.get("output", 0) or 0)
            _daily_tokens["calls"] = int(_row.get("calls", 0) or 0)
            _daily_tokens["cost_usd"] = float(_row.get("cost_usd", 0.0) or 0.0)
    except Exception:
        pass
    _daily_tokens_loaded = True

def _track_tokens(input_tokens, output_tokens):
    today = __import__("datetime").datetime.utcnow().strftime("%Y-%m-%d")
    _token_stats_load()
    if _daily_tokens["date"] != today:
        _daily_tokens["date"] = today
        _daily_tokens["input"] = 0
        _daily_tokens["output"] = 0
        _daily_tokens["calls"] = 0
        _daily_tokens["cost_usd"] = 0.0
        # New day — try to hydrate existing row (in case of mid-day restart)
        try:
            _row = _fs_get("token_stats", today)
            if _row and isinstance(_row, dict):
                _daily_tokens["input"] = int(_row.get("input", 0) or 0)
                _daily_tokens["output"] = int(_row.get("output", 0) or 0)
                _daily_tokens["calls"] = int(_row.get("calls", 0) or 0)
                _daily_tokens["cost_usd"] = float(_row.get("cost_usd", 0.0) or 0.0)
        except Exception:
            pass
    _daily_tokens["input"] += input_tokens
    _daily_tokens["output"] += output_tokens
    _daily_tokens["calls"] += 1
    _daily_tokens["cost_usd"] = (_daily_tokens["input"] * 3 + _daily_tokens["output"] * 15) / 1_000_000
    # Persist to Firestore (best-effort, non-blocking semantics)
    try:
        _fs_set("token_stats", today, {
            "date": today,
            "input": _daily_tokens["input"],
            "output": _daily_tokens["output"],
            "calls": _daily_tokens["calls"],
            "cost_usd": _daily_tokens["cost_usd"],
            "updated_at": __import__("datetime").datetime.utcnow().isoformat(),
        }, merge=True)
    except Exception:
        pass


def _fs_sub_to_dict(d: dict) -> dict:
    """Normalize a form_submissions Firestore doc for API response.
    Ensures form_data/attachments/ai_validation are dicts/lists not strings."""
    if isinstance(d.get("form_data"), str):
        d["form_data"] = json.loads(d["form_data"] or "{}")
    elif d.get("form_data") is None:
        d["form_data"] = {}
    if isinstance(d.get("attachments"), str):
        d["attachments"] = json.loads(d["attachments"] or "[]")
    elif d.get("attachments") is None:
        d["attachments"] = []
    # Normalize attachment field names: filename<->name, content_type<->mime
    # Different storage paths used different key names — expose both for compatibility
    _normalized_atts = []
    for _att in (d.get("attachments") or []):
        if not isinstance(_att, dict):
            _normalized_atts.append(_att); continue
        _a = dict(_att)
        if not _a.get("name") and _a.get("filename"):
            _a["name"] = _a["filename"]
        elif not _a.get("filename") and _a.get("name"):
            _a["filename"] = _a["name"]
        if not _a.get("mime") and _a.get("content_type"):
            _a["mime"] = _a["content_type"]
        elif not _a.get("content_type") and _a.get("mime"):
            _a["content_type"] = _a["mime"]
        _normalized_atts.append(_a)
    d["attachments"] = _normalized_atts
    if isinstance(d.get("ai_validation"), str):
        d["ai_validation"] = json.loads(d["ai_validation"] or "null")
    if isinstance(d.get("ai_hypothesis"), str):
        d["ai_hypothesis"] = json.loads(d["ai_hypothesis"] or "null")
    if not d.get("form_url") and d.get("template_id"):
        d["form_url"] = f"/forms/{d.get('template_id', '')}?sub={d.get('_id', d.get('id', ''))}"
    # Ensure numeric fields are numbers
    if d.get("completeness_pct") is not None:
        d["completeness_pct"] = int(d.get("completeness_pct", 0) or 0)
    if d.get("reminder_count") is not None:
        d["reminder_count"] = int(d.get("reminder_count", 0) or 0)
    return d


