@app.get("/api/audit")
async def api_audit_by_entity(entity_id: str = Query(default=""), entity_type: str = Query(default=""),
                               limit: int = Query(default=50, ge=1, le=500)):
    """Query audit trail for a specific entity (e.g. AKT-xxx, sub-xxx)."""
    filters = []
    if entity_id:
        filters.append(("entity_id", "==", entity_id))
    elif entity_type:
        filters.append(("entity_type", "==", entity_type))
    rows = _fs_query("audit_trail", filters=filters if filters else None,
                     order_by=("created_at", _firestore_mod.Query.DESCENDING), limit=limit)
    return {"items": rows, "total": len(rows)}


@app.get("/api/audit/recent")
async def api_audit_recent(limit: int = Query(default=50, ge=1, le=500)):
    """Get recent audit trail activity."""
    rows = _fs_query("audit_trail", order_by=("created_at", _firestore_mod.Query.DESCENDING), limit=limit)
    return {"items": rows, "total": len(rows)}


