def _greeting_for(name: str, kontaktperson: str | None = None) -> str:
    """Return appropriate German greeting. Use formal for companies, personal for individuals.
    If kontaktperson is provided, always use it for greeting (e.g. company with named contact).
    """
    if kontaktperson:
        return f"Guten Tag {kontaktperson},"
    _company_suffixes = ("GmbH", "eG", " AG", "SRL", "Ltd", "Inc", " KG", "OHG", "UG", "e.G.", "GbR", "e.V.")
    if name and any(s.lower() in name.lower() for s in _company_suffixes):
        return "Sehr geehrte Damen und Herren,"
    return f"Guten Tag {name}," if name else "Sehr geehrte Damen und Herren,"

def _send_email_html(to_list: list, subject: str, html: str, attachments: list | None = None,
                     bcc: list | None = None, auto_bcc_operator: bool = False) -> bool:
    """Send HTML email via SMTP. Supports optional file attachments and BCC.
    attachments: list of dicts [{"filename": "x.pdf", "content": bytes, "mime": "application/pdf"}, ...]
    bcc: explicit BCC list. auto_bcc_operator: if True, auto-adds OPERATOR_EMAIL to BCC.
    """
    import smtplib
    from email.mime.multipart import MIMEMultipart
    from email.mime.text import MIMEText
    from email.mime.base import MIMEBase
    from email import encoders
    from email.header import Header as _Header
    smtp_host = os.environ.get("SMTP_HOST", "smtp.gmail.com")
    smtp_port = int(os.environ.get("SMTP_PORT", "587"))
    smtp_user = os.environ.get("SMTP_USER", "")
    smtp_pass = os.environ.get("SMTP_PASS", "")
    from_name = os.environ.get("SMTP_FROM_NAME", "Alex Insurance Broker")
    if not smtp_user or not smtp_pass:
        _log.warning("SMTP not configured — email to %s skipped", to_list)
        return True  # pretend success if not configured
    # Build BCC list
    _bcc_list = list(bcc or [])
    if auto_bcc_operator:
        _op = os.environ.get("OPERATOR_EMAIL", "")
        if _op and _op not in to_list and _op not in _bcc_list:
            _bcc_list.append(_op)
    msg = MIMEMultipart("mixed")
    msg["Subject"] = _Header(subject, "utf-8")
    msg["From"] = f"{from_name} <{smtp_user}>"
    msg["To"] = ", ".join(to_list)
    # Anti-spam: add Message-ID and Date headers
    import email.utils as _email_utils
    msg["Message-ID"] = _email_utils.make_msgid(domain=smtp_user.split("@")[-1] if "@" in smtp_user else "tpsh.ro")
    msg["Date"] = _email_utils.formatdate(localtime=True)
    msg["MIME-Version"] = "1.0"
    if _bcc_list:
        msg["Bcc"] = ", ".join(_bcc_list)
    # HTML body inside an alternative sub-part (include plain text to avoid MIME_HTML_ONLY spam flag)
    import re as _re_strip
    _plain_text = _re_strip.sub(r'<[^>]+>', '', html).strip()
    _plain_text = _re_strip.sub(r'\n{3,}', '\n\n', _plain_text)
    alt_part = MIMEMultipart("alternative")
    alt_part.attach(MIMEText(_plain_text[:5000], "plain", "utf-8"))
    alt_part.attach(MIMEText(html, "html", "utf-8"))
    msg.attach(alt_part)
    # Attachments (skip S/MIME signatures and HTML body duplicates)
    if attachments:
        for att in attachments:
            _att_fname = att.get("filename", "")
            _att_mime = att.get("mime", "")
            # Skip S/MIME signature files
            if _att_fname == "smime.p7s" or _att_mime in ("application/pkcs7-signature", "application/x-pkcs7-signature"):
                continue
            # Skip "Untitled" attachments (likely HTML body duplicates)
            if _att_fname.lower().startswith("untitled") and _att_mime in ("text/html", "text/plain", ""):
                continue
            part = MIMEBase("application", "octet-stream")
            part.set_payload(att["content"])
            encoders.encode_base64(part)
            part.add_header("Content-Disposition", f'attachment; filename="{_att_fname}"')
            if _att_mime:
                part.set_type(_att_mime)
            msg.attach(part)
    # All recipients (to + bcc) for sendmail envelope
    _all_recipients = list(to_list) + _bcc_list
    try:
        with smtplib.SMTP(smtp_host, smtp_port) as s:
            s.ehlo(); s.starttls(); s.login(smtp_user, smtp_pass)
            s.sendmail(smtp_user, _all_recipients, msg.as_string())
        _bcc_info = f", bcc: {', '.join(_bcc_list)}" if _bcc_list else ""
        _log.info("Email sent to %s%s (attachments: %d)", ", ".join(to_list), _bcc_info, len(attachments or []))
        _audit("email.sent", actor="system", entity_type="email",
               details=f"To: {', '.join(to_list)}, Subject: {subject[:100]}")
        return True
    except Exception as e:
        _log.error("Email error: %s", e)
        _audit("email.failed", actor="system", entity_type="email",
               details=f"To: {', '.join(to_list)}, Error: {str(e)[:200]}")
        return False


def _generate_form_pdf(ticket_code: str, ref: str, client_name: str, client_email: str,
                       template_name: str, completeness: int, ai_score, form_data: dict,
                       ai_validation: dict | None = None,
                       sections: list | None = None,
                       attachments: list | None = None,
                       photo_quality: int = 70,
                       template_id: str = "") -> bytes:
    """Generate a professional PDF of the completed form questionnaire.
    Returns PDF as bytes, ready to attach to email.
    Uses fpdf2 (pure Python, no system deps).
    sections: list of template sections with fields (from sections_json).
    """
    from datetime import datetime as _pdf_dt

    def _safe(text: str) -> str:
        """Replace smart-punct Unicode with ASCII; preserve German umlauts (latin-1 supports them)."""
        return (str(text)
                .replace("\u2014", "-")   # em-dash
                .replace("\u2013", "-")   # en-dash
                .replace("\u2018", "'")   # left single quote
                .replace("\u2019", "'")   # right single quote
                .replace("\u201c", '"')   # left double quote
                .replace("\u201d", '"')   # right double quote
                .replace("\u2022", "*")   # bullet
                .replace("\u2026", "...")  # ellipsis
                # NOTE: umlauts ü/ö/ä/ß are preserved — latin-1 encoding supports them natively
                .encode("latin-1", errors="replace").decode("latin-1")
               )

    # Ensure form_data is a dict
    if form_data is None:
        form_data = {}
    if isinstance(form_data, str):
        try:
            import json as _pdf_json
            form_data = _pdf_json.loads(form_data)
        except Exception:
            form_data = {}

    # Build sections with proper labels from template
    body_html = ""
    if sections and form_data:
        for sec in sections:
            sec_title = sec.get("title", "")
            sec_num = sec.get("number", "")
            fields_in_section = []
            for f in sec.get("fields", []):
                fname = f.get("name", "")
                flabel = f.get("label", fname.replace("_", " ").title())
                fval = form_data.get(fname, "")
                freq = f.get("required", False)
                fields_in_section.append((flabel, fval, freq))
            # Show ALL sections — empty ones show what's missing
            if fields_in_section:
                body_html += f'<h3 class="section-title">{sec_num}. {sec_title}</h3>'
                body_html += '<table>'
                for idx, (label, val, req) in enumerate(fields_in_section):
                    bg = "#f9fafb" if idx % 2 == 0 else "#ffffff"
                    display_val = val if val else '<span style="color:#9ca3af;font-style:italic">—</span>'
                    req_mark = ' <span style="color:#ef4444">*</span>' if req else ''
                    body_html += (
                        f'<tr style="background:{bg}">'
                        f'<td style="padding:8px 12px;border:1px solid #d1d5db;font-weight:600;width:38%;'
                        f'color:#374151;font-size:11px">{label}{req_mark}</td>'
                        f'<td style="padding:8px 12px;border:1px solid #d1d5db;color:#1f2937;font-size:11px">{display_val}</td>'
                        f'</tr>'
                    )
                body_html += '</table>'
    elif form_data:
        # Fallback: flat list if no sections available
        body_html += '<h3 class="section-title">Formulardaten</h3><table>'
        for idx, (k, v) in enumerate(form_data.items()):
            if k.startswith("_") or not v:
                continue
            label = k.replace("_", " ").title()
            bg = "#f9fafb" if idx % 2 == 0 else "#ffffff"
            body_html += (
                f'<tr style="background:{bg}">'
                f'<td style="padding:8px 12px;border:1px solid #d1d5db;font-weight:600;width:38%;'
                f'color:#374151;font-size:11px">{label}</td>'
                f'<td style="padding:8px 12px;border:1px solid #d1d5db;color:#1f2937;font-size:11px">{v}</td>'
                f'</tr>'
            )
        body_html += '</table>'

    # Fallback: if no form_data at all, generate minimal content
    if not body_html.strip():
        body_html = f"""<h3 class="section-title">Formularübersicht</h3>
        <table>
          <tr style="background:#f9fafb">
            <td style="padding:8px 12px;border:1px solid #d1d5db;font-weight:600;width:38%;color:#374151;font-size:11px">Kunde</td>
            <td style="padding:8px 12px;border:1px solid #d1d5db;color:#1f2937;font-size:11px">{client_name or 'N/A'}</td>
          </tr>
          <tr style="background:#ffffff">
            <td style="padding:8px 12px;border:1px solid #d1d5db;font-weight:600;width:38%;color:#374151;font-size:11px">Aktenzeichen</td>
            <td style="padding:8px 12px;border:1px solid #d1d5db;color:#1f2937;font-size:11px">{ticket_code or 'N/A'}</td>
          </tr>
          <tr style="background:#f9fafb">
            <td style="padding:8px 12px;border:1px solid #d1d5db;font-weight:600;width:38%;color:#374151;font-size:11px">Hinweis</td>
            <td style="padding:8px 12px;border:1px solid #d1d5db;color:#1f2937;font-size:11px">Keine Formulardaten vorhanden</td>
          </tr>
        </table>"""

    # AI issues
    issues_html = ""
    if ai_validation and ai_validation.get("issues"):
        issues_items = "".join(f"<li>{i}</li>" for i in ai_validation["issues"][:8])
        issues_html = f"""
        <div style="margin-top:16px;padding:12px;background:#fffbeb;border:1px solid #fbbf24;border-radius:6px">
            <strong style="color:#92400e;font-size:11px">KI-Hinweise:</strong>
            <ul style="margin:4px 0 0;padding-left:20px;font-size:10px;color:#92400e">{issues_items}</ul>
        </div>"""

    pdf_html = f"""<!DOCTYPE html>
<html><head><meta charset="utf-8">
<style>
  @page {{ size: A4; margin: 18mm 14mm 18mm 14mm; }}
  body {{ font-family: 'Segoe UI', Arial, Helvetica, sans-serif; color: #1f2937; font-size: 11px; line-height: 1.5; }}
  .header {{ background: linear-gradient(135deg, #1e40af, #3b82f6); color: white; padding: 24px 28px; border-radius: 8px; margin-bottom: 20px; }}
  .header h1 {{ margin: 0; font-size: 20px; }}
  .header p {{ margin: 4px 0 0; opacity: 0.85; font-size: 12px; }}
  .meta-grid {{ display: flex; gap: 12px; margin-bottom: 20px; flex-wrap: wrap; }}
  .meta-card {{ flex: 1; min-width: 140px; background: #f8fafc; padding: 12px 16px; border-radius: 6px; border-left: 3px solid #3b82f6; }}
  .meta-card .label {{ font-size: 9px; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px; }}
  .meta-card .value {{ font-size: 13px; font-weight: 700; color: #1e293b; margin-top: 2px; }}
  .meta-card .sub {{ font-size: 10px; color: #64748b; }}
  table {{ border-collapse: collapse; width: 100%; margin-top: 6px; margin-bottom: 12px; }}
  .section-title {{ color: #1e40af; font-size: 13px; font-weight: 700; border-bottom: 2px solid #3b82f6; padding-bottom: 5px; margin-top: 18px; margin-bottom: 4px; }}
  .footer {{ margin-top: 24px; padding-top: 12px; border-top: 1px solid #e5e7eb; font-size: 9px; color: #9ca3af; text-align: center; }}
  .badge {{ background: #1e40af; color: white; padding: 2px 8px; border-radius: 4px; font-weight: 700; font-size: 12px; }}
</style></head><body>

<div class="header">
  <h1>Schadenmeldung — {template_name}</h1>
  <p>{('Schadennummer: ' + _safe(form_data.get('schadensnummer') or form_data.get('schadennummer') or form_data.get('schadensnr') or '')) if (form_data.get('schadensnummer') or form_data.get('schadennummer') or form_data.get('schadensnr')) else ('Ref: ' + ref)} | Erstellt: {_pdf_dt.utcnow().strftime('%d.%m.%Y %H:%M')} UTC</p>
</div>

<div class="meta-grid">
  <div class="meta-card">
    <div class="label">Versicherungsnehmer</div>
    <div class="value">{client_name or 'N/A'}</div>
    <div class="sub">{client_email or ''}</div>
  </div>
  <div class="meta-card" style="border-left-color:#10b981">
    <div class="label">{'Schadennummer' if (form_data.get('schadensnummer') or form_data.get('schadennummer') or form_data.get('schadensnr')) else 'Referenz'}</div>
    <div class="value">{_safe(form_data.get('schadensnummer') or form_data.get('schadennummer') or form_data.get('schadensnr') or ref)}</div>
    <div class="sub" style="font-size:9px;color:#9ca3af">{ticket_code}</div>
  </div>
  <div class="meta-card" style="border-left-color:#f59e0b">
    <div class="label">Vollständigkeit / Readiness</div>
    <div class="value">{completeness}% / {_safe(str(form_data.get("_readiness_score","92")))}%</div>
    <div class="sub">SLA: {_safe(str(form_data.get("_sla_processing_sec","11")))}s  ·  {'Versicherer: ' + _safe(form_data.get('versicherer')) if form_data.get('versicherer') else 'AI: ' + str(ai_score) + '/100'}</div>
  </div>
</div>

{body_html}

{issues_html}

<div class="footer">
  TPSH Versicherungsmakler GmbH<br>
  {_safe(os.environ.get("TPSH_ADDRESS","Inselkammerstr. 1, 82008 Unterhaching"))}<br>
  Tel: {_safe(os.environ.get("TPSH_PHONE","+49 (89) 66550 100"))}  ·  Fax: {_safe(os.environ.get("TPSH_FAX","+49 (89) 66550 200"))}  ·  E-Mail: {_safe(os.environ.get("TPSH_EMAIL","info@tpsh.de"))}<br>
  Ansprechpartner: {_safe(os.environ.get("TPSH_ANSPRECHPARTNER","Valeria Teodoru — VTeodoru@tpsh.de"))}
</div>

</body></html>"""

    try:
        from fpdf import FPDF
        import io as _io

        class _ClaimPDF(FPDF):
            def header(self):
                self.set_fill_color(30, 64, 175)
                self.rect(0, 0, 210, 36, 'F')
                self.set_font('Helvetica', 'B', 16)
                self.set_text_color(255, 255, 255)
                self.set_xy(14, 8)
                self.cell(0, 8, f'Schadenmeldung - {self._tpl_name}', new_x="LMARGIN", new_y="NEXT")
                self.set_font('Helvetica', '', 9)
                self.set_xy(14, 18)
                _hdr_ref = f'Schadennummer: {self._schadennr}' if getattr(self, '_schadennr', '') else f'Ref: {self._ref_code}'
                self.cell(0, 5, _hdr_ref, new_x="LMARGIN", new_y="NEXT")
                self.set_xy(14, 24)
                self.cell(0, 5, f'Erstellt: {self._created}', new_x="LMARGIN", new_y="NEXT")
                self.set_text_color(0, 0, 0)
                self.ln(14)

            def footer(self):
                # Multi-line TPSH branded footer (matches HTML PDF footer)
                import os as _ftr_os
                self.set_y(-22)
                self.set_font('Helvetica', 'B', 7)
                self.set_text_color(100, 100, 100)
                self.cell(0, 3.5, 'TPSH Versicherungsmakler GmbH', align='C', new_x="LMARGIN", new_y="NEXT")
                self.set_font('Helvetica', '', 6)
                self.set_text_color(130, 130, 130)
                _addr = _ftr_os.environ.get('TPSH_ADDRESS', 'Musterstr. 1, 10115 Berlin, Deutschland')
                _phone = _ftr_os.environ.get('TPSH_PHONE', '+49 30 00000000')
                _eml = _ftr_os.environ.get('TPSH_EMAIL', 'info@tpsh.de')
                _web = _ftr_os.environ.get('TPSH_WEBSITE', 'www.tpsh.de')
                self.cell(0, 3.2, _addr, align='C', new_x="LMARGIN", new_y="NEXT")
                self.cell(0, 3.2, f'Tel: {_phone}  ·  E-Mail: {_eml}  ·  Web: {_web}', align='C', new_x="LMARGIN", new_y="NEXT")
                self.set_font('Helvetica', 'I', 6)
                self.set_text_color(170, 170, 170)
                _ftr_ref = self._schadennr if getattr(self, '_schadennr', '') else self._ticket
                self.cell(0, 3, f'Automatisch generiert von Alex  ·  {_ftr_ref}', align='C')

        pdf = _ClaimPDF(orientation='P', unit='mm', format='A4')
        pdf._tpl_name = _safe(template_name)
        pdf._ticket = _safe(ticket_code)
        pdf._ref_code = _safe(ref)
        pdf._schadennr = _safe(form_data.get("schadensnummer") or form_data.get("schadennummer") or form_data.get("schadensnr") or form_data.get("Schadensnummer") or form_data.get("schaden_nummer") or "")
        pdf._created = _pdf_dt.utcnow().strftime('%d.%m.%Y %H:%M') + ' UTC'
        pdf.set_auto_page_break(auto=True, margin=20)
        pdf.add_page()

        # Step 5: Extract external reference numbers from form_data
        _schadennr = _safe(form_data.get("schadensnummer") or form_data.get("schadennummer") or form_data.get("schadensnr") or form_data.get("Schadensnummer") or form_data.get("schaden_nummer") or "")
        _vs_nr = _safe(form_data.get("versicherungsschein_nr") or form_data.get("vs_nr") or form_data.get("versicherungsschein") or form_data.get("Versicherungsscheinnummer") or "")
        _polizei_az = _safe(form_data.get("polizei_aktenzeichen") or form_data.get("polizei_az") or form_data.get("Polizeiaktenzeichen") or "")

        # Row 1: Schadennummer + VS-Nr (prominent) or VN + Schadennummer
        pdf.set_y(42)
        _card_w = 58
        _row1_cards = [
            ("Versicherungsnehmer", _safe(client_name or 'N/A'), _safe(client_email or ''), (30, 64, 175)),
        ]
        _versicherer_val = _safe(form_data.get('versicherer','') or '')
        _readiness_val = _safe(str(form_data.get('_readiness_score','') or ''))
        _sla_val = _safe(str(form_data.get('_sla_processing_sec','11') or '11'))
        _rs_sub = f"Readiness {_readiness_val}%" if _readiness_val else ""
        _extras = " | ".join([x for x in (_rs_sub, f"SLA {_sla_val}s") if x])
        # Cover card: if versicherer known, highlight it; else show completeness
        if _versicherer_val:
            _card_lbl = "Versicherer"
            _card_val = _versicherer_val
            _card_sub = f'Vollst\u00e4ndigkeit: {completeness}% | {_extras}' if _extras else f'Vollst\u00e4ndigkeit: {completeness}%'
        else:
            _card_lbl = "Vollst\u00e4ndigkeit"
            _card_val = f'{completeness}%'
            _card_sub = _extras
        if _schadennr:
            _row1_cards.append(("Schadennummer", _schadennr, "", (220, 38, 38)))
        if _vs_nr:
            _row1_cards.append(("VS-Nr.", _vs_nr, "", (124, 58, 237)))
        if not _schadennr and not _vs_nr:
            _row1_cards.append(("Aktenzeichen", _safe(ticket_code), _safe(f'Ref: {ref}'), (16, 185, 129)))
            _row1_cards.append((_card_lbl, _card_val, _card_sub, (245, 158, 11)))

        for i, (lbl, val, sub_val, color) in enumerate(_row1_cards):
            x = 14 + i * (_card_w + 4)
            pdf.set_fill_color(248, 250, 252)
            pdf.rect(x, pdf.get_y(), _card_w, 20, 'F')
            pdf.set_draw_color(*color)
            pdf.line(x, pdf.get_y(), x, pdf.get_y() + 20)
            pdf.set_xy(x + 3, pdf.get_y() + 2)
            pdf.set_font('Helvetica', '', 7)
            pdf.set_text_color(107, 114, 128)
            pdf.cell(_card_w - 6, 3, lbl.upper())
            pdf.set_xy(x + 3, pdf.get_y() + 5)
            # Make Schadennummer and VS-Nr prominent (larger, bold)
            _is_prominent = lbl in ("Schadennummer", "VS-Nr.")
            pdf.set_font('Helvetica', 'B', 13 if _is_prominent else 11)
            pdf.set_text_color(30, 41, 59)
            pdf.cell(_card_w - 6, 5, val[:40])
            pdf.set_xy(x + 3, pdf.get_y() + 6)
            pdf.set_font('Helvetica', '', 7)
            pdf.set_text_color(100, 116, 139)
            pdf.cell(_card_w - 6, 3, sub_val[:55])

        # Row 2: secondary info (AKT, completeness, Polizei AZ) if we had Schadennummer/VS-Nr
        if _schadennr or _vs_nr:
            pdf.set_y(pdf.get_y() + 24)
            _row2_cards = [
                ("Aktenzeichen", _safe(ticket_code), _safe(f'Ref: {ref}'), (100, 116, 139)),
                (_card_lbl, _card_val, _card_sub, (245, 158, 11)),
            ]
            if _polizei_az:
                _row2_cards.append(("Polizei AZ", _polizei_az, "", (59, 130, 246)))
            _card_w2 = 58
            for i, (lbl, val, sub_val, color) in enumerate(_row2_cards):
                x = 14 + i * (_card_w2 + 4)
                pdf.set_fill_color(248, 250, 252)
                pdf.rect(x, pdf.get_y(), _card_w2, 16, 'F')
                pdf.set_draw_color(*color)
                pdf.line(x, pdf.get_y(), x, pdf.get_y() + 16)
                pdf.set_xy(x + 3, pdf.get_y() + 1)
                pdf.set_font('Helvetica', '', 6)
                pdf.set_text_color(107, 114, 128)
                pdf.cell(_card_w2 - 6, 3, lbl.upper())
                pdf.set_xy(x + 3, pdf.get_y() + 4)
                pdf.set_font('Helvetica', 'B', 9)
                pdf.set_text_color(30, 41, 59)
                pdf.cell(_card_w2 - 6, 4, val[:25])
                pdf.set_xy(x + 3, pdf.get_y() + 5)
                pdf.set_font('Helvetica', '', 6)
                pdf.set_text_color(100, 116, 139)
                pdf.cell(_card_w2 - 6, 3, sub_val[:55])

        pdf.set_y(pdf.get_y() + 24)

        # Sections with fields
        if sections and form_data:
            for sec in sections:
                sec_title = sec.get("title", "")
                sec_num = sec.get("number", "")
                fields_in_sec = []
                for f in sec.get("fields", []):
                    fname = f.get("name", "")
                    flabel = _safe(f.get("label", fname.replace("_", " ").title()))
                    fval = _safe(str(form_data.get(fname, "") or ""))
                    freq = f.get("required", False)
                    fields_in_sec.append((flabel, fval, freq))

                if not fields_in_sec:
                    continue

                # Section header
                if pdf.get_y() > 260:
                    pdf.add_page()
                pdf.set_font('Helvetica', 'B', 10)
                pdf.set_text_color(30, 64, 175)
                pdf.cell(0, 7, _safe(f'{sec_num}. {sec_title}'), new_x="LMARGIN", new_y="NEXT")
                pdf.set_draw_color(59, 130, 246)
                pdf.line(14, pdf.get_y(), 196, pdf.get_y())
                pdf.ln(2)

                # Fields table — fixed 2-column layout (label 68mm, value 110mm)
                # Label truncated at 48 chars + req_mark; value wraps via multi_cell
                for idx, (label, val, req) in enumerate(fields_in_sec):
                    if pdf.get_y() > 270:
                        pdf.add_page()
                    bg = (249, 250, 251) if idx % 2 == 0 else (255, 255, 255)
                    pdf.set_fill_color(*bg)
                    y_before = pdf.get_y()
                    # Truncate label only (not req_mark) to avoid asterisk glued to value bug.
                    # Max label = 48 - req_mark_len - 3 (ellipsis)
                    req_mark = ' *' if req else ''
                    _max_label = 48 - len(req_mark) - 3
                    if len(label) + len(req_mark) > 48:
                        _label_text = label[:_max_label] + '...' + req_mark
                    else:
                        _label_text = label + req_mark
                    display = _safe(val) if val else "-"
                    # Use multi_cell for value to get wrap; measure label height similarly
                    pdf.set_font('Helvetica', 'B', 8)
                    pdf.set_text_color(55, 65, 81)
                    pdf.set_x(14)
                    pdf.cell(68, 6, _label_text, fill=True)
                    # Value cell — draw at x=82 with multi_cell if long, else single cell
                    pdf.set_font('Helvetica', '', 8)
                    pdf.set_text_color(31, 41, 55)
                    pdf.set_xy(82, y_before)
                    if len(display) > 70:
                        pdf.multi_cell(110, 6, display, fill=True, new_x="LMARGIN", new_y="NEXT")
                    else:
                        pdf.cell(110, 6, display, fill=True, new_x="LMARGIN", new_y="NEXT")
                    # Fix 4: Guarantee the next field starts on a fresh line at the left
                    # margin. Short labels (e.g. "3.7 Zeuge *" + "3.8 Polizei *") were
                    # colliding because no explicit line advance happened between rows.
                    pdf.set_xy(14, pdf.get_y())

        elif form_data:
            pdf.set_font('Helvetica', 'B', 10)
            pdf.set_text_color(30, 64, 175)
            pdf.cell(0, 7, 'Formulardaten', new_x="LMARGIN", new_y="NEXT")
            pdf.ln(2)
            for idx, (k, v) in enumerate(form_data.items()):
                if k.startswith("_") or not v:
                    continue
                if pdf.get_y() > 270:
                    pdf.add_page()
                bg = (249, 250, 251) if idx % 2 == 0 else (255, 255, 255)
                pdf.set_fill_color(*bg)
                label = _safe(k.replace("_", " ").title())
                pdf.set_font('Helvetica', 'B', 8)
                pdf.set_text_color(55, 65, 81)
                pdf.set_x(14)
                pdf.cell(68, 6, label, fill=True)
                pdf.set_font('Helvetica', '', 8)
                pdf.set_text_color(31, 41, 55)
                pdf.cell(110, 6, _safe(str(v))[:80], fill=True, new_x="LMARGIN", new_y="NEXT")

        # Step 3: Embed photos in PDF (Bildanhaenge section)
        _image_attachments = [a for a in (attachments or []) if (a.get("content_type") or "").startswith("image/")]
        if _image_attachments:
            _upload_dir = Path(__file__).parent / "output" / "form-attachments"
            # B5v3: always new page so title + first image land together
            pdf.add_page()
            pdf.set_font('Helvetica', 'B', 10)
            pdf.set_text_color(30, 64, 175)
            pdf.cell(0, 7, 'Bildanh\u00e4nge', new_x="LMARGIN", new_y="NEXT")
            pdf.set_draw_color(59, 130, 246)
            pdf.line(14, pdf.get_y(), 196, pdf.get_y())
            pdf.ln(4)
            _imgs_on_page = 0
            for _att in _image_attachments:
                # Prefer compressed thumbnail, fall back to original
                _img_file = _att.get("compressed_path") or _att.get("saved_as", "")
                _img_path = _upload_dir / _img_file
                if not _img_path.exists():
                    _img_path = _upload_dir / _att.get("saved_as", "")
                # FAZA 2: If still missing, fetch from GCS and save to /tmp
                if not _img_path.exists():
                    _gcs_uri_img = _att.get("gcs_uri","")
                    if _gcs_uri_img and _gcs_uri_img.startswith("gs://"):
                        try:
                            from google.cloud import storage as _gcs_img_mod
                            _parts_img = _gcs_uri_img.replace("gs://","").split("/",1)
                            _tmp_img = Path(f"/tmp/gcs_img_{_att.get('saved_as','img')}")
                            _img_bytes_gcs = _gcs_img_mod.Client().bucket(_parts_img[0]).blob(_parts_img[1]).download_as_bytes()
                            _tmp_img.write_bytes(_img_bytes_gcs)
                            _img_path = _tmp_img
                            _log.info(f"📥 GCS fetched image {_img_file} ({len(_img_bytes_gcs)} bytes)")
                        except Exception as _gimg_err:
                            _log.warning(f"GCS image fetch failed: {_gimg_err}")
                if not _img_path.exists():
                    continue
                if _imgs_on_page >= 2:
                    pdf.add_page()
                    _imgs_on_page = 0
                try:
                    # B5v4: Use smaller images (80mm h) so title+2 images fit on same page
                    _max_img_w = 170
                    _max_img_h = 80
                    if pdf.get_y() + _max_img_h + 15 > 270:
                        pdf.add_page()
                        _imgs_on_page = 0
                    pdf.image(str(_img_path), x=20, w=_max_img_w, h=_max_img_h, keep_aspect_ratio=True)
                    pdf.ln(2)
                    # Caption with filename
                    pdf.set_font('Helvetica', 'I', 7)
                    pdf.set_text_color(100, 116, 139)
                    _caption = _safe(_att.get("filename", _img_file))
                    _ai_info = _att.get("ai_analysis")
                    # Fix 4: Vehicle-damage captions (Kratzer/Delle/KZ) only make sense
                    # for KFZ context. Suppress them ONLY for tpl-haftpflicht and
                    # tpl-maschinenbruch (exact template_id match) to avoid misleading
                    # labels. KFZ (tpl-kfz-schaden) MUST keep captions.
                    _is_non_kfz = template_id in ('tpl-haftpflicht', 'tpl-maschinenbruch')
                    if _ai_info and isinstance(_ai_info, dict) and not _is_non_kfz:
                        _dmg = _ai_info.get("damage_type", "")
                        _sev = _ai_info.get("severity", "")
                        _kz = _ai_info.get("kennzeichen", "")
                        if _dmg:
                            _caption += f' | Schaden: {_dmg}'
                        if _sev:
                            _caption += f' ({_sev})'
                        if _kz:
                            _caption += f' | KZ: {_kz}'
                    # For non-KFZ templates, also append size info in place of AI details
                    if _is_non_kfz:
                        _size_kb = round((_att.get("size") or 0) / 1024, 1)
                        if _size_kb:
                            _caption += f' ({_size_kb} KB)'
                    pdf.cell(0, 4, _caption[:120], new_x="LMARGIN", new_y="NEXT")
                    pdf.ln(6)
                    _imgs_on_page += 1
                except Exception as _img_err:
                    _log.warning(f"Failed to embed image {_img_file} in PDF: {_img_err}")

        # Step 3b: List non-image attachments (PDFs, docs, etc.)
        _non_image_attachments = [a for a in (attachments or []) if not (a.get("content_type") or "").startswith("image/")]
        if _non_image_attachments:
            if not _image_attachments:
                # No images were added, so we need the Bildanhaenge header
                pdf.add_page()
            pdf.ln(4)
            pdf.set_font('Helvetica', 'B', 9)
            pdf.set_text_color(30, 64, 175)
            pdf.cell(0, 7, _safe('Anlagen (Dokumente)'), new_x="LMARGIN", new_y="NEXT")
            pdf.set_draw_color(59, 130, 246)
            pdf.line(14, pdf.get_y(), 196, pdf.get_y())
            pdf.ln(3)
            for _nimg_att in _non_image_attachments:
                _nimg_fname = _safe(_nimg_att.get("filename", "Dokument"))
                _nimg_size_kb = round((_nimg_att.get("size") or 0) / 1024, 1)
                _nimg_cat = _nimg_att.get("category", "")
                _nimg_summary = _nimg_att.get("summary", "")
                # Draw a bordered reference box
                _box_y = pdf.get_y()
                if _box_y + 14 > 270:
                    pdf.add_page()
                    _box_y = pdf.get_y()
                pdf.set_fill_color(248, 250, 252)
                pdf.set_draw_color(203, 213, 225)
                pdf.rect(14, _box_y, 182, 12, style='DF')
                pdf.set_xy(16, _box_y + 1)
                pdf.set_font('Helvetica', 'B', 8)
                pdf.set_text_color(31, 41, 55)
                _label_text = f'Anlage: {_nimg_fname} ({_nimg_size_kb} KB)'
                pdf.cell(0, 5, _label_text[:90], new_x="LMARGIN", new_y="NEXT")
                pdf.set_x(16)
                pdf.set_font('Helvetica', 'I', 7)
                pdf.set_text_color(100, 116, 139)
                _detail_parts = []
                if _nimg_cat and _nimg_cat != "OTHER":
                    _detail_parts.append(f'Typ: {_nimg_cat}')
                if _nimg_summary:
                    _detail_parts.append(_nimg_summary[:80])
                if _detail_parts:
                    pdf.cell(0, 4, _safe(' | '.join(_detail_parts)), new_x="LMARGIN", new_y="NEXT")
                else:
                    pdf.ln(4)
                pdf.ln(3)

        # AI issues
        if ai_validation and ai_validation.get("issues"):
            pdf.ln(6)
            pdf.set_fill_color(255, 251, 235)
            pdf.set_draw_color(251, 191, 36)
            y0 = pdf.get_y()
            pdf.set_font('Helvetica', 'B', 8)
            pdf.set_text_color(146, 64, 14)
            pdf.cell(0, 6, 'KI-Hinweise:', new_x="LMARGIN", new_y="NEXT")
            pdf.set_font('Helvetica', '', 7)
            for issue in ai_validation["issues"][:8]:
                pdf.cell(6, 4, "*")
                pdf.cell(0, 4, _safe(issue)[:100], new_x="LMARGIN", new_y="NEXT")

        buf = _io.BytesIO()
        pdf.output(buf)
        pdf_bytes = buf.getvalue()
        # Never return a <100 byte PDF — always generate at least a header page
        if len(pdf_bytes) < 100:
            _log.warning(f"PDF too small ({len(pdf_bytes)} bytes) for {ticket_code} — regenerating minimal")
            from fpdf import FPDF as _FPDF_min
            _min_pdf = _FPDF_min()
            _min_pdf.add_page()
            _min_pdf.set_font("Helvetica", "B", 16)
            _min_pdf.cell(0, 12, _safe(f"Schadenmeldung — {ticket_code}"), ln=True)
            _min_pdf.set_font("Helvetica", "", 11)
            _min_pdf.cell(0, 8, _safe(f"Kunde: {client_name or 'N/A'}"), ln=True)
            _min_pdf.cell(0, 8, _safe(f"Aktenzeichen: {ticket_code}"), ln=True)
            _min_pdf.cell(0, 8, "Keine Formulardaten vorhanden", ln=True)
            _min_buf = _io.BytesIO()
            _min_pdf.output(_min_buf)
            pdf_bytes = _min_buf.getvalue()
        _log.info(f"PDF generated for {ticket_code}: {len(pdf_bytes)} bytes (fpdf2)")
        # Merge attached PDFs into the main PDF (append pages)
        try:
            _pdf_attachments = [a for a in (attachments or []) if (a.get("content_type") or a.get("mime","") or "").lower() == "application/pdf" or (a.get("filename","") or "").lower().endswith(".pdf")]
            if _pdf_attachments:
                from pypdf import PdfWriter, PdfReader
                _io_m = __import__("io")
                _writer = PdfWriter()
                # Add main PDF
                _writer.append(PdfReader(_io_m.BytesIO(pdf_bytes)))
                # Append each PDF attachment (pages only, no annotations)
                _upload_dir_m = Path(__file__).parent / "output" / "form-attachments"
                for _pa in _pdf_attachments:
                    _pa_file = _pa.get("saved_as") or ""
                    _pa_path = _upload_dir_m / _pa_file
                    _pa_bytes = None
                    if _pa_path.exists():
                        _pa_bytes = _pa_path.read_bytes()
                    else:
                        # Fallback: fetch from GCS
                        _pa_gcs = _pa.get("gcs_uri","")
                        if _pa_gcs and _pa_gcs.startswith("gs://"):
                            try:
                                from google.cloud import storage as _gcs_dl
                                _gcs_dl_client = _gcs_dl.Client()
                                _parts = _pa_gcs.replace("gs://","").split("/",1)
                                _pa_bytes = _gcs_dl_client.bucket(_parts[0]).blob(_parts[1]).download_as_bytes()
                                _log.info(f"📥 Fetched {_pa_file} from GCS ({len(_pa_bytes)} bytes)")
                            except Exception as _gcs_dl_err:
                                _log.warning(f"GCS download failed for {_pa_file}: {_gcs_dl_err}")
                    if not _pa_bytes:
                        continue
                    try:
                        _pa_reader = PdfReader(_io_m.BytesIO(_pa_bytes))
                        for _p in _pa_reader.pages:
                            _writer.add_page(_p)
                        _log.info(f"📎 Merged {len(_pa_reader.pages)} pages from {_pa_file} into main PDF")
                    except Exception as _pa_err:
                        _log.warning(f"PDF merge failed for {_pa_file}: {_pa_err}")
                _merged_buf = _io_m.BytesIO()
                _writer.write(_merged_buf)
                pdf_bytes = _merged_buf.getvalue()
                _log.info(f"PDF after merge: {len(pdf_bytes)} bytes (+{len(_pdf_attachments)} attachments embedded)")
        except Exception as _mrg_err:
            _log.warning(f"PDF merge skipped (pypdf error): {_mrg_err}")
        return pdf_bytes
    except ImportError:
        _log.warning("fpdf2 not available — PDF generation disabled")
        return b""
    except Exception as e:
        _log.error(f"PDF generation failed for {ticket_code}: {e}")
        return b""

def _get_setting(key: str, default: str = "") -> str:
    """Read a setting from Firestore app_settings collection."""
    try:
        doc = _fs_get("app_settings", key)
        return doc["value"] if doc else default
    except Exception:
        return default

def _set_setting(key: str, value: str):
    """Write a setting to Firestore app_settings collection."""
    _fs_set("app_settings", key, {"value": value, "updated_at": __import__("datetime").datetime.utcnow().isoformat()})

def _oracle_auto_sync_enabled() -> bool:
    """Check if Oracle auto-sync is enabled (user controls via Interconectare dashboard)."""
    return _get_setting("oracle_auto_sync", "off").lower() == "on"

