# ── RAG Hook Engine — self-learning knowledge system ────────────────────────

def emit_hook(hook: str, content: str, actor: str = "system",
              entity_type: str = None, entity_id: str = None,
              tags: list = None, relevance_score: int = 5):
    """Fire a learning hook — stores knowledge for RAG retrieval.
    Non-blocking: failures are silently logged, never break main flow."""
    try:
        import uuid as _uu
        _fs_set("alex_knowledge", f"kn-{_uu.uuid4().hex[:12]}", {
            "hook": hook, "actor": actor, "entity_type": entity_type, "entity_id": entity_id,
            "content": content, "tags": tags or [], "relevance_score": relevance_score,
            "times_used": 0, "created_at": __import__("datetime").datetime.utcnow().isoformat()
        })
        _log.info(f"🧠 Hook [{hook}]: {content[:80]}...")
    except Exception as e:
        _log.warning(f"Hook emit failed: {e}")


def _audit(action: str, actor: str = "system", entity_type: str = None,
           entity_id: str = None, details: str = None):
    """Write to audit_trail table. Non-blocking: failures silently logged."""
    try:
        import uuid as _uu_audit
        _fs_set("audit_trail", f"aud-{_uu_audit.uuid4().hex[:10]}", {
            "action": action, "actor": actor, "entity_type": entity_type,
            "entity_id": entity_id, "details": details,
            "created_at": __import__("datetime").datetime.utcnow().isoformat()
        })
    except Exception as e:
        _log.warning(f"Audit write failed: {e}")


# ── Legacy _firestore_sync — now a no-op since Firestore is PRIMARY ──────
def _firestore_sync(collection: str, doc_id: str | None, data: dict):
    """Legacy sync shim — Firestore is now primary, so this is a no-op.
    Kept for backward compat with any callers we haven't migrated yet."""
    pass


def get_relevant_knowledge(query: str, limit: int = 5) -> list[dict]:
    """Retrieve top-N most relevant knowledge entries for a query.
    Uses keyword matching now; semantic search in phase 2."""
    try:
        words = [w.strip() for w in query.lower().split() if len(w.strip()) > 2]
        if not words:
            return []
        all_entries = _fs_all("alex_knowledge", limit=500)
        results = []
        for entry in all_entries:
            content_lower = (entry.get("content") or "").lower()
            if any(w in content_lower for w in words):
                results.append(entry)
        results.sort(key=lambda x: (-(x.get("relevance_score") or 0), x.get("created_at", "")))
        results = results[:limit]
        # Bump times_used for retrieved entries
        for r in results:
            doc_id = r.get("_id") or r.get("id")
            if doc_id:
                try:
                    _fs_update("alex_knowledge", doc_id, {
                        "times_used": (r.get("times_used") or 0) + 1,
                        "last_used_at": __import__("datetime").datetime.utcnow().isoformat()
                    })
                except Exception:
                    pass
        return results
    except Exception as e:
        _log.warning(f"Knowledge retrieval failed: {e}")
        return []


def get_knowledge_stats() -> dict:
    """Get knowledge base statistics for dashboard."""
    try:
        all_entries = _fs_all("alex_knowledge", limit=1000)
        total = len(all_entries)
        hook_counts = {}
        actor_counts = {}
        for e in all_entries:
            h = e.get("hook", "unknown")
            hook_counts[h] = hook_counts.get(h, 0) + 1
            a = e.get("actor", "unknown")
            actor_counts[a] = actor_counts.get(a, 0) + 1
        by_hook = sorted([{"hook": k, "cnt": v} for k, v in hook_counts.items()], key=lambda x: -x["cnt"])[:10]
        by_actor = sorted([{"actor": k, "cnt": v} for k, v in actor_counts.items()], key=lambda x: -x["cnt"])
        recent = sorted(all_entries, key=lambda x: x.get("created_at", ""), reverse=True)[:20]
        most_used = sorted([e for e in all_entries if (e.get("times_used") or 0) > 0],
                           key=lambda x: -(x.get("times_used") or 0))[:10]
        patterns = _fs_query("alex_patterns", filters=[("is_active", "==", True)], limit=10)
        return {
            "total_entries": total,
            "by_hook": by_hook,
            "by_actor": by_actor,
            "recent": recent,
            "patterns": patterns,
            "most_used": most_used,
        }
    except Exception as e:
        _log.warning(f"Knowledge stats failed: {e}")
        return {"total_entries": 0, "by_hook": [], "by_actor": [], "recent": [], "patterns": [], "most_used": []}


# ── Convenience aliases (avoid Chainlit catch-all) ──────────────────────────

@app.get("/api/clients")
async def api_clients_alias(q: str = Query(default=""), limit: int = Query(default=100, ge=1, le=500)):
    """List all clients — alias for /api/db/clients."""
    all_clients = _fs_all("clients", limit=limit)
    if q:
        q_low = q.lower()
        all_clients = [c for c in all_clients if q_low in (c.get("name") or "").lower()
                       or q_low in (c.get("email") or "").lower()
                       or q_low in (c.get("phone") or "").lower()]
    all_clients.sort(key=lambda x: x.get("name", ""))
    return JSONResponse({"items": all_clients[:limit], "total": len(all_clients)})

@app.get("/api/claims")
async def api_claims_alias(status: str = Query(default=""), limit: int = Query(default=100, ge=1, le=500)):
    """List all claims — alias for /api/db/claims."""
    filters = []
    if status:
        filters.append(("status", "==", status))
    claims = _fs_query("claims", filters=filters if filters else None, limit=limit)
    # Enrich with client name and policy info
    for cl in claims:
        if cl.get("client_id"):
            c = _fs_get("clients", cl["client_id"])
            cl["client_name"] = c.get("name") if c else None
        if cl.get("policy_id"):
            p = _fs_get("policies", cl["policy_id"])
            if p:
                cl["policy_type"] = p.get("policy_type")
                cl["insurer"] = p.get("insurer")
    claims.sort(key=lambda x: x.get("reported_date", ""), reverse=True)
    return JSONResponse({"items": claims[:limit], "total": len(claims)})

@app.get("/api/cross-sell")
async def api_cross_sell():
    """Identify cross-sell opportunities — clients with few policies."""
    all_clients = _fs_all("clients", limit=500)
    all_policies = _fs_query("policies", filters=[("status", "==", "active")], limit=2000)
    # Group policies by client
    client_policies = {}
    for p in all_policies:
        cid = p.get("client_id")
        if cid:
            client_policies.setdefault(cid, []).append(p)
    all_types = {'KFZ', 'Haftpflicht', 'Hausrat', 'Rechtsschutz', 'BU', 'Leben', 'Kranken'}
    items = []
    for c in all_clients:
        cid = c.get("_id") or c.get("id")
        pols = client_policies.get(cid, [])
        if len(pols) <= 2:
            existing = set(p.get("policy_type", "") for p in pols)
            total_premium = sum(p.get("annual_premium", 0) or 0 for p in pols)
            d = {"id": cid, "name": c.get("name"), "email": c.get("email"), "phone": c.get("phone"),
                 "policy_count": len(pols), "existing_types": ",".join(existing), "total_premium": total_premium,
                 "missing_types": sorted(all_types - existing), "opportunity_score": len(all_types - existing)}
            items.append(d)
    items.sort(key=lambda x: (x["policy_count"], x.get("name", "")))
    return JSONResponse({"items": items[:50], "total": len(items)})

@app.get("/api/renewals")
async def api_renewals(days: int = Query(default=45, ge=1, le=365)):
    """Get policies expiring within N days — structured JSON for n8n automation."""
    from datetime import date as _date, timedelta as _td
    try:
        _today = _date.today().isoformat()
        _cutoff = (_date.today() + _td(days=days)).isoformat()
        active_policies = _fs_query("policies", filters=[("status", "==", "active")], limit=2000)
        _items = []
        for p in active_policies:
            end = p.get("end_date", "")
            if end and _today <= end <= _cutoff:
                cid = p.get("client_id")
                c = _fs_get("clients", cid) if cid else {}
                try:
                    days_left = (_date.fromisoformat(end) - _date.today()).days
                except Exception:
                    days_left = 0
                _items.append({
                    "id": p.get("_id") or p.get("id"), "client_id": cid,
                    "client_name": (c or {}).get("name"), "client_email": (c or {}).get("email"),
                    "client_phone": (c or {}).get("phone"),
                    "policy_type": p.get("policy_type"), "insurer": p.get("insurer"),
                    "policy_number": p.get("policy_number"), "end_date": end,
                    "annual_premium": p.get("annual_premium"), "currency": p.get("currency"),
                    "days_left": days_left
                })
        _items.sort(key=lambda x: x.get("end_date", ""))
        return JSONResponse({
            "as_of": _today, "days_ahead": days, "total": len(_items),
            "urgent": [i for i in _items if i["days_left"] <= 7],
            "upcoming": [i for i in _items if i["days_left"] > 7],
            "all": _items,
        })
    except Exception as _ex:
        return JSONResponse({"error": str(_ex)}, status_code=500)

