@app.get("/api/claims/open")
async def api_open_claims(max_age_days: int = Query(default=90, ge=1, le=365)):
    """Return open/investigating claims — useful for n8n follow-up automation."""
    from datetime import date as _date, timedelta as _td
    try:
        _cutoff = (_date.today() - _td(days=max_age_days)).isoformat()
        open_claims = _fs_all("claims", limit=1000)
        _items = []
        for cl in open_claims:
            if cl.get("status") in ("open", "investigating") and (cl.get("reported_date", "") >= _cutoff):
                cid = cl.get("client_id")
                c = _fs_get("clients", cid) if cid else {}
                days_open = 0
                try:
                    days_open = (_date.today() - _date.fromisoformat(cl.get("reported_date", _date.today().isoformat()))).days
                except Exception:
                    pass
                item = {**cl, "client_name": (c or {}).get("name"), "client_email": (c or {}).get("email"),
                        "client_phone": (c or {}).get("phone"), "days_open": days_open}
                item.pop("_id", None)
                _items.append(item)
        _items.sort(key=lambda x: x.get("reported_date", ""))
        return JSONResponse({"total": len(_items), "claims": _items})
    except Exception as _ex:
        return JSONResponse({"error": str(_ex)}, status_code=500)

@app.get("/api/dashboard")
async def api_dashboard():
    """Dashboard summary stats — real Firestore submission counts + policies."""
    from datetime import date as _date, datetime as _dt_dash, timedelta as _td
    try:
        _today_str = _date.today().isoformat()
        _7d = (_date.today() + _td(days=7)).isoformat()
        _30d = (_date.today() + _td(days=30)).isoformat()
        # Real submission data from Firestore
        all_subs = _cached_fs_all("form_submissions") or []
        total_submissions = len(all_subs)
        complete = len([s for s in all_subs if (s.get("completeness_pct") or s.get("completeness") or 0) >= 100 or s.get("status") == "forwarded"])
        incomplete = len([s for s in all_subs if (s.get("completeness_pct") or s.get("completeness") or 0) < 100 and s.get("status") not in ("forwarded", "closed", "validated")])
        avg_completeness = round(sum(s.get("completeness_pct") or s.get("completeness") or 0 for s in all_subs) / max(total_submissions, 1))
        # Today's new
        today_new = 0
        for s in all_subs:
            ca = s.get("created_at") or ""
            if ca and ca[:10] == _today_str:
                today_new += 1
        # Overdue (>4 days incomplete)
        overdue = 0
        _4days_ago = (_date.today() - _td(days=4)).isoformat()
        for s in all_subs:
            if s.get("status") in ("forwarded", "closed", "validated"):
                continue
            if (s.get("completeness_pct") or s.get("completeness") or 0) >= 100:
                continue
            ca = s.get("created_at") or ""
            if ca and ca[:10] <= _4days_ago:
                overdue += 1
        # Also keep policy/client data
        active_pols = _fs_query("policies", filters=[("status", "==", "active")], limit=2000)
        stats = {
            "total_submissions": total_submissions,
            "complete": complete,
            "incomplete": incomplete,
            "avg_completeness": avg_completeness,
            "today_new": today_new,
            "overdue": overdue,
            "active_policies": len(active_pols),
            "total_clients": _fs_count("clients"),
            "open_claims": _fs_count("claims", filters=[("status", "in", ["open", "investigating"])]),
            "expiring_7": len([p for p in active_pols if _today_str <= (p.get("end_date") or "") <= _7d]),
            "expiring_30": len([p for p in active_pols if _today_str <= (p.get("end_date") or "") <= _30d]),
            "offers_total": _fs_count("offers"),
        }
        return JSONResponse(stats)
    except Exception as _ex:
        return JSONResponse({"error": str(_ex)}, status_code=500)

