@app.get("/api/approvals/stats")
async def api_approval_stats():
    """Get approval queue statistics."""
    stats = {}
    for status in ["pending", "sent", "rejected", "expired"]:
        stats[status] = _fs_count("approval_queue", filters=[("status", "==", status)])
    return stats


@app.get("/api/approvals")
async def api_list_approvals(status: str = Query(default="pending"), limit: int = Query(default=50)):
    """List approval queue items. Filter by status. Use status='all' for everything."""
    filters = [] if status == "all" else [("status", "==", status)]
    rows = _fs_query("approval_queue", filters=filters if filters else None, limit=limit)
    priority_order = {"urgent": 1, "high": 2, "medium": 3}
    rows.sort(key=lambda x: (priority_order.get(x.get("priority", ""), 4), -(hash(x.get("created_at", "")))))
    for r in rows:
        r["id"] = r.pop("_id", r.get("id"))
    return rows


@app.get("/api/approvals/{approval_id}")
async def api_get_approval(approval_id: str):
    """Get details of a single approval item."""
    row = _fs_get("approval_queue", approval_id)
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    row["id"] = approval_id
    return row


@app.post("/api/approvals")
async def api_create_approval(request: _Request):
    """Create a new approval queue item."""
    import uuid as _u_appr
    data = await request.json()
    if not data.get("client_id"):
        return JSONResponse({"error": "client_id is required"}, status_code=400)
    approval_id = data.get("id") or f"APR-{_u_appr.uuid4().hex[:8].upper()}"
    now = __import__("datetime").datetime.utcnow().isoformat()
    try:
        _fs_set("approval_queue", approval_id, {
            "type": data.get("type", "offer"), "client_id": data["client_id"],
            "client_name": data.get("client_name", ""), "client_email": data.get("client_email", ""),
            "priority": data.get("priority", "medium"), "subject": data.get("subject", ""),
            "email_body_html": data.get("email_body_html", ""), "offer_id": data.get("offer_id", ""),
            "status": "pending", "created_at": now, "updated_at": now,
        })
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)
    row = _fs_get("approval_queue", approval_id)
    if row:
        row["id"] = approval_id
    return {"ok": True, "approval": row}


@app.post("/api/approvals/{approval_id}/approve")
async def api_approve_item(approval_id: str):
    """Approve an item and send the email to the client."""
    row = _fs_get("approval_queue", approval_id)
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    row["id"] = approval_id
    if row.get("status") != "pending":
        return JSONResponse({"error": f"Item is {row.get('status')}, not pending"}, status_code=400)

    # Send email
    email_sent = False
    tracking_id = None
    recipient = row["client_email"]
    if recipient:
        try:
            import smtplib
            from email.mime.multipart import MIMEMultipart
            from email.mime.text import MIMEText

            smtp_user = os.environ.get("SMTP_USER", "")
            smtp_pass = os.environ.get("SMTP_PASS", "")
            smtp_host = os.environ.get("SMTP_HOST", "smtp.gmail.com")
            smtp_port = int(os.environ.get("SMTP_PORT", "587"))
            from_name = os.environ.get("SMTP_FROM_NAME", "Alex Broker")

            # Create tracking record
            tracking_id = f"TRK-{os.urandom(4).hex().upper()}"
            _fs_set("email_tracking", tracking_id, {
                "approval_id": approval_id, "client_id": row.get("client_id"),
                "recipient": recipient, "sent_at": __import__("datetime").datetime.utcnow().isoformat(),
                "open_count": 0,
            })

            # Add tracking pixel + response buttons to email body
            base_url = os.environ.get("ALEX_API_URL", "https://alex-insurance-broker-elo6xae6nq-ey.a.run.app")
            body_html = row["email_body_html"] or ""
            tracking_footer = f"""
            <br/><hr style="border:1px solid #eee; margin:20px 0"/>
            <div style="text-align:center; font-family:sans-serif;">
                <p style="color:#666; font-size:13px;">Are you interested in this offer?</p>
                <a href="{base_url}/api/respond/{tracking_id}/accept"
                   style="display:inline-block; padding:10px 25px; background:#28a745; color:white;
                          text-decoration:none; border-radius:5px; margin:5px; font-weight:bold;">
                    Yes, I'm interested
                </a>
                <a href="{base_url}/api/respond/{tracking_id}/reject"
                   style="display:inline-block; padding:10px 25px; background:#dc3545; color:white;
                          text-decoration:none; border-radius:5px; margin:5px; font-weight:bold;">
                    No, thank you
                </a>
            </div>
            <!-- tracking disabled to avoid email client warnings -->
            """
            full_body = body_html + tracking_footer

            if smtp_user and smtp_pass:
                msg = MIMEMultipart("alternative")
                msg["From"] = f"{from_name} <{smtp_user}>"
                msg["To"] = recipient
                from email.header import Header as _Header
                msg["Subject"] = _Header(row["subject"] or "Insurance offer", "utf-8")
                msg.attach(MIMEText(full_body, "html", "utf-8"))

                with smtplib.SMTP(smtp_host, smtp_port) as server:
                    server.starttls()
                    server.login(smtp_user, smtp_pass)
                    server.send_message(msg)
                email_sent = True
            else:
                # Dry run — just log
                email_sent = True  # Consider it "sent" for status update
        except Exception as e:
            return JSONResponse({"error": f"Email failed: {e}"}, status_code=500)

    # Update status
    now = __import__("datetime").datetime.utcnow().isoformat()
    _fs_update("approval_queue", approval_id, {
        "status": "sent", "approved_at": now, "sent_at": now, "updated_at": now
    })

    # ── RAG Hook: approval.approved ──────────────────────────────
    emit_hook(
        hook="approval.approved",
        actor="broker",
        entity_type="approval",
        entity_id=approval_id,
        content=f"Broker approved email for {row['client_name']} ({recipient}). "
                f"Subject: {row['subject']}. Type: {row['type']}. Priority: {row['priority']}",
        tags=["approval", "approved", row["type"] or "offer"],
        relevance_score=6
    )

    return {"ok": True, "email_sent": email_sent, "tracking_id": tracking_id,
            "recipient": recipient}


@app.post("/api/approvals/{approval_id}/reject")
async def api_reject_item(approval_id: str, reason: str = Body(default="", embed=True)):
    """Reject an approval item."""
    row = _fs_get("approval_queue", approval_id)
    if row and row.get("status") == "pending":
        _fs_update("approval_queue", approval_id, {
            "status": "rejected", "rejected_reason": reason,
            "updated_at": __import__("datetime").datetime.utcnow().isoformat()
        })
    # ── RAG Hook: approval.rejected (HIGH VALUE — learns what NOT to do) ──
    if row:
        emit_hook(
            hook="approval.rejected",
            actor="broker",
            entity_type="approval",
            entity_id=approval_id,
            content=f"Broker REJECTED email for {row['client_name']}. "
                    f"Subject: {row['subject']}. Reason: {reason or 'No reason given'}. "
                    f"Type: {row['type']}",
            tags=["approval", "rejected", row["type"] or "offer", "high_value"],
            relevance_score=10
        )
    return {"ok": True}


@app.put("/api/approvals/{approval_id}/edit")
async def api_edit_approval(approval_id: str, subject: str = Body(default=None),
                             email_body_html: str = Body(default=None)):
    """Edit email subject and/or body before approving."""
    original = _fs_get("approval_queue", approval_id)
    updates = {"updated_at": __import__("datetime").datetime.utcnow().isoformat()}
    if subject is not None:
        updates["subject"] = subject
    if email_body_html is not None:
        updates["email_body_html"] = email_body_html
    _fs_update("approval_queue", approval_id, updates)
    # ── RAG Hook: approval.edited (HIGHEST VALUE — broker corrects Alex) ──
    if original:
        changes = []
        if subject is not None:
            changes.append(f"subject changed from '{original['subject']}' to '{subject}'")
        if email_body_html is not None:
            changes.append("email body was modified")
        emit_hook(
            hook="approval.approved_with_edits",
            actor="broker",
            entity_type="approval",
            entity_id=approval_id,
            content=f"Broker edited email for {original['client_name']} before approving. "
                    f"Changes: {'; '.join(changes)}",
            tags=["approval", "edited", "high_value", "broker_correction"],
            relevance_score=10
        )
    return {"ok": True}


# ── WhatsApp via n8n ─────────────────────────────────────────────────────────

@app.post("/api/approvals/{approval_id}/whatsapp")
async def api_send_whatsapp(approval_id: str, phone: str = Body(default="", embed=True)):
    """Send approval content via WhatsApp — uses n8n webhook or falls back to wa.me link."""
    import urllib.parse
    import urllib.request
    import json as _json

    row = _fs_get("approval_queue", approval_id)
    if row:
        row["id"] = approval_id
        c = _fs_get("clients", row.get("client_id", "")) if row.get("client_id") else None
        if c:
            row.setdefault("client_name", c.get("name"))
            row.setdefault("client_email", c.get("email"))
            row.setdefault("client_phone", c.get("phone"))

    # Use provided phone, or fall back to DB phone
    if not phone:
        phone = row["client_phone"] if row and row["client_phone"] else ""
    if not phone:
        return JSONResponse({"error": "No phone number found. Enter manually."}, status_code=400)

    if not row:
        return JSONResponse({"error": "Item not found"}, status_code=404)

    # Build WhatsApp message with offer details (plain text)
    client_name = row["client_name"] or "Client"
    subject = row["subject"] or "Insurance offer"

    # Extract offer summary from email_body_html (markdown content)
    offer_summary = ""
    try:
        body_html = row["email_body_html"] or ""
    except (KeyError, IndexError):
        body_html = ""
    if body_html:
        import re as _re_wa
        # Extract product lines from markdown table: | 1 | Insurer | Type | **1,234 RON** | ...
        table_lines = _re_wa.findall(
            r'\|\s*(\d+)\s*\|\s*([^|]+?)\s*\|\s*([^|]+?)\s*\|\s*\*?\*?([^|*]+?)\*?\*?\s*\|',
            body_html
        )
        if table_lines:
            offer_summary = "\n📋 *Insurance options:*\n"
            for num, insurer, ptype, premium in table_lines:
                insurer = insurer.strip()
                ptype = ptype.strip()
                premium = premium.strip()
                offer_summary += f"  {num}. {insurer} — {ptype} — {premium}\n"

        # Extract best value recommendation
        best_match = _re_wa.search(r'💡\s*\*?\*?(?:Recomandare|Best Value|Empfehlung)[:\s]*\*?\*?\s*(.+?)(?:\n|$)', body_html)
        if best_match:
            offer_summary += f"\n💡 *Recommendation:* {best_match.group(1).strip()}\n"

        # Extract offer ID
        offer_id_match = _re_wa.search(r'(OFF-[A-F0-9]{8})', body_html)
        if offer_id_match:
            offer_summary = f"\n📄 Offer {offer_id_match.group(1)}\n" + offer_summary

    _client_email = ""
    try:
        _client_email = row["client_email"] or ""
    except (KeyError, IndexError):
        pass

    if offer_summary:
        wa_text = (
            f"Hello {client_name},\n\n"
            f"We have prepared a personalized insurance offer for you:"
            f"{offer_summary}\n"
            f"For full details and documents, please check your email"
            f"{' (' + _client_email + ')' if _client_email else ''}.\n\n"
            f"Best regards,\nAlex — Insurance Broker"
        )
    else:
        wa_text = (
            f"Hello {client_name},\n\n"
            f"{subject}\n\n"
            f"We have prepared a personalized insurance offer for you. "
            f"Please check your email ({_client_email or 'sent separately'}) "
            f"for full details.\n\n"
            f"Best regards,\nAlex — Insurance Broker"
        )

    # Clean phone number
    clean_phone = phone.replace(" ", "").replace("-", "")
    if not clean_phone.startswith("+"):
        clean_phone = "+40" + clean_phone.lstrip("0")

    wa_link = f"https://wa.me/{clean_phone.lstrip('+')}?text={urllib.parse.quote(wa_text)}"

    # Try n8n webhook first
    n8n_url = os.environ.get("N8N_WEBHOOK_URL", "")
    if n8n_url:
        try:
            payload = _json.dumps({
                "event": "whatsapp-send",
                "phone": clean_phone,
                "client_name": client_name,
                "subject": subject,
                "message": wa_text,
                "approval_id": approval_id,
            }).encode("utf-8")
            req = urllib.request.Request(
                n8n_url, data=payload,
                headers={"Content-Type": "application/json"},
                method="POST",
            )
            with urllib.request.urlopen(req, timeout=10) as resp:
                if resp.status < 400:
                    return {"ok": True, "method": "n8n", "phone": clean_phone}
        except Exception:
            pass  # Fall through to wa.me link

    # Fallback: return wa.me link for browser to open
    return {"ok": True, "method": "wa_link", "fallback_url": wa_link, "wa_link": wa_link,
            "phone": clean_phone}


