@app.get("/api/respond/{tracking_id}/{response}")
async def client_respond(tracking_id: str, response: str):
    """Client clicks accept/reject link in email."""
    if response not in ("accept", "reject"):
        return HTMLResponse("<h2>Link invalid</h2>", status_code=400)

    now = __import__("datetime").datetime.utcnow().isoformat()
    _fs_update("email_tracking", tracking_id, {
        "responded": response + "ed", "responded_at": now
    })
    tracking_row = _fs_get("email_tracking", tracking_id)
    if tracking_row and tracking_row.get("approval_id"):
        approval_id = tracking_row["approval_id"]
        if response == "accept":
            _fs_update("approval_queue", approval_id, {"status": "accepted", "updated_at": now})
        approval_row = _fs_get("approval_queue", approval_id)
        if approval_row and approval_row.get("offer_id"):
            _fs_update("offers", approval_row["offer_id"], {
                "client_response": response + "ed", "client_response_at": now
            })

    # HTML response page
    if response == "accept":
        html = """<!DOCTYPE html><html><head><meta charset="UTF-8">
        <style>body{font-family:sans-serif;display:flex;justify-content:center;align-items:center;
        min-height:100vh;margin:0;background:#f0f8f0;}
        .card{background:white;padding:40px;border-radius:10px;text-align:center;box-shadow:0 2px 20px rgba(0,0,0,0.1);}
        h1{color:#28a745;}</style></head><body>
        <div class="card"><h1>Thank you!</h1>
        <p>We received your response. We will contact you shortly with details.</p>
        <p style="color:#666;">Alex - Insurance Broker</p></div></body></html>"""
    else:
        html = """<!DOCTYPE html><html><head><meta charset="UTF-8">
        <style>body{font-family:sans-serif;display:flex;justify-content:center;align-items:center;
        min-height:100vh;margin:0;background:#f8f8f8;}
        .card{background:white;padding:40px;border-radius:10px;text-align:center;box-shadow:0 2px 20px rgba(0,0,0,0.1);}
        h1{color:#666;}</style></head><body>
        <div class="card"><h1>We understand</h1>
        <p>Thank you for your response. If you change your mind, don't hesitate to contact us.</p>
        <p style="color:#666;">Alex - Insurance Broker</p></div></body></html>"""

    return HTMLResponse(html)


