        ("cron_cleanup", "File Cleanup", "Delete reports and temporary files older than 30 days",
         "0 2 * * 0", "file_cleanup", {"max_age_days": 30}, True),
        ("cron_backup", "Database Backup", "Sync database with Firestore",
         "0 3 * * *", "db_backup", {"target": "firestore"}, True),
        ("cron_form_followup", "Form Follow-up", "Send reminders for incomplete form submissions at 4/8/12 days",
         "0 9 * * 1-5", "form_followup", {"reminder_days": [4, 8, 12], "max_reminders": 3}, True),
        ("cron_auto_questionnaire", "Auto-Send Questionnaires", "Auto-detect open claims without questionnaires",
         "0 8 * * 1-5", "auto_questionnaire", {"claim_statuses": ["open", "investigating"], "auto_send": True}, True),
        ("cron_form_daily_report", "Daily Form Report", "Daily completion report emailed to operator",
         "0 18 * * 1-5", "form_daily_report", {"send_email": True}, True),
