# ── Ensure form templates are seeded at startup ──────────────────────────
def _init_form_templates():
    """Seed form templates from JSON files if they don't exist in Firestore."""
    _tpl_dir = Path(__file__).parent / "mcp-server" / "insurance_broker_mcp" / "data" / "form_templates"
    if not _tpl_dir.exists():
        return
    added = 0
    for _tpl_file in _tpl_dir.glob("*.json"):
        try:
            with open(_tpl_file) as _f:
                _tpl = json.load(_f)
            if not _fs_get("form_templates", _tpl["id"]):
                _fs_set("form_templates", _tpl["id"], {
                    "name": _tpl["name"],
                    "description": _tpl.get("description", ""),
                    "language": _tpl.get("language", "de"),
                    "category": _tpl.get("category", "claims"),
                    "sections": _tpl["sections"],  # native list
                    "pdf_filename": _tpl.get("pdf_filename", _tpl_file.stem + ".pdf"),
                    "status": _tpl.get("status", "published"),
                    "created_at": __import__("datetime").datetime.utcnow().isoformat(),
                }, merge=False)
                added += 1
        except Exception:
            pass
    if added:
        _log.info("[startup] Seeded %d form templates to Firestore", added)

try:
    _init_form_templates()
except Exception:
    pass

