@app.post("/api/admin/update-client-emails")
async def admin_update_client_emails(request: _Request):
    """Bulk update all client emails to a target email (for testing)."""
    body = await request.json()
    target = body.get("email", os.environ.get("TEST_CLIENT_EMAIL", "testclient@tpsh.ro"))
    # Update form submissions in Firestore
    all_subs = _fs_all("form_submissions", limit=5000)
    c1 = 0
    for d in all_subs:
        if d.get("client_email") and d["client_email"] != target:
            _fs_set("form_submissions", d["_id"], {"client_email": target}, merge=True)
            c1 += 1
    # Update clients in Firestore
    all_clients = _fs_all("clients", limit=5000)
    c2 = 0
    for c in all_clients:
        if c.get("email") and c["email"] != target:
            _fs_set("clients", c["_id"], {"email": target}, merge=True)
            c2 += 1
    return {"ok": True, "updated_submissions": c1, "updated_clients": c2, "target_email": target}


# ── Cron Jobs API ──

@app.get("/api/cron")
async def api_list_cron_jobs():
    """List all cron jobs."""
    docs = _fs_all("cron_jobs", limit=100)
    jobs = []
    for d in docs:
        d["id"] = d.pop("_id")
        # Ensure parameters is a dict (handle legacy JSON strings)
        if isinstance(d.get("parameters"), str):
            try: d["parameters"] = json.loads(d["parameters"])
            except Exception: pass
        jobs.append(d)
    jobs.sort(key=lambda x: x.get("name", ""))
    return {"jobs": jobs}

@app.put("/api/cron/{job_id}")
async def api_update_cron_job(job_id: str, request: _Request):
    """Update cron job parameters."""
    data = await request.json()
    allowed = {"name", "description", "schedule", "parameters", "is_active"}
    updates = {k: v for k, v in data.items() if k in allowed}
    if not updates:
        return JSONResponse({"error": "No valid fields to update"}, status_code=400)
    updates["updated_at"] = __import__("datetime").datetime.utcnow().isoformat()
    _fs_set("cron_jobs", job_id, updates, merge=True)
    updated = _fs_get("cron_jobs", job_id)
    if updated: updated["id"] = job_id
    return {"ok": True, "job": updated}

@app.post("/api/cron/{job_id}/toggle")
async def api_toggle_cron_job(job_id: str):
    """Toggle a cron job on/off."""
    current = _fs_get("cron_jobs", job_id)
    if not current:
        return JSONResponse({"error": "Job not found"}, status_code=404)
    new_state = not current.get("is_active", True)
    _fs_set("cron_jobs", job_id, {
        "is_active": new_state,
        "updated_at": __import__("datetime").datetime.utcnow().isoformat()
    }, merge=True)
    return {"ok": True, "is_active": new_state}

@app.post("/api/cron/{job_id}/run")
async def api_run_cron_job_now(job_id: str):
    """Manually trigger a cron job (mark as last_run = now, increment run_count)."""
    job = _fs_get("cron_jobs", job_id)
    if not job:
        return JSONResponse({"error": "Job not found"}, status_code=404)
    now = __import__("datetime").datetime.utcnow().isoformat()
    _fs_set("cron_jobs", job_id, {
        "last_run": now, "last_status": "running",
        "run_count": (job.get("run_count") or 0) + 1,
        "updated_at": now,
    }, merge=True)

    # Execute the actual job based on task_type
    job_result = None
    task_type = job.get("task_type", "")
    try:
        if task_type == "form_followup":
            job_result = await api_run_form_followup()
        elif task_type == "auto_questionnaire":
            job_result = await api_auto_send_questionnaires()
        elif task_type == "form_daily_report":
            job_result = await api_form_daily_report()
        elif task_type == "oracle_sync":
            job_result = await oracle_sync_from_sqlite()
        elif task_type == "knowledge_analysis":
            job_result = await api_analyze_patterns()
        elif task_type == "status_report":
            job_result = await api_form_status_report()
        else:
            job_result = {"message": f"Job '{job.get('name','')}' triggered manually (execution pending).", "task_type": task_type}

        _fs_set("cron_jobs", job_id, {"last_status": "success", "updated_at": __import__("datetime").datetime.utcnow().isoformat()}, merge=True)
    except Exception as _cron_err:
        _fs_set("cron_jobs", job_id, {"last_status": "failed", "updated_at": __import__("datetime").datetime.utcnow().isoformat()}, merge=True)
        job_result = {"error": str(_cron_err)}

    return {"ok": True, "message": f"Job '{job.get('name','')}' executed.", "task_type": task_type, "result": job_result}


# ── Clients CRUD ──

@app.get("/api/db/clients")
async def db_list_clients(q: str = Query(default=""), limit: int = Query(default=100, ge=1, le=500)):
    """List all clients, optionally filtered by search query."""
    all_clients = _fs_all("clients", limit=limit)
    if q:
        q_low = q.lower()
        all_clients = [c for c in all_clients if q_low in (c.get("name") or "").lower()
                       or q_low in (c.get("email") or "").lower()
                       or q_low in (c.get("phone") or "").lower()
                       or q_low in (c.get("id_number") or "").lower()]
    all_clients.sort(key=lambda x: x.get("name", ""))
    for c in all_clients:
        c["id"] = c.pop("_id", c.get("id"))
    return {"items": all_clients[:limit], "total": len(all_clients)}

@app.get("/api/db/clients/{client_id}")
async def db_get_client(client_id: str):
    """Get a single client with their policies and claims."""
    client = _fs_get("clients", client_id)
    if not client:
        return JSONResponse({"error": "Client not found"}, status_code=404)
    client["id"] = client_id
    policies = _fs_query("policies", filters=[("client_id", "==", client_id)], limit=100)
    claims = _fs_query("claims", filters=[("client_id", "==", client_id)], limit=100)
    offers = _fs_query("offers", filters=[("client_id", "==", client_id)], limit=100)
    for p in policies: p["id"] = p.pop("_id", p.get("id"))
    for c in claims: c["id"] = c.pop("_id", c.get("id"))
    for o in offers: o["id"] = o.pop("_id", o.get("id"))
    return {"client": client, "policies": policies, "claims": claims, "offers": offers}

