@app.delete("/api/db/clients/{client_id}")
async def db_delete_client(client_id: str):
    """Delete a client and all associated data (policies, claims, offers)."""
    client = _fs_get("clients", client_id)
    if not client:
        return JSONResponse({"error": "Client not found"}, status_code=404)
    # Delete associated records first (cascade)
    for coll in ("offers", "claims", "policies", "vehicles"):
        related = _fs_query(coll, filters=[("client_id", "==", client_id)], limit=500)
        for r in related:
            _fs_delete(coll, r["_id"])
    _fs_delete("clients", client_id)
    return {"ok": True, "deleted": client_id}

