@app.post("/api/claims/{claim_id}/send-questionnaire")
async def api_send_claim_questionnaire(claim_id: str, request: _Request):
    """Create a form submission linked to a claim and send the link to the client.
    Auto-selects template based on policy_type. Sends email + WhatsApp.
    Optional body: {"template_id": "tpl-haftpflicht"} to override auto-selection.
    """
    import uuid as _u; import urllib.parse
    from datetime import datetime as _dt

    body = {}
    try:
        body = await request.json()
    except Exception:
        pass

    # 1. Get claim with client and policy info
    _claim_doc = _fs_get("claims", claim_id)
    if not _claim_doc:
        return JSONResponse({"error": "Claim not found"}, status_code=404)
    _client_doc = _fs_get("clients", _claim_doc.get("client_id", "")) if _claim_doc.get("client_id") else {}
    _policy_doc = _fs_get("policies", _claim_doc.get("policy_id", "")) if _claim_doc.get("policy_id") else {}
    claim = {**_claim_doc, "client_name": (_client_doc or {}).get("name"),
             "client_email": (_client_doc or {}).get("email"),
             "client_phone": (_client_doc or {}).get("phone"),
             "cid": _claim_doc.get("client_id"),
             "policy_type": (_policy_doc or {}).get("policy_type"),
             "insurer": (_policy_doc or {}).get("insurer"),
             "policy_number": (_policy_doc or {}).get("policy_number")}

    # 2. Map policy_type → template_id (with manual override)
    override_tpl = body.get("template_id")
    if override_tpl:
        template_id = override_tpl
    else:
        policy_type = (claim["policy_type"] or "").upper()
        TEMPLATE_MAP = {
            "KFZ": "tpl-kfz-schaden", "CASCO": "tpl-kfz-schaden", "RCA": "tpl-kfz-schaden",
            "AUTO": "tpl-kfz-schaden", "MOTOR": "tpl-kfz-schaden",
            "LIABILITY": "tpl-haftpflicht", "HAFTPFLICHT": "tpl-haftpflicht",
            "PRIVATHAFTPFLICHT": "tpl-haftpflicht", "BETRIEBSHAFTPFLICHT": "tpl-haftpflicht",
            "MASCHINE": "tpl-maschinenbruch", "MASCHINENBRUCH": "tpl-maschinenbruch",
            "UTILAJ": "tpl-maschinenbruch", "MACHINERY": "tpl-maschinenbruch",
            "EQUIPMENT": "tpl-maschinenbruch", "TITAN": "tpl-maschinenbruch",
        }
        template_id = TEMPLATE_MAP.get(policy_type, "tpl-kfz-schaden")

    # 3. Verify template exists
    tpl = _fs_get("form_templates", template_id)
    if not tpl:
        return JSONResponse({"error": f"Template '{template_id}' not found."}, status_code=404)
    tpl["id"] = template_id

    # 4. Check if a submission already exists for this claim
    existing_hits = _fs_query("form_submissions", filters=[("claim_id", "==", claim_id)], limit=1)
    if existing_hits:
        existing = existing_hits[0]; existing["id"] = existing.pop("_id")
        return JSONResponse({
            "error": "Questionnaire already sent for this claim",
            "existing_submission_id": existing["id"],
            "reference": existing.get("reference_number"),
            "status": existing.get("status")
        }, status_code=409)

    # 5. Create submission linked to claim
    sub_id = f"sub-{_u.uuid4().hex[:10]}"
    # Use Schadennummer as Referenznummer if valid 7-digit (Oliver feedback)
    _sn_for_ref = (form_data.get("schadensnummer") or form_data.get("schadennummer","") or "").strip()
    _sn_for_ref_digits = _sn_for_ref.replace("-","").replace(" ","").replace(".","")
    if _sn_for_ref_digits.isdigit() and len(_sn_for_ref_digits) >= 6:
        ref = _sn_for_ref_digits
    else:
        ref = f"FRM-{_dt.utcnow().strftime('%Y')}-{_u.uuid4().hex[:5].upper()}"
    _sn_supplied = (form_data.get("schadensnummer") or form_data.get("schadennummer","") or "").strip()
    _sn_digits = _sn_supplied.replace("-","").replace(" ","").replace(".","")
    if not _sn_digits.isdigit() or len(_sn_digits) < 6:
        import hashlib as _sn_hash
        _auto_sn = str(int(_sn_hash.sha1(sub_id.encode()).hexdigest(),16) % 9000000 + 1000000)
        form_data["schadensnummer"] = _auto_sn
        form_data["schadennummer"] = _auto_sn
    now = _dt.utcnow().isoformat()
    client_name = claim["client_name"] or "there"
    client_email = claim["client_email"] or ""
    client_phone = claim["client_phone"] or ""

    from datetime import timedelta as _tdelta
    follow_up = (_dt.utcnow() + _tdelta(days=4)).isoformat()
    _fs_set("form_submissions", sub_id, {
        "template_id": template_id, "reference_number": ref,
        "claim_id": claim_id, "client_id": claim.get("cid"),
        "client_name": client_name, "client_email": client_email,
        "client_phone": client_phone,
        "form_data": {}, "attachments": [],
        "status": "sent", "completeness_pct": 0,
        "sent_at": now, "sent_via": "both",
        "created_at": now, "follow_up_at": follow_up,
        "reminder_count": 0,
    }, merge=False)

    # 6. Build form URL
    _host = os.environ.get("APP_HOST", "https://alex-insurance-broker-426485075291.europe-west3.run.app")
    form_url = f"{_host}/forms/{template_id}?sub={sub_id}"
    if client_email:
        form_url += f"&client={client_email}"

    results = {"ok": True, "submission_id": sub_id, "reference": ref,
               "form_url": form_url, "template": tpl["name"], "claim_id": claim_id,
               "client_name": client_name, "sent": []}

    # 7. Send email
    if client_email:
        email_html = f"""
        <div style="font-family:'Segoe UI',sans-serif;max-width:600px;margin:0 auto;padding:20px;">
          <div style="background:linear-gradient(135deg,#6366f1,#8b5cf6);padding:30px;border-radius:12px 12px 0 0;text-align:center;">
            <h1 style="color:white;margin:0;font-size:24px;">📋 {tpl['name']}</h1>
            <p style="color:rgba(255,255,255,0.8);margin:8px 0 0;font-size:14px;">Schadenreferenz: {claim.get('insurer_claim_number') or claim_id[:8]}</p>
          </div>
          <div style="background:white;padding:30px;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 12px 12px;">
            <p style="font-size:16px;color:#374151;">{_greeting_for(client_name)}</p>
            <p style="font-size:15px;color:#4b5563;line-height:1.6;">
              wir bitten Sie, das Schadenformular f&uuml;r Ihren Versicherungsschaden auszuf&uuml;llen
              {f'(Vorfall: {claim["incident_date"]})' if claim.get("incident_date") else ''}.
              Bitte klicken Sie auf die Schaltfl&auml;che unten:
            </p>
            <div style="text-align:center;margin:25px 0;">
              <a href="{form_url}" style="background:linear-gradient(135deg,#6366f1,#8b5cf6);color:white;text-decoration:none;
                padding:14px 40px;border-radius:10px;font-size:16px;font-weight:600;display:inline-block;">
                Schadenformular ausf&uuml;llen &rarr;
              </a>
            </div>
            <p style="font-size:14px;color:#6b7280;">
              Referenz: <strong>{ref}</strong><br>
              Bei Fragen antworten Sie einfach auf diese E-Mail.
            </p>
            <hr style="border:none;border-top:1px solid #e5e7eb;margin:20px 0;">
            <p style="font-size:12px;color:#9ca3af;text-align:center;">
              TPSH Versicherungsmakler GmbH
            </p>
          </div>
        </div>
        """
        _claim_sn = claim.get('insurer_claim_number', '') if claim else ''
        _claim_vs = claim.get('policy_number', '') or claim.get('versicherungsschein_nr', '') if claim else ''
        _claim_sd = claim.get('incident_date', '') or claim.get('schadendatum', '') if claim else ''
        if _claim_sn and _claim_vs and _claim_sd:
            _sl2_subj = f"KFZ-Schaden v. {_claim_sd} / Versicherungsnr. {_claim_vs} / TPSH Schadenr. {_claim_sn}"
        elif _claim_sn:
            _sl2_subj = f"Bitte ausfüllen: {tpl['name']} — TPSH Schadenr. {_claim_sn}"
        else:
            _sl2_subj = f"Bitte ausfüllen: {tpl['name']} — Ref {ref}"
        email_ok = _send_email_html([client_email], _sl2_subj, email_html, auto_bcc_operator=True)
        results["sent"].append({"via": "email", "to": client_email, "ok": email_ok})

    # 8. Send WhatsApp if phone available
    if client_phone:
        wa_text = (
            f"{_greeting_for(client_name)}\n\n"
            f"📋 Bitte füllen Sie das Schadenformular aus:\n"
            f"*{tpl['name']}*\n\n"
            f"👉 {form_url}\n\n"
            f"Referenz: {ref}\n"
            f"— TPSH Versicherungsmakler GmbH"
        )
        n8n_url = os.environ.get("N8N_WHATSAPP_WEBHOOK", "")
        wa_sent = False
        if n8n_url:
            try:
                import urllib.request
                _payload = json.dumps({"phone": client_phone, "message": wa_text}).encode()
                _req = urllib.request.Request(n8n_url, data=_payload,
                    headers={"Content-Type": "application/json"}, method="POST")
                urllib.request.urlopen(_req, timeout=10)
                wa_sent = True
            except Exception:
                pass
        wa_link = f"https://wa.me/{client_phone.replace('+','').replace(' ','')}?text={urllib.parse.quote(wa_text)}"
        results["sent"].append({"via": "whatsapp", "to": client_phone, "ok": wa_sent, "wa_link": wa_link})

    return results


async def send_claim_questionnaire_direct(claim_id: str, template_id: str = ""):
    """Standalone version of api_send_claim_questionnaire — no Request dependency.
    Used by MCP tool broker_send_claim_questionnaire.
    """
    class _FakeRequest:
        async def json(self):
            return {"template_id": template_id} if template_id else {}
    return await api_send_claim_questionnaire(claim_id, _FakeRequest())


@app.post("/api/forms/auto-send-questionnaires")
async def api_auto_send_questionnaires():
    """Auto-detect open claims without questionnaires and send appropriate forms.
    Used by cron job 'auto_questionnaire' and quick command 'cmd_send_questionnaire'.
    """
    import uuid as _u; import urllib.parse
    from datetime import datetime as _dt

    # Find open/investigating claims that DON'T have a form_submission yet
    _all_claims_batch = _fs_query("claims", filters=None, limit=500)
    _open_batch = [c for c in _all_claims_batch if c.get("status") in ("open", "investigating")]
    _all_subs_batch = _fs_all("form_submissions", limit=5000)
    _claimed_ids = {s.get("claim_id") for s in _all_subs_batch if s.get("claim_id")}
    claims = []
    for cl in _open_batch:
        cl_id = cl.get("_id") or cl.get("id")
        if cl_id not in _claimed_ids:
            c = _fs_get("clients", cl.get("client_id", "")) if cl.get("client_id") else {}
            p = _fs_get("policies", cl.get("policy_id", "")) if cl.get("policy_id") else {}
            cl["claim_id"] = cl_id
            cl["client_name"] = (c or {}).get("name"); cl["client_email"] = (c or {}).get("email")
            cl["client_phone"] = (c or {}).get("phone"); cl["client_id"] = cl.get("client_id")
            cl["policy_type"] = (p or {}).get("policy_type"); cl["insurer"] = (p or {}).get("insurer")
            cl["policy_number"] = (p or {}).get("policy_number")
            claims.append(cl)

    results = {"ok": True, "total_claims": len(claims), "sent": [], "errors": []}

    TEMPLATE_MAP = {
        "KFZ": "tpl-kfz-schaden", "CASCO": "tpl-kfz-schaden", "RCA": "tpl-kfz-schaden",
        "AUTO": "tpl-kfz-schaden", "MOTOR": "tpl-kfz-schaden",
        "LIABILITY": "tpl-haftpflicht", "HAFTPFLICHT": "tpl-haftpflicht",
        "PRIVATHAFTPFLICHT": "tpl-haftpflicht", "BETRIEBSHAFTPFLICHT": "tpl-haftpflicht",
        "MASCHINE": "tpl-maschinenbruch", "MASCHINENBRUCH": "tpl-maschinenbruch",
        "UTILAJ": "tpl-maschinenbruch", "MACHINERY": "tpl-maschinenbruch",
        "EQUIPMENT": "tpl-maschinenbruch", "TITAN": "tpl-maschinenbruch",
    }

    for claim in claims:
        policy_type = (claim["policy_type"] or "").upper()
        template_id = TEMPLATE_MAP.get(policy_type, "tpl-kfz-schaden")

        # ── AI Hypothesis: ask Claude which template fits + reasoning ────
        ai_hypothesis = None
        try:
            import anthropic as _anth
            _hyp_client = _anth.Anthropic(api_key=os.environ.get("ANTHROPIC_API_KEY", ""))
            _claim_desc = claim["insurer_claim_number"] or ""
            _incident = claim["incident_date"] or ""
            _insurer = claim["insurer"] or ""
            _hyp_msg = _hyp_client.messages.create(
                model="claude-sonnet-4-20250514",
                max_tokens=400,
                messages=[{"role": "user", "content": f"""Analysiere diesen Versicherungsschaden und bestimme den passenden Fragebogen.

Verfügbare Fragebögen:
1. tpl-kfz-schaden — KFZ-Schadenmeldung (Autounfall, Fahrzeugschaden, Verkehrsunfall)
2. tpl-haftpflicht — Haftpflicht-Schadenanzeige (Personenschaden, Sachschaden an Dritten, Haftpflichtansprüche)
3. tpl-maschinenbruch — Maschinenbruch-Schadenformular (Maschinenschaden, Geräteversicherung, Utilaje, Titan Machinery)

Schadendetails:
- Versicherungsart: {policy_type or 'unbekannt'}
- Schadensnummer: {_claim_desc}
- Schadensdatum: {_incident}
- Versicherer: {_insurer}
- Kundenname: {claim['client_name'] or 'unbekannt'}

Antwort als JSON:
{{"template": "tpl-kfz-schaden" oder "tpl-haftpflicht", "hypothesis": "Kurze Begründung auf Deutsch (1-2 Sätze)", "priority": "hoch"|"mittel"|"niedrig", "confidence": 0-100}}
Nur JSON, kein anderer Text."""}]
            )
            _hyp_text = _hyp_msg.content[0].text.strip()
            _hyp_json = json.loads(_hyp_text)
            ai_hypothesis = json.dumps(_hyp_json, ensure_ascii=False)
            # Override template if Claude is confident
            if _hyp_json.get("confidence", 0) >= 70 and _hyp_json.get("template") in ("tpl-kfz-schaden", "tpl-haftpflicht"):
                template_id = _hyp_json["template"]
        except Exception:
            pass  # fallback to TEMPLATE_MAP

        # Verify template exists
        tpl = _fs_get("form_templates", template_id)
        if not tpl:
            results["errors"].append({"claim_id": claim["claim_id"], "error": f"Template {template_id} not found"})
            continue
        tpl["id"] = template_id

        # Create submission
        sub_id = f"sub-{_u.uuid4().hex[:10]}"
        ref = f"FRM-{_dt.utcnow().strftime('%Y')}-{_u.uuid4().hex[:5].upper()}"
        now = _dt.utcnow().isoformat()
        client_name = claim["client_name"] or "there"
        client_email = claim["client_email"] or ""
        client_phone = claim["client_phone"] or ""

        try:
            _fs_set("form_submissions", sub_id, {
                "template_id": template_id, "reference_number": ref,
                "claim_id": claim["claim_id"], "client_id": claim.get("client_id"),
                "client_name": client_name, "client_email": client_email,
                "client_phone": client_phone,
                "form_data": {}, "attachments": [],
                "status": "sent", "completeness_pct": 0,
                "sent_at": now, "sent_via": "both",
                "created_at": now, "ai_hypothesis": ai_hypothesis,
                "reminder_count": 0,
            }, merge=False)
        except Exception as e:
            results["errors"].append({"claim_id": claim["claim_id"], "error": str(e)})
            continue

        # Build form URL
        _host = os.environ.get("APP_HOST", "https://alex-insurance-broker-426485075291.europe-west3.run.app")
        form_url = f"{_host}/forms/{template_id}?sub={sub_id}"
        if client_email:
            form_url += f"&client={client_email}"

        sent_via = []

        # Send email
        if client_email:
            email_html = f"""
            <div style="font-family:'Segoe UI',sans-serif;max-width:600px;margin:0 auto;padding:20px;">
              <div style="background:linear-gradient(135deg,#6366f1,#8b5cf6);padding:30px;border-radius:12px 12px 0 0;text-align:center;">
                <h1 style="color:white;margin:0;font-size:24px;">📋 {tpl['name']}</h1>
              </div>
              <div style="background:white;padding:30px;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 12px 12px;">
                <p style="font-size:16px;color:#374151;">{_greeting_for(client_name)}</p>
                <p style="font-size:15px;color:#4b5563;line-height:1.6;">
                  wir bitten Sie, das Schadenformular f&uuml;r Ihren Versicherungsschaden auszuf&uuml;llen.
                  Bitte klicken Sie auf die Schaltfl&auml;che unten:
                </p>
                <div style="text-align:center;margin:25px 0;">
                  <a href="{form_url}" style="background:linear-gradient(135deg,#6366f1,#8b5cf6);color:white;text-decoration:none;
                    padding:14px 40px;border-radius:10px;font-size:16px;font-weight:600;display:inline-block;">
                    Schadenformular ausf&uuml;llen &rarr;
                  </a>
                </div>
                <p style="font-size:14px;color:#6b7280;">Referenz: <strong>{ref}</strong></p>
                <hr style="border:none;border-top:1px solid #e5e7eb;margin:20px 0;">
                <p style="font-size:12px;color:#9ca3af;text-align:center;">TPSH Versicherungsmakler GmbH</p>
              </div>
            </div>
            """
            _claim_sn2 = claim.get('insurer_claim_number', '') if claim else ''
            _claim_vs2 = claim.get('policy_number', '') or claim.get('versicherungsschein_nr', '') if claim else ''
            _claim_sd2 = claim.get('incident_date', '') or claim.get('schadendatum', '') if claim else ''
            if _claim_sn2 and _claim_vs2 and _claim_sd2:
                _sl3_subj = f"KFZ-Schaden v. {_claim_sd2} / Versicherungsnr. {_claim_vs2} / TPSH Schadenr. {_claim_sn2}"
            elif _claim_sn2:
                _sl3_subj = f"Bitte ausfüllen: {tpl['name']} — TPSH Schadenr. {_claim_sn2}"
            else:
                _sl3_subj = f"Bitte ausfüllen: {tpl['name']} — Ref {ref}"
            email_ok = _send_email_html([client_email], _sl3_subj, email_html, auto_bcc_operator=True)
            sent_via.append({"via": "email", "to": client_email, "ok": email_ok})

        # Send WhatsApp
        if client_phone:
            wa_text = (
                f"{_greeting_for(client_name)}\n\n"
                f"📋 Bitte füllen Sie das Schadenformular aus:\n"
                f"*{tpl['name']}*\n\n"
                f"👉 {form_url}\n\n"
                f"Referenz: {ref}\n"
                f"— TPSH Versicherungsmakler GmbH"
            )
            n8n_url = os.environ.get("N8N_WHATSAPP_WEBHOOK", "")
            wa_sent = False
            if n8n_url:
                try:
                    import urllib.request
                    _payload = json.dumps({"phone": client_phone, "message": wa_text}).encode()
                    _req = urllib.request.Request(n8n_url, data=_payload,
                        headers={"Content-Type": "application/json"}, method="POST")
                    urllib.request.urlopen(_req, timeout=10)
                    wa_sent = True
                except Exception:
                    pass
            sent_via.append({"via": "whatsapp", "to": client_phone, "ok": wa_sent})

        results["sent"].append({
            "claim_id": claim["claim_id"],
            "client_name": client_name,
            "template": tpl["name"],
            "reference": ref,
            "form_url": form_url,
            "sent_via": sent_via,
        })
    return results


@app.get("/api/forms/status-summary")
async def api_forms_status_summary():
    """Get summary of all form submissions grouped by status."""
    from datetime import datetime as _dt, timedelta as _td
    all_subs = _fs_all("form_submissions", limit=5000)
    status_counts = {}
    four_days_ago = (_dt.utcnow() - _td(days=4)).isoformat()
    overdue = 0
    # Sort by created_at descending for recent
    all_subs.sort(key=lambda x: x.get("created_at", ""), reverse=True)
    recent = []
    _tpl_cache = {}
    for d in all_subs:
        st = d.get("status", "unknown")
        status_counts[st] = status_counts.get(st, 0) + 1
        if st in ("sent", "submitted", "incomplete") and (d.get("created_at", "") < four_days_ago):
            overdue += 1
        if len(recent) < 20:
            tid = d.get("template_id", "")
            if tid and tid not in _tpl_cache:
                _tpl_cache[tid] = _fs_get("form_templates", tid) or {}
            d["template_name"] = _tpl_cache.get(tid, {}).get("name", "")
            d["id"] = d.pop("_id")
            recent.append(d)
    return {
        "status_counts": status_counts,
        "total": sum(status_counts.values()),
        "overdue": overdue,
        "recent": recent,
    }


# ── Daily Form Completion Report ──────────────────────────────────────────

@app.post("/api/forms/daily-report")
async def api_form_daily_report():
    """Generate daily form completion report and email to operator.
    Shows: total forms, per-status counts, completion rate, overdue list.
    """
    from datetime import datetime as _dt, timedelta as _td

    all_subs = _fs_all("form_submissions", limit=5000)
    _tpl_cache = {}
    status_counts = {}
    four_days_ago = (_dt.utcnow() - _td(days=4)).isoformat()
    seven_days_ago = (_dt.utcnow() - _td(days=7)).isoformat()
    overdue_rows = []
    recent_completed = []

    for d in all_subs:
        d["id"] = d.pop("_id")
        st = d.get("status", "unknown")
        status_counts[st] = status_counts.get(st, 0) + 1
        # Overdue
        if st in ("sent", "incomplete") and (d.get("created_at", "") < four_days_ago):
            tid = d.get("template_id", "")
            if tid and tid not in _tpl_cache:
                _tpl_cache[tid] = _fs_get("form_templates", tid) or {}
            d["template_name"] = _tpl_cache.get(tid, {}).get("name", "")
            overdue_rows.append(d)
        # Recent completed
        if st in ("submitted", "validated", "processing", "review") and d.get("submitted_at", "") > seven_days_ago:
            tid = d.get("template_id", "")
            if tid and tid not in _tpl_cache:
                _tpl_cache[tid] = _fs_get("form_templates", tid) or {}
            d["template_name"] = _tpl_cache.get(tid, {}).get("name", "")
            recent_completed.append(d)

    total = sum(status_counts.values())
    completed = status_counts.get("validated", 0) + status_counts.get("submitted", 0) + status_counts.get("processing", 0) + status_counts.get("review", 0)
    sent_waiting = status_counts.get("sent", 0)
    rejected = status_counts.get("rejected", 0)
    completion_rate = round((completed / total * 100) if total > 0 else 0, 1)
    overdue_rows.sort(key=lambda x: x.get("created_at", ""))
    recent_completed.sort(key=lambda x: x.get("submitted_at", ""), reverse=True)
    recent_completed = recent_completed[:10]

    now_str = _dt.utcnow().strftime("%d.%m.%Y %H:%M")

    # Build HTML report
    overdue_html = ""
    if overdue_rows:
        overdue_html = "<table style='width:100%;border-collapse:collapse;margin:10px 0'>"
        overdue_html += "<tr style='background:#fee2e2'><th style='padding:8px;text-align:left;border:1px solid #e5e7eb'>Ref</th><th style='padding:8px;text-align:left;border:1px solid #e5e7eb'>Client</th><th style='padding:8px;text-align:left;border:1px solid #e5e7eb'>Formular</th><th style='padding:8px;text-align:left;border:1px solid #e5e7eb'>Gesendet</th><th style='padding:8px;text-align:left;border:1px solid #e5e7eb'>Erinnerungen</th></tr>"
        for r in overdue_rows:
            created = r.get("created_at","")[:10] if r.get("created_at","") else "?"
            overdue_html += f"<tr><td style='padding:6px;border:1px solid #e5e7eb'>{r['reference_number'] or r['id']}</td><td style='padding:6px;border:1px solid #e5e7eb'>{r['client_name'] or 'N/A'}</td><td style='padding:6px;border:1px solid #e5e7eb'>{r['template_name'] or '?'}</td><td style='padding:6px;border:1px solid #e5e7eb'>{created}</td><td style='padding:6px;border:1px solid #e5e7eb'>{r.get('reminder_count', 0) or 0}/3</td></tr>"
        overdue_html += "</table>"
    else:
        overdue_html = "<p style='color:#065f46;font-weight:600'>✅ Keine überfälligen Formulare</p>"

    completed_html = ""
    if recent_completed:
        completed_html = "<table style='width:100%;border-collapse:collapse;margin:10px 0'>"
        completed_html += "<tr style='background:#d1fae5'><th style='padding:8px;text-align:left;border:1px solid #e5e7eb'>Ref</th><th style='padding:8px;text-align:left;border:1px solid #e5e7eb'>Client</th><th style='padding:8px;text-align:left;border:1px solid #e5e7eb'>Formular</th><th style='padding:8px;text-align:left;border:1px solid #e5e7eb'>%</th></tr>"
        for r in recent_completed:
            completed_html += f"<tr><td style='padding:6px;border:1px solid #e5e7eb'>{r.get('reference_number',r.get('_id','?'))}</td><td style='padding:6px;border:1px solid #e5e7eb'>{r.get('client_name','N/A') or 'N/A'}</td><td style='padding:6px;border:1px solid #e5e7eb'>{r.get('template_name','?') or '?'}</td><td style='padding:6px;border:1px solid #e5e7eb'>{r.get('completeness_pct',r.get('completeness',0))}%</td></tr>"
        completed_html += "</table>"
    else:
        completed_html = "<p style='color:#6b7280'>Keine Einreichungen in den letzten 7 Tagen</p>"

    report_html = f"""
    <div style="font-family:'Segoe UI',sans-serif;max-width:700px;margin:0 auto;padding:20px;">
      <div style="background:linear-gradient(135deg,#6366f1,#8b5cf6);padding:30px;border-radius:12px 12px 0 0;text-align:center;">
        <h1 style="color:white;margin:0;font-size:22px;">📊 Täglicher Formularbericht</h1>
        <p style="color:rgba(255,255,255,0.8);margin:8px 0 0;font-size:14px;">{now_str} UTC</p>
      </div>
      <div style="background:white;padding:30px;border:1px solid #e5e7eb;border-top:none;">

        <div style="display:flex;gap:12px;margin-bottom:20px;flex-wrap:wrap;">
          <div style="flex:1;min-width:120px;background:#f3f4f6;padding:16px;border-radius:10px;text-align:center;">
            <div style="font-size:28px;font-weight:700;color:#374151;">{total}</div>
            <div style="font-size:12px;color:#6b7280;margin-top:4px;">Gesamt</div>
          </div>
          <div style="flex:1;min-width:120px;background:#d1fae5;padding:16px;border-radius:10px;text-align:center;">
            <div style="font-size:28px;font-weight:700;color:#065f46;">{completion_rate}%</div>
            <div style="font-size:12px;color:#065f46;margin-top:4px;">Abschlussrate</div>
          </div>
          <div style="flex:1;min-width:120px;background:#fef3c7;padding:16px;border-radius:10px;text-align:center;">
            <div style="font-size:28px;font-weight:700;color:#92400e;">{sent_waiting}</div>
            <div style="font-size:12px;color:#92400e;margin-top:4px;">Warten</div>
          </div>
          <div style="flex:1;min-width:120px;background:#fee2e2;padding:16px;border-radius:10px;text-align:center;">
            <div style="font-size:28px;font-weight:700;color:#991b1b;">{len(overdue_rows)}</div>
            <div style="font-size:12px;color:#991b1b;margin-top:4px;">Überfällig</div>
          </div>
        </div>

        <h3 style="color:#374151;margin:20px 0 8px;">🔴 Überfällige Formulare ({len(overdue_rows)})</h3>
        {overdue_html}

        <h3 style="color:#374151;margin:20px 0 8px;">✅ Letzte Einreichungen (7 Tage)</h3>
        {completed_html}

        <h3 style="color:#374151;margin:20px 0 8px;">📈 Status-Übersicht</h3>
        <table style="width:100%;border-collapse:collapse;">
          <tr><td style="padding:6px;border-bottom:1px solid #e5e7eb;color:#6b7280">Gesendet (wartend)</td><td style="padding:6px;border-bottom:1px solid #e5e7eb;font-weight:600">{status_counts.get('sent', 0)}</td></tr>
          <tr><td style="padding:6px;border-bottom:1px solid #e5e7eb;color:#6b7280">Eingereicht</td><td style="padding:6px;border-bottom:1px solid #e5e7eb;font-weight:600">{status_counts.get('submitted', 0)}</td></tr>
          <tr><td style="padding:6px;border-bottom:1px solid #e5e7eb;color:#6b7280">In Bearbeitung</td><td style="padding:6px;border-bottom:1px solid #e5e7eb;font-weight:600">{status_counts.get('processing', 0)}</td></tr>
          <tr><td style="padding:6px;border-bottom:1px solid #e5e7eb;color:#6b7280">Validiert</td><td style="padding:6px;border-bottom:1px solid #e5e7eb;font-weight:600">{status_counts.get('validated', 0)}</td></tr>
          <tr><td style="padding:6px;border-bottom:1px solid #e5e7eb;color:#6b7280">Abgelehnt</td><td style="padding:6px;border-bottom:1px solid #e5e7eb;font-weight:600">{status_counts.get('rejected', 0)}</td></tr>
          <tr><td style="padding:6px;border-bottom:1px solid #e5e7eb;color:#6b7280">Unvollständig</td><td style="padding:6px;border-bottom:1px solid #e5e7eb;font-weight:600">{status_counts.get('incomplete', 0)}</td></tr>
        </table>
      </div>
      <div style="background:#f9fafb;padding:16px;border-radius:0 0 12px 12px;border:1px solid #e5e7eb;border-top:none;text-align:center;">
        <a href="{os.environ.get('APP_HOST', 'https://alex-insurance-broker-426485075291.europe-west3.run.app')}/dashboard/forms"
           style="color:#6366f1;font-weight:600;text-decoration:none;">Dashboard öffnen →</a>
        <p style="font-size:11px;color:#9ca3af;margin:8px 0 0;">TPSH Versicherungsmakler GmbH — Automatischer Bericht</p>
      </div>
    </div>
    """

    # Send email to operator
    operator_email = os.environ.get("SMTP_USER", "")
    report_to = os.environ.get("REPORT_EMAIL", operator_email)
    email_sent = False
    if report_to:
        email_sent = _send_email_html(
            [report_to],
            f"📊 Formularbericht — {now_str} — {completion_rate}% Abschlussrate",
            report_html
        )

    return {
        "ok": True,
        "total": total,
        "completion_rate": completion_rate,
        "overdue": len(overdue_rows),
        "completed_recent": len(recent_completed),
        "status_counts": status_counts,
        "email_sent": email_sent,
        "report_to": report_to,
    }


# ── Vehicles CRUD ──

@app.get("/api/db/vehicles")
async def db_list_vehicles(q: str = Query(default=""), client_id: str = Query(default=""),
                            limit: int = Query(default=100, ge=1, le=500)):
    """List vehicles with optional search and client filter."""
    filters = []
    if client_id:
        filters.append(("client_id", "==", client_id))
    rows = _fs_query("vehicles", filters=filters if filters else None, limit=limit)
    if q:
        q_low = q.lower()
        rows = [v for v in rows if q_low in (v.get("plate_number") or "").lower()
                or q_low in (v.get("make") or "").lower()
                or q_low in (v.get("model") or "").lower()
                or q_low in (v.get("vin") or "").lower()]
    for r in rows:
        r["id"] = r.pop("_id", r.get("id"))
        if r.get("client_id"):
            c = _fs_get("clients", r["client_id"])
            r["client_name"] = c.get("name") if c else None
    return {"items": rows[:limit], "total": len(rows)}

@app.get("/api/db/vehicles/{vehicle_id}")
async def db_get_vehicle(vehicle_id: str):
    """Get a single vehicle with associated policies."""
    vehicle = _fs_get("vehicles", vehicle_id)
    if not vehicle:
        return JSONResponse({"error": "Vehicle not found"}, status_code=404)
    vehicle["id"] = vehicle_id
    if vehicle.get("client_id"):
        c = _fs_get("clients", vehicle["client_id"])
        vehicle["client_name"] = c.get("name") if c else None
    policies = _fs_query("policies", filters=[("vehicle_id", "==", vehicle_id)], limit=100)
    for p in policies: p["id"] = p.pop("_id", p.get("id"))
    return {"vehicle": vehicle, "policies": policies}

@app.put("/api/db/vehicles/{vehicle_id}")
async def db_update_vehicle(vehicle_id: str, request: _Request):
    """Update vehicle fields."""
    data = await request.json()
    allowed = {"plate_number", "vin", "make", "model", "year", "engine_cc", "engine_power_kw",
               "fuel_type", "vehicle_type", "color", "vehicle_value", "seats", "gross_weight_kg",
               "registration_date", "notes"}
    updates = {k: v for k, v in data.items() if k in allowed}
    if not updates:
        return JSONResponse({"error": "No valid fields to update"}, status_code=400)
    _fs_update("vehicles", vehicle_id, updates)
    updated = _fs_get("vehicles", vehicle_id)
    if updated: updated["id"] = vehicle_id
    return {"ok": True, "vehicle": updated}

@app.post("/api/db/vehicles")
async def db_create_vehicle(request: _Request):
    """Create a new vehicle."""
    import uuid as _u
    data = await request.json()
    if not data.get("client_id") or not data.get("plate_number"):
        return JSONResponse({"error": "client_id and plate_number are required"}, status_code=400)
    vehicle_id = f"VEH{_u.uuid4().hex[:6].upper()}"
    client = _fs_get("clients", data["client_id"])
    if not client:
        return JSONResponse({"error": "Client not found"}, status_code=404)
    _fs_set("vehicles", vehicle_id, {
        "client_id": data["client_id"], "plate_number": (data.get("plate_number") or "").upper().strip(),
        "vin": data.get("vin"), "make": data.get("make"), "model": data.get("model"),
        "year": data.get("year"), "engine_cc": data.get("engine_cc"),
        "engine_power_kw": data.get("engine_power_kw"),
        "fuel_type": data.get("fuel_type", "benzina"), "vehicle_type": data.get("vehicle_type", "autoturism"),
        "color": data.get("color"), "vehicle_value": data.get("vehicle_value"),
        "seats": data.get("seats", 5), "gross_weight_kg": data.get("gross_weight_kg"),
        "registration_date": data.get("registration_date"), "notes": data.get("notes"),
        "created_at": __import__("datetime").datetime.utcnow().isoformat(),
    }, merge=False)
    vehicle = _fs_get("vehicles", vehicle_id)
    if vehicle: vehicle["id"] = vehicle_id
    return {"ok": True, "vehicle": vehicle}

@app.delete("/api/db/vehicles/{vehicle_id}")
async def db_delete_vehicle(vehicle_id: str):
    """Delete a vehicle. Unlinks from policies first."""
    vehicle = _fs_get("vehicles", vehicle_id)
    if not vehicle:
        return JSONResponse({"error": "Vehicle not found"}, status_code=404)
    active_pols = _fs_query("policies", filters=[("vehicle_id", "==", vehicle_id), ("status", "==", "active")], limit=10)
    if len(active_pols) > 0:
        return JSONResponse({"error": f"Vehicle has {len(active_pols)} active policies. Cancel them first."}, status_code=400)
    # Unlink from expired/cancelled policies
    linked = _fs_query("policies", filters=[("vehicle_id", "==", vehicle_id)], limit=500)
    for p in linked:
        _fs_update("policies", p["_id"], {"vehicle_id": None})
    _fs_delete("vehicles", vehicle_id)
    return {"ok": True, "deleted": vehicle_id}

