@app.get("/api/db/offers")
async def db_list_offers(client_id: str = Query(default=""), limit: int = Query(default=100, ge=1, le=500)):
    """List offers with optional client filter."""
    filters = [("client_id", "==", client_id)] if client_id else None
    rows = _fs_query("offers", filters=filters, limit=limit)
    for r in rows:
        r["id"] = r.pop("_id", r.get("id"))
        if r.get("client_id"):
            c = _fs_get("clients", r["client_id"])
            r["client_name"] = c.get("name") if c else None
    rows.sort(key=lambda x: x.get("created_at", ""), reverse=True)
    return {"items": rows, "total": len(rows)}

# ── DB Stats ──

@app.get("/api/db/stats")
async def db_stats():
    """Overall database stats for the database browser."""
    stats = {
        "clients": _fs_count("clients"),
        "vehicles": _fs_count("vehicles"),
        "policies": _fs_count("policies"),
        "claims": _fs_count("claims"),
        "insurers": _fs_count("insurers"),
        "products": _fs_count("products"),
        "offers": _fs_count("offers"),
        "approval_queue": _fs_count("approval_queue"),
    }
    return stats


