@app.post("/api/public/request-offer")
async def api_request_offer(
    plate_number: str = _Form(...),
    phone: str = _Form(...),
    email: str = _Form(default=""),
    name: str = _Form(default=""),
):
    """Client requests an offer → creates approval item for broker to process."""
    import uuid
    # Create or find client
    client_id = None
    if email:
        hits = _fs_query("clients", filters=[("email", "==", email)], limit=1)
        if hits:
            client_id = hits[0].get("_id")
    if not client_id and name:
        client_id = str(_uuid.uuid4())[:8]
        try:
            _fs_set("clients", client_id, {
                "name": name or f"Client {plate_number}", "email": email, "phone": phone,
                "created_at": __import__("datetime").datetime.utcnow().isoformat(),
            })
        except Exception:
            client_id = None

    # Create approval queue item of type 'offer_request'
    item_id = f"REQ-{_uuid.uuid4().hex[:8].upper()}"
    now = __import__("datetime").datetime.utcnow().isoformat()
    try:
        _fs_set("approval_queue", item_id, {
            "type": "offer_request", "client_id": client_id,
            "client_name": name or f"Client {plate_number}", "client_email": email,
            "subject": f"RCA Quote Request — {plate_number}",
            "email_body_html":
                f"<div style='font-family:sans-serif;'>"
                f"<h3>📋 Website Quote Request</h3>"
                f"<table style='border-collapse:collapse; margin:10px 0;'>"
                f"<tr><td style='padding:8px; border:1px solid #ddd; font-weight:bold;'>License Plate</td>"
                f"<td style='padding:8px; border:1px solid #ddd;'><strong>{plate_number.upper()}</strong></td></tr>"
                f"<tr><td style='padding:8px; border:1px solid #ddd; font-weight:bold;'>Phone</td>"
                f"<td style='padding:8px; border:1px solid #ddd;'>{phone}</td></tr>"
                f"<tr><td style='padding:8px; border:1px solid #ddd; font-weight:bold;'>Email</td>"
                f"<td style='padding:8px; border:1px solid #ddd;'>{email or 'not specified'}</td></tr>"
                f"<tr><td style='padding:8px; border:1px solid #ddd; font-weight:bold;'>Name</td>"
                f"<td style='padding:8px; border:1px solid #ddd;'>{name or 'not specified'}</td></tr>"
                f"</table>"
                f"<p>⚡ <em>Client is waiting for an RCA quote. Check the data and generate the offer from Chat Alex.</em></p>"
                f"</div>",
            "priority": "high", "status": "pending", "created_at": now, "updated_at": now,
        })
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)

    # Notify n8n if configured
    n8n_url = os.environ.get("N8N_WEBHOOK_URL", "")
    if n8n_url:
        try:
            import urllib.request, json as _j
            payload = _j.dumps({
                "event": "offer-request",
                "plate_number": plate_number,
                "phone": phone,
                "email": email,
                "name": name,
                "item_id": item_id,
            }).encode("utf-8")
            req = urllib.request.Request(n8n_url, data=payload,
                                         headers={"Content-Type": "application/json"}, method="POST")
            urllib.request.urlopen(req, timeout=5)
        except Exception:
            pass  # Non-critical

    # Return success page
    return HTMLResponse(f"""<!DOCTYPE html>
<html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Request Received — Alex Broker</title>
<style>
    body {{ font-family: 'Segoe UI', sans-serif; background: #f0f4f8; display: flex; justify-content: center;
           align-items: center; min-height: 100vh; margin: 0; }}
    .card {{ background: white; border-radius: 16px; padding: 40px; max-width: 500px; text-align: center;
            box-shadow: 0 10px 40px rgba(0,0,0,0.1); }}
    .icon {{ font-size: 3em; margin-bottom: 15px; }}
    h2 {{ color: #2c3e50; margin: 10px 0; }}
    p {{ color: #666; line-height: 1.6; }}
    .plate {{ background: #f0f4f8; padding: 10px 20px; border-radius: 8px; font-size: 1.3em;
             font-weight: bold; color: #2c3e50; display: inline-block; margin: 10px 0; }}
</style></head><body>
<div class="card">
    <div class="icon">✅</div>
    <h2>Request received!</h2>
    <div class="plate">{plate_number.upper()}</div>
    <p>Thank you! A broker will review your request and contact you
    as soon as possible with a personalized RCA offer.</p>
    <p style="color:#999; font-size:0.9em; margin-top:20px;">Alex — AI Insurance Broker</p>
</div></body></html>""")


