@app.get("/api/forms/templates")
async def api_list_templates():
    """List all form templates (with section/field counts)."""
    docs = _fs_query("form_templates", order_by=("created_at",), limit=500)
    results = []
    for d in docs:
        d["id"] = d.pop("_id")
        # sections stored as list in Firestore; handle legacy JSON string
        sec = d.get("sections") or d.pop("sections_json", "[]")
        if isinstance(sec, str):
            sec = json.loads(sec or "[]")
        d["sections"] = sec
        d.pop("sections_json", None)
        results.append(d)
    return results

@app.get("/api/forms/templates/{tpl_id}")
async def api_get_template(tpl_id: str):
    d = _fs_get("form_templates", tpl_id)
    if not d: return JSONResponse({"error": "not found"}, 404)
    d["id"] = tpl_id
    sec = d.get("sections") or d.pop("sections_json", "[]")
    if isinstance(sec, str): sec = json.loads(sec or "[]")
    d["sections"] = sec
    d.pop("sections_json", None)
    return d

@app.post("/api/forms/templates")
async def api_create_template(request: _Request):
    import uuid as _u
    body = await request.json()
    tpl_id = body.get("id") or f"tpl-{_u.uuid4().hex[:8]}"
    now = __import__("datetime").datetime.utcnow().isoformat()
    _fs_set("form_templates", tpl_id, {
        "name": body["name"],
        "description": body.get("description", ""),
        "language": body.get("language", "de"),
        "category": body.get("category", "claims"),
        "sections": body.get("sections", []),  # stored as native list
        "pdf_filename": body.get("pdf_filename", ""),
        "status": body.get("status", "draft"),
        "novonexus_form_id": body.get("novonexus_form_id"),
        "novonexus_public_url": body.get("novonexus_public_url"),
        "collection_mode": body.get("collection_mode", "alex"),
        "created_at": now,
    }, merge=False)
    _audit("template.created", actor="broker", entity_type="form_template",
           entity_id=tpl_id, details=f"Template created: {body.get('name','')}")
    return {"id": tpl_id, "status": "saved"}

@app.put("/api/forms/templates/{tpl_id}")
async def api_update_template(tpl_id: str, request: _Request):
    body = await request.json()
    updates = {}
    for k in ["name", "description", "language", "category", "pdf_filename", "status",
              "novonexus_form_id", "novonexus_public_url", "collection_mode"]:
        if k in body:
            updates[k] = body[k]
    if "sections" in body:
        updates["sections"] = body["sections"]  # native list in Firestore
    if updates:
        updates["updated_at"] = __import__("datetime").datetime.utcnow().isoformat()
        _fs_set("form_templates", tpl_id, updates, merge=True)
    _audit("template.updated", actor="broker", entity_type="form_template",
           entity_id=tpl_id, details=f"Template updated")
    return {"id": tpl_id, "status": "updated"}

@app.post("/api/forms/templates/{tpl_id}/translate")
async def api_translate_template(tpl_id: str, request: _Request):
    """Translate template field labels to target language. Caches in wiki."""
    body = await request.json()
    target_lang = body.get("language", "EN")
    lang_names = {"DE": "German", "EN": "English", "RO": "Romanian"}
    lang_full = lang_names.get(target_lang, target_lang)

    tpl = _fs_get("form_templates", tpl_id)
    if not tpl:
        return JSONResponse({"error": "template not found"}, 404)

    tpl_name = tpl.get("name", tpl_id)
    wiki_title = f"Translation: {tpl_name} → {target_lang}"

    # Check wiki cache first
    all_wiki = _fs_all("alex_wiki", limit=500)
    cached = [w for w in all_wiki if w.get("title", "").lower() == wiki_title.lower()]
    if cached:
        try:
            cached_sections = json.loads(cached[0].get("content", "[]"))
            if isinstance(cached_sections, list) and cached_sections:
                return {"ok": True, "sections": cached_sections, "source": "wiki_cache", "language": target_lang}
        except: pass

    # Build translation request - safely load sections with fallback
    sections = tpl.get("sections") or tpl.get("sections_json") or []
    if isinstance(sections, str):
        try:
            sections = json.loads(sections)
        except (json.JSONDecodeError, ValueError):
            # Try fixing common JSON issues in stored sections
            import re as _re_fix
            _fixed = sections.replace("'", '"')
            _fixed = _re_fix.sub(r',\s*([}\]])', r'\1', _fixed)
            try:
                sections = json.loads(_fixed)
            except Exception:
                return JSONResponse({"ok": False, "error": "Template sections contain malformed JSON"}, 400)
    if not isinstance(sections, list):
        sections = []

    # Extract only labels/placeholders to reduce prompt size
    labels_to_translate = []
    for sec in sections:
        sec_title = sec.get("title", "")
        if sec_title:
            labels_to_translate.append({"type": "section", "original": sec_title})
        for f in sec.get("fields", []):
            lbl = f.get("label", "")
            if lbl:
                labels_to_translate.append({"type": "field", "name": f.get("name", ""), "original": lbl})
            ph = f.get("placeholder", "")
            if ph:
                labels_to_translate.append({"type": "placeholder", "name": f.get("name", ""), "original": ph})

    if not labels_to_translate:
        return JSONResponse({"ok": False, "error": "No translatable labels found in template"}, 400)

    # Call Claude for translation
    try:
        import anthropic as _anth
        _client = _anth.Anthropic()
        _prompt = f"""Translate these insurance form labels to {lang_full}.
Return ONLY a JSON array. Each item must have "type", "original", and "translated" fields.
Do NOT wrap in markdown code blocks. Do NOT add explanation.

{json.dumps(labels_to_translate, ensure_ascii=False)}"""

        try:
            _resp = _client.messages.create(
                model="claude-sonnet-4-20250514",
                max_tokens=4096,
                messages=[{"role": "user", "content": _prompt}]
            )
        except Exception as _translate_err:
            return JSONResponse({"ok": False, "error": f"AI temporarily unavailable: {str(_translate_err)}"}, status_code=503)
        _text = _resp.content[0].text.strip()

        # Multi-strategy JSON extraction
        import re as _re_translate
        translations = None

        # Strategy 1: direct parse
        try:
            translations = json.loads(_text)
        except (json.JSONDecodeError, ValueError):
            pass

        # Strategy 2: extract from markdown code blocks
        if translations is None:
            _md_match = _re_translate.search(r'```(?:json)?\s*\n?(.*?)```', _text, _re_translate.DOTALL)
            if _md_match:
                try:
                    translations = json.loads(_md_match.group(1).strip())
                except (json.JSONDecodeError, ValueError):
                    pass

        # Strategy 3: extract JSON array substring
        if translations is None:
            _arr_match = _re_translate.search(r'\[.*\]', _text, _re_translate.DOTALL)
            if _arr_match:
                try:
                    translations = json.loads(_arr_match.group(0))
                except (json.JSONDecodeError, ValueError):
                    pass

        # Strategy 4: fix common JSON issues (single quotes, trailing commas)
        if translations is None:
            _fixed_text = _text.replace("'", '"')
            _fixed_text = _re_translate.sub(r',\s*([}\]])', r'\1', _fixed_text)
            _arr_match2 = _re_translate.search(r'\[.*\]', _fixed_text, _re_translate.DOTALL)
            if _arr_match2:
                try:
                    translations = json.loads(_arr_match2.group(0))
                except (json.JSONDecodeError, ValueError):
                    pass

        if translations is None:
            return JSONResponse({"ok": False, "error": f"Could not parse translation response"}, 500)

        # Apply translations to sections
        trans_map = {}
        for t in translations:
            key = t.get("original", "")
            if key: trans_map[key] = t.get("translated", key)

        translated_sections = json.loads(json.dumps(sections))  # deep copy
        for sec in translated_sections:
            if sec.get("title") in trans_map:
                sec["title"] = trans_map[sec["title"]]
            for f in sec.get("fields", []):
                if f.get("label") in trans_map:
                    f["label"] = trans_map[f["label"]]
                if f.get("placeholder") in trans_map:
                    f["placeholder"] = trans_map[f["placeholder"]]

        # Cache in wiki
        from datetime import datetime as _dt_wiki
        _wiki_upsert(wiki_title, json.dumps(translated_sections, ensure_ascii=False),
                     tags=["translation", target_lang.lower(), tpl_id])

        return {"ok": True, "sections": translated_sections, "source": "ai_translated", "language": target_lang,
                "translated_count": len(trans_map)}

    except Exception as e:
        return JSONResponse({"ok": False, "error": str(e)}, 500)


@app.get("/api/forms/templates/{tpl_id}/export-novonexus")
async def api_export_template_novonexus(tpl_id: str, form_id: int = 33):
    """Export a template in NovoNexus Formular-Designer JSON format."""
    sys.path.insert(0, os.path.join(os.path.dirname(__file__), "scripts"))
    from novonexus_converter import convert_template as _nn_convert
    tpl = _fs_get("form_templates", tpl_id)
    if not tpl:
        return JSONResponse({"error": "template not found"}, 404)
    tpl["id"] = tpl_id
    effective_form_id = tpl.get("novonexus_form_id") or form_id
    sec = tpl.get("sections") or tpl.get("sections_json", [])
    if isinstance(sec, str): sec = json.loads(sec or "[]")
    template_data = {"id": tpl_id, "name": tpl["name"], "sections": sec}
    nn_schema = _nn_convert(template_data, effective_form_id)
    filename = f"{tpl_id}_novonexus_schema.json"
    return Response(
        content=json.dumps(nn_schema, ensure_ascii=False, indent=2),
        media_type="application/json",
        headers={"Content-Disposition": f'attachment; filename="{filename}"', "X-Template-Id": tpl_id}
    )

