@app.get("/api/forms/submissions")
async def api_list_submissions(status: str = None, template_id: str = None, page: int = 1, limit: int = 500):
    """List form submissions. Default limit=500 (backwards-compatible array response).
    Pass ?page=N&limit=M for pagination. Response always array; totals in X-Total-Count / X-Page headers."""
    filters = []
    if status:
        filters.append(("status", "==", status))
    if template_id:
        filters.append(("template_id", "==", template_id))
    try: page = max(1, int(page))
    except: page = 1
    try: limit = max(1, min(1000, int(limit)))
    except: limit = 500
    docs = _fs_query("form_submissions", filters=filters or None,
                     order_by=("created_at",), limit=5000)
    total = len(docs)
    start = (page - 1) * limit
    end = start + limit
    page_docs = docs[start:end]
    items = []
    for d in page_docs:
        d["id"] = d.pop("_id")
        items.append(_fs_sub_to_dict(d))
    pages = (total + limit - 1) // limit if limit > 0 else 1
    return JSONResponse(content=items, headers={
        "X-Total-Count": str(total),
        "X-Page": str(page),
        "X-Limit": str(limit),
        "X-Pages": str(pages),
    })

@app.get("/api/forms/submissions/export-all")
async def api_export_all_submissions(status: str = None, template_id: str = None):
    """Bulk export all submissions (filtered) as a single JSON array download."""
    filters = []
    if status: filters.append(("status", "==", status))
    if template_id: filters.append(("template_id", "==", template_id))
    docs = _fs_query("form_submissions", filters=filters or None,
                     order_by=("created_at",), limit=1000)
    # Cache templates for JOIN-like behavior
    _tpl_cache = {}
    exports = []
    for r in docs:
        r["id"] = r.pop("_id")
        form_data = r.get("form_data") or {}
        if isinstance(form_data, str): form_data = json.loads(form_data or "{}")
        # Load template (cached)
        _tid = r.get("template_id", "")
        if _tid and _tid not in _tpl_cache:
            _tpl_cache[_tid] = _fs_get("form_templates", _tid) or {}
        _tpl_d = _tpl_cache.get(_tid, {})
        r["template_name"] = _tpl_d.get("name", "")
        sections_raw = _tpl_d.get("sections") or _tpl_d.get("sections_json", [])
        if isinstance(sections_raw, str): sections_raw = json.loads(sections_raw or "[]")
        structured = []
        for sec in sections_raw:
            sec_exp = {"title": sec["title"], "number": sec.get("number",""), "fields": []}
            for f in sec.get("fields", []):
                sec_exp["fields"].append({
                    "name": f["name"], "label": f["label"], "type": f.get("type","text"),
                    "value": form_data.get(f["name"], None)
                })
            structured.append(sec_exp)
        exports.append({
            "id": r["id"],
            "reference_number": r.get("reference_number"),
            "template_id": r.get("template_id",""),
            "template_name": r.get("template_name"),
            "status": r.get("status","?"),
            "completeness_pct": r.get("completeness_pct",0),
            "submitted_at": r.get("submitted_at"),
            "client": {"name": r.get("client_name"), "email": r.get("client_email"), "phone": r.get("client_phone")},
            "form_data_flat": form_data,
            "form_data_structured": structured,
        })
    now_str = __import__("datetime").datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    filename = f"form_submissions_export_{now_str}.json"
    return Response(
        content=json.dumps({"export_version": "1.0", "count": len(exports), "submissions": exports},
                           ensure_ascii=False, indent=2),
        media_type="application/json",
        headers={"Content-Disposition": f'attachment; filename="{filename}"'}
    )

