@app.post("/api/forms/extract-from-text")
async def api_extract_from_text(request: _Request):
    """Extract form field values from unstructured text (email, voice transcript, notes)."""
    import anthropic
    body = await request.json()
    text_input = body.get("text", "")
    template_id = body.get("template_id", "")
    source_type = body.get("source", "text")  # "text", "voice", "email"

    if not text_input.strip():
        return JSONResponse({"error": "No text provided"}, 400)

    # Load template fields
    fields_schema = []
    if template_id:
        tpl = _fs_get("form_templates", template_id)
        if tpl:
            sections = tpl.get("sections") or tpl.get("sections_json", [])
            if isinstance(sections, str): sections = json.loads(sections or "[]")
            for sec in sections:
                for f in sec.get("fields", []):
                    if isinstance(f, dict):
                        fields_schema.append({"name": f.get("name", f.get("id", "")), "label": f.get("label", ""), "type": f.get("type", "text")})

    schema_text = json.dumps(fields_schema, ensure_ascii=False) if fields_schema else "Extract all recognizable insurance claim fields"

    client = anthropic.Anthropic(api_key=os.environ.get("ANTHROPIC_API_KEY", ""))
    msg = client.messages.create(
        model="claude-sonnet-4-20250514",
        max_tokens=4096,
        messages=[{
            "role": "user",
            "content": f"""Extract insurance form field values from this unstructured {source_type}.

Text input:
\"\"\"
{text_input}
\"\"\"

Form field schema:
{schema_text}

Return ONLY valid JSON:
{{
  "extracted_data": {{"field_name": "extracted value", ...}},
  "confidence": 0.75,
  "missing_fields": ["field_name1"],
  "notes": "any observations"
}}

Match field names from the schema. Extract all identifiable values (names, dates, addresses, phone numbers, descriptions, amounts).
For yes/no fields: use "ja" or "nein". Leave missing fields in missing_fields array."""
        }]
    )
    resp_text = msg.content[0].text
    if "```json" in resp_text:
        resp_text = resp_text.split("```json")[1].split("```")[0]
    elif "```" in resp_text:
        resp_text = resp_text.split("```")[1].split("```")[0]
    try:
        result = json.loads(resp_text.strip())
    except json.JSONDecodeError:
        return JSONResponse({"error": "Failed to parse AI response", "raw": resp_text}, 422)

    # Emit knowledge hook
    try:
        extracted_count = len(result.get("extracted_data", {}))
        missing_count = len(result.get("missing_fields", []))
        confidence = result.get("confidence", 0)
        _emit_hook("text.processed", "system", "form_template", template_id, {
            "source": source_type, "template_id": template_id,
            "fields_extracted": extracted_count, "fields_missing": missing_count,
            "confidence": confidence, "text_length": len(text_input)
        }, f"AI extracted {extracted_count} fields from {source_type} (len={len(text_input)}), confidence {confidence:.0%}",
        ["smart-fill", source_type, "ai-extract"], int(confidence * 10))
    except Exception:
        pass

    return result


