# ── Engagement Tracking Endpoints ──────────────────────────────────────────
# Tracking pixel for email opens + form page view tracking

@app.get("/api/forms/track/{sub_id}/open")
async def track_email_open(sub_id: str):
    """1x1 pixel — tracks when client opens an email containing a form link."""
    from datetime import datetime as _dt
    try:
        _now = _dt.utcnow().isoformat()
        existing = _fs_get("form_submissions", sub_id)
        updates = {"last_activity_at": _now,
                   "email_open_count": (existing.get("email_open_count") or 0) + 1 if existing else 1}
        if existing and not existing.get("email_opened_at"):
            updates["email_opened_at"] = _now
        _fs_set("form_submissions", sub_id, updates, merge=True)
    except Exception:
        pass
    import base64
    _pixel = base64.b64decode(
        "iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg=="
    )
    from starlette.responses import Response
    return Response(content=_pixel, media_type="image/png",
                    headers={"Cache-Control": "no-cache, no-store, must-revalidate"})


@app.get("/api/forms/track/{sub_id}/view")
async def track_form_view(sub_id: str):
    """Called by form page JS when client opens the form link."""
    from datetime import datetime as _dt
    try:
        _now = _dt.utcnow().isoformat()
        existing = _fs_get("form_submissions", sub_id)
        updates = {"last_activity_at": _now,
                   "form_view_count": (existing.get("form_view_count") or 0) + 1 if existing else 1}
        if existing and not existing.get("form_viewed_at"):
            updates["form_viewed_at"] = _now
        _fs_set("form_submissions", sub_id, updates, merge=True)
        _audit("form.viewed", actor="client", entity_type="form_submission", entity_id=sub_id,
               details="Client opened form page")
    except Exception:
        pass
    return {"ok": True}


# ── Form Submission History API ────────────────────────────────────────────

@app.get("/api/forms/submissions/{sub_id}/history")
async def get_submission_history(sub_id: str):
    """Get the full history of a form submission — every partial save, field update, reminder."""
    history = _fs_query("form_submission_history", filters=[("submission_id", "==", sub_id)], limit=500)
    history.sort(key=lambda x: x.get("created_at", ""))
    sub = _fs_get("form_submissions", sub_id)
    return {
        "submission": sub,
        "history": history,
        "total_events": len(history)
    }


# ── CMD Commands Endpoint ──────────────────────────────────────────────────
# Angajatul trimite CMD codes prin email/chat — Alex execută și răspunde

@app.post("/api/commands/execute")
async def execute_command(request: _Request):
    """Execute a quick command from the operator.
    Body: {command: "CMD1", ref: "FRM-2026-70560"}
    Returns result as JSON — can also be emailed back.
    """
    from datetime import datetime as _dt
    import re as _cmd_re

    body = await request.json()
    raw_cmd = (body.get("command", "") or "").strip().upper()
    ref = (body.get("ref", "") or "").strip()
    reply_email = body.get("reply_to", "")

    # Normalize command: accept "CMD1", "CMD 1", "cmd1", "CMD-1" etc.
    _cmd_match = _cmd_re.match(r'CMD[\s\-]*(\d+)', raw_cmd)
    cmd = f"CMD{_cmd_match.group(1)}" if _cmd_match else raw_cmd

    result = {"command": cmd, "ref": ref, "ok": False, "message": ""}

    # Helper: find submission by ticket_code OR reference_number (Firestore)
    def _find_sub(ref_val, columns="*"):
        hits = _fs_query("form_submissions", filters=[("ticket_code", "==", ref_val)], limit=1)
        if not hits:
            hits = _fs_query("form_submissions", filters=[("reference_number", "==", ref_val)], limit=1)
        if hits:
            d = hits[0]; d["id"] = d.pop("_id"); return d
        return None

    # Keep broker DB connection for claims/policies (not migrated)

    if cmd == "CMD1" and not ref:
        result["message"] = "CMD1 benötigt eine Referenz. Beispiel: CMD1 AKT-2026-00001"
    elif cmd == "CMD1" and ref:
        # Status prüfen — check status of a specific form
        sub = _find_sub(ref)
        if sub:
            s = dict(sub)
            _fd = s.get("form_data") or {}
            if isinstance(_fd, str):
                try: _fd = json.loads(_fd)
                except: _fd = {}
            engagement = "Kein Kontakt"
            if s.get("form_viewed_at"):
                engagement = f"Formular geöffnet am {s['form_viewed_at'][:10]}"
            elif s.get("email_opened_at"):
                engagement = f"Email geöffnet am {s['email_opened_at'][:10]}"
            _tc = s.get('ticket_code') or ref
            _sn = _fd.get("schadensnummer") or _fd.get("schadennummer") or ""
            _hergang = _fd.get("unfallhergang") or _fd.get("schadenhergang") or _fd.get("damage_description") or ""
            result["ok"] = True
            result["message"] = (
                f"Status für {_tc}:\n"
                f"  Aktenzeichen: {_tc}\n"
                f"  Ref: {s.get('reference_number', ref)}\n"
                f"  Client: {s.get('client_name','?')} ({s.get('client_email','')})\n"
                f"  Kontaktperson: {_fd.get('kontaktperson','-')}\n"
                f"  Status: {s.get('status','?')}\n"
                f"  Vollständigkeit: {s.get('completeness_pct',0)}%\n"
                f"  Formular: {s.get('template_id','')}\n"
                f"  Erstellt: {(s.get('created_at',''))[:16]}\n"
                f"\n  Versicherungsdaten:\n"
                f"  Versicherer: {_fd.get('versicherer','-')}\n"
                f"  VS-Nr: {_fd.get('versicherungsschein_nr','-')}\n"
                f"  Schadennummer: {_sn or '-'}\n"
                f"  Kennzeichen: {_fd.get('vn_kennzeichen') or _fd.get('kfz_kennzeichen') or _fd.get('kennzeichen') or '-'}\n"
                f"\n  Schadendaten:\n"
                f"  Schadentag: {_fd.get('schadentag_uhrzeit','-')}\n"
                f"  Schadenort: {_fd.get('schadenort','-')}\n"
                f"  Schadenshöhe: {_fd.get('schadenshoehe','-')}\n"
                f"  Hergang: {_hergang[:200] if _hergang else '-'}\n"
                f"\n  Engagement: {engagement}\n"
                f"  Erinnerungen: {s.get('reminder_count',0) or 0}\n"
                f"  Anhänge: {len(s.get('attachments',[]))}\n"
                f"  Letzte Aktivität: {s.get('last_activity_at', 'keine') or 'keine'}"
            )
            result["data"] = s
        else:
            result["message"] = f"Formular {ref} nicht gefunden."

    elif cmd == "CMD2" and not ref:
        result["message"] = "CMD2 benötigt eine Referenz. Beispiel: CMD2 AKT-2026-00001"
    elif cmd == "CMD2" and ref:
        # Erinnerung sofort senden
        sub = _find_sub(ref)
        if sub and sub.get("client_email",""):
            _host = os.environ.get("APP_HOST", "https://alex-insurance-broker-426485075291.europe-west3.run.app")
            _url = f"{_host}/forms/{sub['template_id']}?sub={sub['id']}&client={sub['client_email']}"
            _html = f"""<div style="font-family:'Segoe UI',sans-serif;max-width:600px;margin:0 auto">
              <div style="background:linear-gradient(135deg,#f59e0b,#d97706);padding:24px;border-radius:12px 12px 0 0;text-align:center">
                <h2 style="color:white;margin:0">⏰ Erinnerung — Formular ausfüllen</h2>
              </div>
              <div style="background:#fff;padding:24px;border:1px solid #e5e7eb;border-radius:0 0 12px 12px">
                <p>{_greeting_for(sub['client_name'])}</p>
                <p>Bitte füllen Sie das ausstehende Formular aus:</p>
                <div style="text-align:center;margin:20px 0">
                  <a href="{_url}" style="background:#6366f1;color:white;padding:12px 32px;border-radius:8px;text-decoration:none;font-weight:600">Formular ausfüllen →</a>
                </div>
                <p style="font-size:12px;color:#9ca3af">Ref: {ref} — TPSH Versicherungsmakler GmbH</p>
              </div>
            </div>"""
            _send_email_html([sub.get("client_email","")], f"⏰ Erinnerung: {ref}", _html)
            result["ok"] = True
            result["message"] = f"Erinnerung gesendet an {sub['client_email']}"
            # Wiki backlink: log reminder in client's Communication History
            try:
                _rem_count = int(sub.get("reminder_count", 0) or 0) + 1
                _rem_ts = __import__("datetime").datetime.utcnow().strftime("%Y-%m-%d %H:%M")
                _client_nm = sub.get("client_name", "")
                if _client_nm:
                    _wiki_append_log(f"Client: {_client_nm}", f"Reminder #{_rem_count} sent via email (CMD2) — Ref: {ref}")
                _wiki_append_log("Activity Log", f"CMD2 Reminder sent to {_client_nm or sub.get('client_email','')} for {ref}")
            except Exception as _wiki_cmd2_err:
                _log.warning(f"Wiki CMD2 backlink failed: {_wiki_cmd2_err}")
        else:
            result["message"] = f"Formular {ref} nicht gefunden oder keine Email."

    elif cmd == "CMD3":
        # Kundenhistorie — engagement tracking für einen bestimmten Client
        # CMD3 Name/Email/AKT = vollständige Historie eines Kunden
        # CMD3 ohne ref = Fehler, ref ist erforderlich
        if not ref:
            result["ok"] = False
            result["message"] = "CMD3 benötigt einen Kundennamen, eine Email oder ein Aktenzeichen.\nBeispiel: CMD3 Hans Mueller"
        else:
            _search = ref.strip()
            _all_subs = _fs_all("form_submissions", limit=2000)
            _search_low = _search.lower()
            _client_subs = [s for s in _all_subs
                           if _search_low in (s.get("client_name") or "").lower()
                           or _search_low in (s.get("client_email") or "").lower()
                           or _search == s.get("ticket_code")
                           or _search == s.get("reference_number")]
            _client_subs.sort(key=lambda x: x.get("created_at", ""), reverse=True)
            _client_subs = _client_subs[:30]
            lines = []
            for r in _client_subs:
                r = dict(r)  # ensure dict
                _akt = r.get("ticket_code","") or r.get("reference_number","")
                _events = []
                if r.get("created_at",""): _events.append(f"Erstellt: {r['created_at'][:16]}")
                if r.get("email_opened_at",""): _events.append(f"Email gelesen: {r['email_opened_at'][:16]}")
                if r.get("form_viewed_at",""): _events.append(f"Formular geöffnet: {r['form_viewed_at'][:16]}")
                if r.get("submitted_at",""): _events.append(f"Eingereicht: {r['submitted_at'][:16]}")
                if r.get("last_activity_at",""): _events.append(f"Letzte Aktivität: {r['last_activity_at'][:16]}")
                status_emoji = {"validated":"✅","forwarded":"📤","closed":"🔒","incomplete":"⚠️","submitted":"📋","sent":"📧"}.get(r.get("status","?"),"📄")
                lines.append(f"{status_emoji} {_akt} — {r.get('client_name','?')} ({r.get('completeness_pct',r.get('completeness',0)) or 0}%) — {r.get('status','?')}")
                for ev in _events:
                    lines.append(f"   → {ev}")
                if r.get("reminder_count",0): lines.append(f"   → Erinnerungen: {r['reminder_count']}/3")
            if lines:
                result["ok"] = True
                result["message"] = f"Kundenhistorie für '{_search}' ({len(_client_subs)} Fälle):\n" + "\n".join(lines)
            else:
                result["ok"] = False
                result["message"] = f"Kein Client gefunden für '{_search}'."
            result["count"] = len(_client_subs)

    elif cmd == "CMD4" and not ref:
        result["message"] = "CMD4 benötigt eine Referenz. Beispiel: CMD4 AKT-2026-00001"
    elif cmd == "CMD4" and ref:
        # Formular erneut an Client senden
        sub = _find_sub(ref)
        if sub and sub.get("client_email",""):
            _host = os.environ.get("APP_HOST", "https://alex-insurance-broker-426485075291.europe-west3.run.app")
            _url = f"{_host}/forms/{sub['template_id']}?sub={sub['id']}&client={sub['client_email']}"
            _html = f"""<div style="font-family:'Segoe UI',sans-serif;max-width:600px;margin:0 auto">
              <div style="background:linear-gradient(135deg,#6366f1,#8b5cf6);padding:24px;border-radius:12px 12px 0 0;text-align:center">
                <h2 style="color:white;margin:0">📋 Formular — erneut gesendet</h2>
              </div>
              <div style="background:#fff;padding:24px;border:1px solid #e5e7eb;border-radius:0 0 12px 12px">
                <p>{_greeting_for(sub['client_name'])}</p>
                <p>Hier ist der Link zu Ihrem Formular:</p>
                <div style="text-align:center;margin:20px 0">
                  <a href="{_url}" style="background:#6366f1;color:white;padding:12px 32px;border-radius:8px;text-decoration:none;font-weight:600">Formular öffnen →</a>
                </div>
                <p style="font-size:12px;color:#9ca3af">Ref: {ref} — TPSH Versicherungsmakler GmbH</p>
              </div>
            </div>"""
            _send_email_html([sub.get("client_email","")], f"📋 Formular: {ref}", _html)
            result["ok"] = True
            result["message"] = f"Formular erneut gesendet an {sub['client_email']}"
            # Wiki backlink: log resend in client's Communication History
            try:
                _client_nm = sub.get("client_name", "")
                if _client_nm:
                    _wiki_append_log(f"Client: {_client_nm}", f"Form resent via email (CMD4) — Ref: {ref}")
                _wiki_append_log("Activity Log", f"CMD4 Form resent to {_client_nm or sub.get('client_email','')} for {ref}")
            except Exception as _wiki_cmd4_err:
                _log.warning(f"Wiki CMD4 backlink failed: {_wiki_cmd4_err}")
        else:
            result["message"] = f"Formular {ref} nicht gefunden oder keine Email."

    elif cmd == "CMD5" and not ref:
        result["message"] = "CMD5 benötigt eine Referenz. Beispiel: CMD5 AKT-2026-00001"
    elif cmd == "CMD5" and ref:
        # Fall abschließen — search by ticket_code OR reference_number
        _close_sub = _find_sub(ref)
        if _close_sub:
            _fs_set("form_submissions", _close_sub.get("id",""), {"status": "closed"}, merge=True)
            # Wiki backlink: log case closure in client's Communication History
            try:
                _client_nm = _close_sub.get("client_name", "")
                if _client_nm:
                    _wiki_append_log(f"Client: {_client_nm}", f"Case closed (CMD5) — Ref: {ref}")
                _wiki_append_log("Activity Log", f"CMD5 Case closed: {ref} ({_close_sub.get('client_name', '')})")
            except Exception as _wiki_cmd5_err:
                _log.warning(f"Wiki CMD5 backlink failed: {_wiki_cmd5_err}")
        result["ok"] = True
        result["message"] = f"Fall {ref} abgeschlossen."

    elif cmd == "CMD6":
        # CMD6 AKT-xxxx "Frage1" "Frage2" — Zusatzfragen zum Formular hinzufügen und erneut senden
        # CMD6 ohne ref = Tagesbericht (backward compatible)
        import re as _re6
        body_text = body.get("body_text", "") or ""
        _questions = _re6.findall(r'"([^"]+)"', body_text) if body_text else []
        if _questions and not ref:
            # Questions provided but no ref — need a ref to know which form to update
            result["ok"] = False
            result["message"] = "CMD6 mit Fragen benötigt eine Referenz (z.B. CMD6 AKT-2026-00001 \"Ihre Frage\")"
        elif ref and _questions:
            # Add questions to the submission and resend
            sub = _find_sub(ref)
            if sub and sub.get("client_email",""):
                # Store extra questions in form_data JSON
                _fd = sub.get("form_data") or {}
                if isinstance(_fd, str): _fd = json.loads(_fd or "{}")
                _existing_q = _fd.get("_extra_questions", [])
                _existing_q.extend(_questions)
                _fd["_extra_questions"] = _existing_q
                _fs_set("form_submissions", sub.get("id",""), {"form_data": _fd, "status": "sent"}, merge=True)
                # Resend form link to client
                _host = os.environ.get("APP_HOST", "https://alex-insurance-broker-426485075291.europe-west3.run.app")
                _url = f"{_host}/forms/{sub['template_id']}?sub={sub['id']}&client={sub['client_email']}"
                _q_html = "".join(f"<li style='margin:4px 0'>{q}</li>" for q in _questions)
                _resend_html = f"""<div style="font-family:'Segoe UI',sans-serif;max-width:600px;margin:0 auto">
                  <div style="background:linear-gradient(135deg,#f59e0b,#d97706);padding:24px;border-radius:12px 12px 0 0;text-align:center">
                    <h2 style="color:white;margin:0">❓ Zusätzliche Fragen zu Ihrem Formular</h2>
                  </div>
                  <div style="background:#fff;padding:24px;border:1px solid #e5e7eb;border-radius:0 0 12px 12px">
                    <p>{_greeting_for(sub['client_name'])}</p>
                    <p>Ihr Makler hat zusätzliche Fragen zu Ihrem Formular:</p>
                    <ul style="background:#fffbeb;padding:16px 16px 16px 32px;border-radius:8px;border:1px solid #fde68a;margin:16px 0">{_q_html}</ul>
                    <p>Bitte öffnen Sie Ihr Formular und ergänzen Sie die fehlenden Informationen:</p>
                    <div style="text-align:center;margin:20px 0">
                      <a href="{_url}" style="background:#f59e0b;color:white;padding:12px 32px;border-radius:8px;text-decoration:none;font-weight:600">Formular öffnen →</a>
                    </div>
                    <p style="font-size:12px;color:#9ca3af">Ref: {sub['reference_number']} — TPSH Versicherungsmakler GmbH</p>
                  </div>
                </div>"""
                _send_email_html([sub.get("client_email","")],
                    f"❓ Zusatzfragen: {sub['reference_number']}", _resend_html, auto_bcc_operator=True)
                result["ok"] = True
                result["message"] = f"{len(_questions)} Frage(n) hinzugefügt und Formular erneut an {sub['client_email']} gesendet: " + "; ".join(_questions)
                # Wiki backlink: log questions sent in client's Communication History
                try:
                    _client_nm = sub.get("client_name", "")
                    _q_summary = "; ".join(_questions[:3])
                    if _client_nm:
                        _wiki_append_log(f"Client: {_client_nm}", f"Extra questions sent via email (CMD6) — Ref: {ref} — {_q_summary}")
                    _wiki_append_log("Activity Log", f"CMD6 Questions sent to {_client_nm or sub.get('client_email','')} for {ref}: {_q_summary}")
                except Exception as _wiki_cmd6_err:
                    _log.warning(f"Wiki CMD6 backlink failed: {_wiki_cmd6_err}")
            else:
                result["message"] = f"Fall {ref} nicht gefunden oder keine Email."
        else:
            # CMD6 without ref and without questions → error
            result["ok"] = False
            result["message"] = "CMD6 benötigt eine Referenz und Fragen.\nBeispiel: CMD6 AKT-2026-00001 \"Wie hoch war die Geschwindigkeit?\" \"Gab es Zeugen?\""

    elif cmd == "CMD7":
        # Oracle Sync starten
        try:
            sync_result = await oracle_sync_from_sqlite()
            result["ok"] = True
            result["message"] = f"Oracle Sync abgeschlossen: {sync_result.get('synced', 0)} synchronisiert"
            result["data"] = sync_result
        except Exception as _e:
            result["message"] = f"Sync Fehler: {_e}"

    elif cmd == "CMD8":
        # Tagesbericht (daily report)
        try:
            report = await api_form_daily_report()
            result["ok"] = True
            result["message"] = f"Tagesbericht: {report.get('total', 0)} Formulare, {report.get('completion_rate', 0)}% Abschlussrate, {report.get('overdue', 0)} überfällig"
            result["data"] = report
        except Exception as _e:
            result["message"] = f"Fehler beim Erstellen des Berichts: {_e}"

    else:
        result["message"] = (
            "Unbekannter Befehl. Verfügbare Befehle:\n"
            "CMD1 [Ref] → Status prüfen\n"
            "CMD2 [Ref] → Erinnerung senden\n"
            "CMD3 [Name/Email] → Kundenhistorie\n"
            "CMD4 [Ref] → Formular erneut senden\n"
            "CMD5 [Ref] → Fall abschließen\n"
            "CMD6 [Ref] \"Frage\" → Zusatzfragen an Client\n"
            "CMD7 → Oracle Sync\n"
            "CMD8 → Tagesbericht"
        )

    # Only send email reply for ACTION commands (CMD2, CMD4, CMD5, CMD6, CMD7)
    # CMD1, CMD3, CMD8 are read-only — no email reply (prevents infinite loop)
    _action_cmds = {"CMD2", "CMD4", "CMD5", "CMD6", "CMD7"}
    if reply_email and result.get("ok") and cmd.upper() in _action_cmds:
        _cmd_reply_html = f"""<div style="font-family:'Segoe UI',sans-serif;max-width:600px;margin:0 auto">
          <div style="background:linear-gradient(135deg,#1e293b,#334155);padding:20px;border-radius:12px 12px 0 0">
            <h3 style="color:white;margin:0">🤖 Alex — Befehlsergebnis</h3>
          </div>
          <div style="background:#fff;padding:20px;border:1px solid #e5e7eb;border-radius:0 0 12px 12px">
            <p><strong>Befehl:</strong> {cmd} {ref}</p>
            <pre style="background:#f8fafc;padding:12px;border-radius:6px;font-size:13px;white-space:pre-wrap">{result['message']}</pre>
          </div>
        </div>"""
        _send_email_html([reply_email], f"🤖 Alex: {cmd} {ref} — Ergebnis", _cmd_reply_html)

    # Audit trail for all CMD executions
    _audit(f"cmd.{cmd.lower()}", actor=reply_email or "operator",
           entity_type="form_submission", entity_id=ref or None,
           details=f"{cmd} {ref} — {'OK' if result.get('ok') else 'FAIL'}: {result.get('message','')[:200]}")

    return result


# ── Email Inbox Polling — read CMD replies from operators ─────────────────

def _detect_claim_type(body, subject=""):
    """Detect claim type from email body/subject with weighted scoring.
    Strong signals (explicit type mentions) override weak ones (ambiguous words).
    KFZ wins ties since it's the most common case.
    """
    text = (body + " " + subject).lower()

    # STRONG KFZ signals (explicit vehicle claim language)
    kfz_strong = sum(1 for w in [
        'kfz-schaden', 'kfz schaden', 'autounfall', 'verkehrsunfall', 'auffahrunfall',
        'parkschaden', 'kaskoschaden', 'teilkasko', 'vollkasko', 'kfz-haftpflicht',
        'kfz-versicherung', 'fahrzeugschaden'
    ] if w in text)
    # WEAK KFZ signals (vehicle words that could also appear in other claims)
    kfz_weak = sum(1 for w in [
        'kfz', 'fahrzeug', 'auto', 'kennzeichen', 'fahrer', 'unfall', 'polizei-aktenzeichen'
    ] if w in text)

    # STRONG Maschinenbruch signals
    mb_strong = sum(1 for w in [
        'maschinenbruch', 'maschinenschaden', 'produktionsausfall', 'betriebsunterbrechung',
        'werkzeugmaschine', 'cnc', 'hydraulik'
    ] if w in text)
    mb_weak = sum(1 for w in ['maschine', 'anlage', 'aggregat', 'spindel', 'turbine', 'kompressor', 'generator'] if w in text)

    # STRONG Haftpflicht signals (explicit type mentions)
    hpf_strong = sum(1 for w in [
        'haftpflichtschaden', 'betriebshaftpflicht', 'privathaftpflicht',
        'mietsachschaden', 'wasserschaden', 'gebäudeschaden', 'gebaudeschaden',
        'drittschaden', 'fremdschaden'
    ] if w in text)
    hpf_weak = sum(1 for w in [
        'haftpflicht', 'sachschaden', 'personenschaden',
        'geschädigter', 'geschadigter', 'schadensersatz'
    ] if w in text)

    # Score: strong = 3 pts, weak = 1 pt
    kfz_score = kfz_strong * 3 + kfz_weak
    mb_score = mb_strong * 3 + mb_weak
    hpf_score = hpf_strong * 3 + hpf_weak

    # Need at least 3 points for non-default to win (i.e., one strong signal)
    if mb_score >= 3 and mb_score > kfz_score and mb_score >= hpf_score:
        return 'tpl-maschinenbruch'
    if hpf_score >= 3 and hpf_score > kfz_score:
        return 'tpl-haftpflicht'
    # Default to KFZ (most common)
    return 'tpl-kfz-schaden'


async def _process_openviva_email(body_text: str, sender_email: str) -> dict:
    """Parse a structured OpenVIVA email and create a pre-filled form submission.
    Expected format (key: value pairs):
        VN: Claudia Mustermann
        Adresse: Musterstr. 1
        PLZ: 82008
        Ort: Unterhaching
        Email: test@Kunde.de
        Telefon: +4988 888888
        VS-Nummer: 33-4543543-4334545
        Versicherer: Allianz
        Fahrzeug-Ident-Nr.: 9898797098709
        Baujahr: 2025
        Erstzulassung: 12.01.2026
        Formularkennung AlexAI: KFZ-ALEX-AI
    """
    import re as _re, uuid as _u, time as _ov_time_mod
    from datetime import datetime as _dt, timedelta as _td
    _ov_local_start_ts = _ov_time_mod.time()

    # Truncate at signature to avoid picking up fields from email signature
    _body_clean = body_text
    for _sig in ["Grüße", "Gruesse", "Grüsse", "Viele Grüße", "Mit freundlichen Grüßen", "Mit freundlichen", "i.A. ", "Best regards", "Kind regards", "TPSH group", "Insurance & Reinsurance Broker", "TPSH Versicherungsmakler", "Bitte berücksichtigen Sie", "From:", "Von:", "Sent:", "Gesendet:", "-----Original"]:
        _sig_pos = _body_clean.find(_sig)
        if _sig_pos > 50:  # Only if signature is not at the very start
            _body_clean = _body_clean[:_sig_pos]
            break

    # Parse key: value pairs from email body (signature-truncated).
    # Track "Geschaedigter:" / "Anspruchsteller:" block so indented sub-fields route
    # into Geschaedigter-<Key> namespace (prevents VN slot poisoning: a nested
    # "Kennzeichen: D-HW 1234" would otherwise overwrite the VN's Kennzeichen).
    _fields = {}
    _in_gesch_block = False
    for _raw_line in _body_clean.split("\n"):
        _is_indented = _raw_line.startswith(("  ", "\t"))
        line = _raw_line.strip()
        if not line:
            _in_gesch_block = False
            continue
        if ":" in line and not line.startswith(">") and not line.startswith("--"):
            _k, _v = line.split(":", 1)
            _k_s = _k.strip()
            _v = _v.strip()
            _v = _re.sub(r'<(?:https?://|mailto:|javascript:)[^>]*>', '', _v).strip()
            # Detect block header: key ending in ":" with empty value AND known block name
            _lk = _k_s.lower().rstrip(":")
            if not _v and _lk in ("geschädigter", "geschaedigter", "geschädigte person",
                                   "geschaedigte person", "anspruchsteller", "gegner"):
                _in_gesch_block = True
                continue
            # Inside block + indented → route to Geschädigter-* namespace
            if _in_gesch_block and _is_indented:
                _gk = f"Geschädigter-{_k_s}"
                if _gk not in _fields:
                    _fields[_gk] = _v
                continue
            # Non-indented line exits the block
            if _in_gesch_block and not _is_indented:
                _in_gesch_block = False
            # Top-level: first match wins (defense against duplicate keys)
            if _k_s not in _fields:
                _fields[_k_s] = _v

    # Map email fields to EXACTLY ONE template field each (no duplicates)
    _field_mapping = {
        # Identity — populates KFZ (vn_name), Haftpflicht (vn_firma_name), Maschinenbruch (owner_name, contact_name)
        "VN": ["vn_name", "vn_firma_name", "owner_name", "contact_name", "versicherungsnehmer_header"],
        "Kontaktperson": ["kontaktperson", "contact_name"],
        "Fahrzeug-Ident-Nr.": ["fahrgestellnummer"],
        "Fahrzeug-Ident-Nr": ["fahrgestellnummer"],
        "FIN": ["fahrgestellnummer"],
        "VIN": ["fahrgestellnummer"],
        "Name": ["vn_name", "vn_firma_name", "owner_name", "contact_name", "versicherungsnehmer_header"],
        "Versicherungsnehmer": ["vn_name", "vn_firma_name", "owner_name", "contact_name", "versicherungsnehmer_header"],
        "Kontaktperson": ["kontaktperson", "contact_name"],
        "Ansprechpartner": ["kontaktperson", "contact_name"],

        # Address — populates KFZ (vn_adresse), Haftpflicht (vn_strasse, vn_plz_ort)
        "Adresse": ["vn_adresse", "vn_strasse"],
        "Straße": ["vn_adresse", "vn_strasse"],
        "PLZ": ["vn_plz_ort"],
        "Ort": ["vn_plz_ort"],  # will be combined with PLZ below

        # Contact — HPF: vn_email/vn_telefon, MB: contact_phone_email/owner_phone
        "Email": ["vn_email"],
        "E-Mail": ["vn_email"],
        "Absender": ["vn_email"],
        "Telefon": ["vn_kontakt", "vn_telefon", "contact_phone_email", "owner_phone"],
        "Tel": ["vn_kontakt", "vn_telefon", "contact_phone_email", "owner_phone"],
        "Fax": ["vn_fax"],

        # Insurance — KFZ (versicherungsschein_nr), HPF (vertragsnummer), MB (versicherungsschein_nr)
        "VS-Nummer": ["versicherungsschein_nr", "vertragsnummer"],
        "VS-Nr": ["versicherungsschein_nr", "vertragsnummer"],
        "Versicherungsschein-Nr": ["versicherungsschein_nr", "vertragsnummer"],
        "Versicherungsscheinnummer": ["versicherungsschein_nr", "vertragsnummer"],
        "Vertragsnummer": ["versicherungsschein_nr", "vertragsnummer"],
        "Versicherer": ["versicherer"],
        "Versicherungsgesellschaft": ["versicherer"],
        "VG": ["versicherer"],

        # Vehicle
        "Kennzeichen": ["vn_kennzeichen"],
        "Kfz-Kennzeichen": ["vn_kennzeichen"],
        "Amtliches Kennzeichen": ["vn_kennzeichen"],
        # REGRESSION FIX: "Fahrzeug" in broker email is typically VN's OWN vehicle,
        # not Geschädigter's. Don't alias to anspruch_fabrikat (wrong-slot bug in T5).
        # Claimant vehicle comes from Polizeibericht Vision extraction (role-aware).
        "Fahrzeug": ["vn_fahrzeug"],
        "Fahrzeugtyp": ["vn_fahrzeug"],
        # Explicit claimant vehicle keys (only populate anspruch_fabrikat when broker says so)
        "Gegner-Fahrzeug": ["anspruchsteller_fahrzeug", "anspruch_fabrikat"],
        "Anspruchsteller-Fahrzeug": ["anspruchsteller_fahrzeug", "anspruch_fabrikat"],
        "Geschädigtes Fahrzeug": ["anspruchsteller_fahrzeug", "anspruch_fabrikat"],
        "Fahrzeug-Ident-Nr": ["fahrgestellnummer"],
        "Fahrzeug-Ident-Nr.": ["fahrgestellnummer"],
        "Fahrgestellnr": ["fahrgestellnummer"],
        "Fahrgestellnr.": ["fahrgestellnummer"],
        "Fahrgestellnummer": ["fahrgestellnummer"],
        "FIN": ["fahrgestellnummer"],
        "VIN": ["fahrgestellnummer"],
        "Baujahr": ["baujahr", "serie_produs"],  # covers both KFZ and MB
        "Erstzulassung": ["erstzulassung"],
        "Fahrer": ["fahrer"],
        "Halter": ["vn_name"],
        "Fahrzeughalter": ["vn_name"],
        "Motorleistung": ["motorleistung"],
        "Kraftstoff": ["kraftstoff"],
        "Getriebe": ["getriebe"],
        "Fahrzeugkategorie": ["fahrzeugkategorie"],

        # Damage — populate across templates: KFZ + HPF (schadentag_uhrzeit), MB (schadensdatum, schadensort)
        "Schadennummer": ["schadensnummer", "vorgangsnummer", "dosar_nr_client"],
        "Schadennr": ["schadensnummer", "vorgangsnummer", "dosar_nr_client"],
        "Schadensnummer": ["schadensnummer", "vorgangsnummer", "dosar_nr_client"],
        "SN": ["schadensnummer", "vorgangsnummer", "dosar_nr_client"],
        "Schadenfall-Nr": ["schadensnummer", "vorgangsnummer", "dosar_nr_client"],
        "Schadenfall-Nr.": ["schadensnummer", "vorgangsnummer", "dosar_nr_client"],
        "Unser Zeichen": ["schadensnummer", "vorgangsnummer", "dosar_nr_client"],
        "Schadendatum": ["schadentag_uhrzeit", "schadensdatum"],
        "Schadentag": ["schadentag_uhrzeit", "schadensdatum"],
        "Schadensdatum": ["schadentag_uhrzeit", "schadensdatum"],
        "Unfall-Uhrzeit": ["schadentag_uhrzeit", "schadensdatum"],
        "Unfallzeit": ["schadentag_uhrzeit", "schadensdatum"],
        "Unfalldatum": ["schadentag_uhrzeit", "schadensdatum"],
        "Schadenort": ["schadenort", "schadensort"],
        "Schadensort": ["schadenort", "schadensort"],
        "Unfallort": ["schadenort", "schadensort"],
        # Damage amount — KFZ (anspruch_schadenshoehe), HPF (schadenhoehe_ansprueche)
        # kasko_schadenshoehe only via explicit Kasko keys below
        "Schadenshöhe": ["schadenshoehe", "anspruch_schadenshoehe", "schadenhoehe_ansprueche"],
        "Schadenshoehe": ["schadenshoehe", "anspruch_schadenshoehe", "schadenhoehe_ansprueche"],
        "Schadenhöhe": ["schadenshoehe", "anspruch_schadenshoehe", "schadenhoehe_ansprueche"],
        "Schadenhoehe": ["schadenshoehe", "anspruch_schadenshoehe", "schadenhoehe_ansprueche"],
        "Schadenhöhe EUR": ["schadenshoehe", "anspruch_schadenshoehe", "schadenhoehe_ansprueche"],
        "Geschätzte Schadenshöhe": ["schadenshoehe", "anspruch_schadenshoehe", "schadenhoehe_ansprueche"],
        "Geschätzter Schaden": ["schadenshoehe", "anspruch_schadenshoehe", "schadenhoehe_ansprueche"],
        # Explicit Kasko keys (only populate kasko_schadenshoehe when broker says so)
        "Kasko-Schadenshöhe": ["schadenshoehe", "kasko_schadenshoehe"],
        "Kaskoschaden": ["schadenshoehe", "kasko_schadenshoehe"],
        "Selbstbeteiligung": ["selbstbeteiligung"],
        "SB": ["selbstbeteiligung"],
        "Deckung": ["deckung"],
        "Versicherungsklasse": ["versicherungsklasse"],

        # Damage details — KFZ (unfallhergang), HPF (schadenhergang), MB (descriere_dauna)
        "Schadenhergang": ["unfallhergang", "schadenhergang", "descriere_dauna"],
        "Unfallhergang": ["unfallhergang", "schadenhergang", "descriere_dauna"],
        "Unfallbeschreibung": ["unfallhergang", "schadenhergang", "descriere_dauna"],
        "Hergang": ["unfallhergang", "schadenhergang", "descriere_dauna"],
        "Beschreibung": ["unfallhergang", "schadenhergang", "descriere_dauna"],

        # Third party — KFZ (anspruch_name), HPF (gesch_firma_name + geschaedigter in sec 3)
        "Geschädigter": ["anspruchsteller_name", "anspruch_name", "gesch_firma_name", "geschaedigter"],
        "Geschadigter": ["anspruchsteller_name", "anspruch_name", "gesch_firma_name", "geschaedigter"],
        "Beschädigter": ["anspruchsteller_name", "anspruch_name", "gesch_firma_name", "geschaedigter"],
        "Anspruchsteller": ["anspruchsteller_name", "anspruch_name", "gesch_firma_name", "geschaedigter"],
        "Gegnerisches Kennzeichen": ["schadensbeschreibung_gegner"],

        # Police
        "Polizei-Aktenzeichen": ["polizei_aktenzeichen"],
        "Aktenzeichen": ["polizei_aktenzeichen"],
        "Polizei": ["polizei_dienststelle"],

        # Machine specific — MB (producator, catalog_position, serie_produs)
        "Maschinentyp": ["machine_type", "catalog_position", "piese_avariate"],
        "Hersteller": ["machine_manufacturer", "producator"],
        "Fabrikat": ["machine_manufacturer", "producator"],
        "Seriennummer": ["serie_produs"],
        "Maschine": ["machine_type", "catalog_position", "piese_avariate"],
        "Fabrikationsnummer": ["serie_produs"],
        "Fabr-Nr": ["serie_produs"],
        "Fabriknummer": ["serie_produs"],
        "Beschädigte Teile": ["piese_avariate"],
        "Teile zu ersetzen": ["piese_inlocuit"],
        "Ersatzteile": ["piese_inlocuit"],
        "Garantie abgelaufen": ["garantie_expirata"],
        "Position Verzeichnis": ["catalog_position"],
        "Servicemitarbeiter": ["contact_name"],
        "Eigentümer": ["owner_name"],
        "Eigentuemer": ["owner_name"],
        # Haftpflicht specific
        "Art der Haftpflicht": ["haftpflicht_art"],
        "Haftpflicht-Art": ["haftpflicht_art"],
        "Was wurde beschädigt": ["was_beschaedigt"],
        "Beschädigte Sache": ["was_beschaedigt"],
    }

    form_data = {}
    for email_key, form_keys in _field_mapping.items():
        if email_key in _fields and _fields[email_key]:
            for fk in form_keys:
                # Don't overwrite an existing populated field with the same target key
                # (e.g., Schadendatum → schadentag_uhrzeit should not be overridden by Unfall-Uhrzeit)
                if fk in form_data and form_data[fk]:
                    continue
                form_data[fk] = _fields[email_key]
    # Compose vn_kontakt from telefon + email (always, when both exist — even if _field_mapping already set one part)
    _vk_tel = _fields.get("Telefon","") or _fields.get("Tel","") or form_data.get("vn_telefon","")
    _vk_email = _fields.get("Email","") or _fields.get("E-Mail","") or form_data.get("vn_email","")
    _vk_parts = [p for p in (_vk_tel, _vk_email) if p]
    if len(_vk_parts) >= 2:
        form_data["vn_kontakt"] = " / ".join(_vk_parts)
    elif _vk_parts and not form_data.get("vn_kontakt"):
        form_data["vn_kontakt"] = _vk_parts[0]
    # Combine PLZ + Ort into vn_plz_ort if both exist
    _plz = _fields.get("PLZ", "")
    _ort = _fields.get("Ort", "")
    if _plz and _ort:
        form_data["vn_plz_ort"] = f"{_plz} {_ort}"
    # Combine Adresse + PLZ + Ort for full address field
    _addr = _fields.get("Adresse", "") or _fields.get("Straße", "")
    if _addr and _plz and _ort:
        form_data["vn_adresse"] = f"{_addr}, {_plz} {_ort}"
    # Parse Geschädigter block — extract sub-fields (name, strasse, plz_ort, telefon, email, kennzeichen, fahrzeug).
    # Broker emails format as indented block:
    #   Geschaedigter:
    #     Name: Hans Wagner
    #     Strasse: Hauptstrasse 5
    #     PLZ-Ort: 40210 Düsseldorf
    #     Telefon: +49 211 5555100
    #     Email: hw@example.de
    #     Kennzeichen: D-HW 1234
    #     Fahrzeug: VW Passat B8
    # The block-aware body parser routes indented keys into Geschädigter-<Key> namespace.
    # Always run (regardless of whether Geschädigter-Name is already populated in form_data),
    # because Name may arrive via Geschädigter-Name alone without a top-level Geschädigter key.
    _gesch_subkey_map = [
        ("Geschädigter-Name", ["anspruchsteller_name", "anspruch_name", "gesch_firma_name", "geschaedigter"]),
        ("Geschädigter-Adresse", ["anspruch_strasse", "gesch_strasse"]),
        ("Geschädigter-Straße", ["anspruch_strasse", "gesch_strasse"]),
        ("Geschädigter-Strasse", ["anspruch_strasse", "gesch_strasse"]),
        ("Geschädigter-PLZ", ["anspruch_plz_ort", "gesch_plz_ort"]),
        ("Geschädigter-Ort", ["anspruch_plz_ort", "gesch_plz_ort"]),
        ("Geschädigter-PLZ-Ort", ["anspruch_plz_ort", "gesch_plz_ort"]),
        ("Geschädigter-Telefon", ["anspruch_telefon", "gesch_telefon"]),
        ("Geschädigter-Tel", ["anspruch_telefon", "gesch_telefon"]),
        ("Geschädigter-Email", ["anspruch_email", "gesch_email"]),
        ("Geschädigter-E-Mail", ["anspruch_email", "gesch_email"]),
        ("Geschädigter-Kennzeichen", ["anspruch_kennzeichen"]),
        ("Geschädigter-Fahrzeug", ["anspruch_fabrikat", "anspruchsteller_fahrzeug"]),
    ]
    for _suffix_key, _target_keys in _gesch_subkey_map:
        if _fields.get(_suffix_key):
            for _tk in _target_keys:
                if not form_data.get(_tk):
                    form_data[_tk] = _fields[_suffix_key]
    _gesch_name = form_data.get("anspruchsteller_name") or form_data.get("gesch_firma_name") or form_data.get("anspruch_name") or ""
    if _gesch_name:
        # Also parse inline Geschädigter "Name, Str. 5, 12345 Ort" comma-separated
        if "," in _gesch_name and not form_data.get("anspruch_strasse") and not form_data.get("gesch_strasse"):
            _parts = [p.strip() for p in _gesch_name.split(",")]
            if len(_parts) >= 3:
                form_data["anspruchsteller_name"] = _parts[0]
                form_data["anspruch_name"] = _parts[0]
                form_data["gesch_firma_name"] = _parts[0]
                form_data["geschaedigter"] = _parts[0]
                form_data["anspruch_strasse"] = _parts[1]
                form_data["gesch_strasse"] = _parts[1]
                form_data["anspruch_plz_ort"] = _parts[2]
                form_data["gesch_plz_ort"] = _parts[2]

    # Combine date + time into schadentag_uhrzeit if both present
    _date_val = _fields.get("Schadendatum", "") or _fields.get("Schadentag", "") or _fields.get("Schadensdatum", "") or _fields.get("Unfalldatum", "")
    _time_val = _fields.get("Unfall-Uhrzeit", "") or _fields.get("Unfallzeit", "") or _fields.get("Uhrzeit", "")
    if _date_val and _time_val:
        form_data["schadentag_uhrzeit"] = f"{_date_val} {_time_val}".strip()
    elif _date_val and not form_data.get("schadentag_uhrzeit"):
        form_data["schadentag_uhrzeit"] = _date_val
    elif _time_val and not form_data.get("schadentag_uhrzeit"):
        form_data["schadentag_uhrzeit"] = _time_val

    # Extract freetext paragraphs for accident description (lines without key: pattern)
    if not form_data.get("unfallhergang"):
        _freetext_lines = []
        _in_freetext = False
        for line in _body_clean.split("\n"):
            _stripped = line.strip()
            if not _stripped or _stripped.startswith(">") or _stripped.startswith("--"):
                if _in_freetext and _freetext_lines:
                    _in_freetext = False
                continue
            # Lines without ":" pattern and longer than 40 chars are likely freetext descriptions
            if ":" not in _stripped and len(_stripped) > 40:
                _in_freetext = True
                _freetext_lines.append(_stripped)
            elif _in_freetext and ":" not in _stripped:
                _freetext_lines.append(_stripped)
            else:
                if _in_freetext and _freetext_lines:
                    _in_freetext = False
        if _freetext_lines:
            form_data["unfallhergang"] = " ".join(_freetext_lines)
    # Alias: many templates use "hergang" as shorter field name for accident/damage description
    if not form_data.get("hergang"):
        _hg_src = form_data.get("unfallhergang") or form_data.get("schadenhergang") or form_data.get("descriere_dauna") or ""
        if _hg_src:
            form_data["hergang"] = _hg_src
    # Alias: schadenhergang ← unfallhergang (and vice versa) for templates using either name
    if not form_data.get("schadenhergang") and form_data.get("unfallhergang"):
        form_data["schadenhergang"] = form_data["unfallhergang"]
    if not form_data.get("unfallhergang") and form_data.get("schadenhergang"):
        form_data["unfallhergang"] = form_data["schadenhergang"]
    if not form_data.get("descriere_dauna") and form_data.get("unfallhergang"):
        form_data["descriere_dauna"] = form_data["unfallhergang"]

    # === NARRATIVE ENRICHMENT — full-sentence German when original is thin (G2 verb-forms) ===
    _n_date = form_data.get("schadentag_uhrzeit") or form_data.get("schadensdatum") or ""
    _n_ort = form_data.get("schadenort") or form_data.get("schadensort") or ""
    _n_sum_raw = form_data.get("schadenshoehe") or form_data.get("anspruch_schadenshoehe") or ""
    # Format EUR with thousand-separator for narrative (before composition)
    _n_sum_clean = str(_n_sum_raw).replace(".","").replace(",","").replace(" EUR","").replace(" ","").strip()
    if _n_sum_clean.isdigit() and len(_n_sum_clean) >= 4:
        _n_sum = format(int(_n_sum_clean), ",").replace(",", ".")
    else:
        _n_sum = _n_sum_raw
    # Verb-form map — covers broker-common damage phrases. Substring-match so "Hydraulik defekt" maps via "hydraulik".
    _noun_to_clause = {
        "kollision": "ereignete sich eine Kollision",
        "auffahrunfall": "ereignete sich ein Auffahrunfall",
        "parkschaden": "entstand ein Parkschaden",
        "wasserschaden": "entstand ein Wasserschaden",
        "waschmaschine": "entstand ein Wasserschaden durch eine defekte Waschmaschine",
        "wasserleitung": "entstand ein Wasserschaden durch eine geplatzte Wasserleitung",
        "rohrbruch": "entstand ein Wasserschaden durch Rohrbruch",
        "hydraulik": "trat ein Hydraulikschaden auf",
        "spindel": "trat ein Spindeldefekt auf",
        "motor": "trat ein Motorschaden auf",
        "pumpe": "trat ein Pumpendefekt auf",
        "getriebe": "trat ein Getriebeschaden auf",
        "elektronik": "trat ein elektronischer Defekt auf",
        "steuerung": "trat ein Steuerungsausfall auf",
        "steuerungsausfall": "trat ein Steuerungsausfall auf",
        "sensor": "trat ein Sensordefekt auf",
        "lager": "trat ein Lagerschaden auf",
        "welle": "trat ein Wellenschaden auf",
        "ausfall": "trat ein Schadenereignis durch Ausfall auf",
        "stromausfall": "trat ein Schaden durch Stromausfall auf",
        "kurzschluss": "entstand ein Schaden durch Kurzschluss",
        "defekt": "trat ein technischer Defekt auf",
        "bruch": "ereignete sich ein Bruchschaden",
        "maschinenbruch": "ereignete sich ein Maschinenbruchschaden",
        "toner": "entstand ein Sachschaden durch auslaufenden Toner",
        "brand": "ereignete sich ein Brandschaden",
        "feuer": "ereignete sich ein Brandschaden",
        "diebstahl": "ereignete sich ein Diebstahl",
        "vandalismus": "ereignete sich ein Sachschaden durch Vandalismus",
        "glasbruch": "entstand ein Glasbruchschaden",
        "sturm": "trat ein Sturmschaden auf",
        "hagel": "entstand ein Hagelschaden",
        "parkett": "entstand ein Sachschaden am Parkettboden",
        "teppich": "entstand ein Sachschaden am Teppichboden",
        "decke": "entstand ein Sachschaden an der Decke",
    }
    _enriched_narrative = None
    for _narr_key in ("unfallhergang","schadenhergang"):
        _orig = (form_data.get(_narr_key,"") or "").strip()
        if _orig and len(_orig) < 80:
            if _enriched_narrative is None:
                _core = _orig.rstrip(".").strip()
                _core_low = _core.lower()
                # First try exact first-word match, then substring on any map key
                _clause = None
                _words = _core_low.split()
                if _words:
                    _clause = _noun_to_clause.get(_words[0])
                if not _clause:
                    for _k, _v in _noun_to_clause.items():
                        if _k in _core_low:
                            _clause = _v
                            break
                if not _clause:
                    # Longer source or uncovered noun — use as-is with proper sentence wrapping
                    _clause = f"ereignete sich folgender Schaden: {_core}"
                _parts = []
                if _n_date:
                    _parts.append(f"Am {_n_date}")
                if _n_ort:
                    _parts.append(f"in {_n_ort}" if _n_date else f"In {_n_ort}")
                if _clause:
                    # Verb-form clause — flows grammatically
                    _parts.append(_clause + ".")
                else:
                    # Longer source — use original with slight reformat
                    _parts.append(f"ereignete sich folgender Schaden: {_core}.")
                if _n_sum:
                    _parts.append(f"Die Schadenshoehe wird auf {_n_sum} EUR geschaetzt.")
                _enriched_narrative = " ".join(_parts).strip()
            form_data[_narr_key] = _enriched_narrative
    # G1: Canonical narrative — write once to descriere_dauna, cross-ref for hergang/was_beschaedigt/etc.
    if _enriched_narrative:
        if not (form_data.get("descriere_dauna","") or "").strip() or len((form_data.get("descriere_dauna","") or "").strip()) < 60:
            form_data["descriere_dauna"] = _enriched_narrative
        # hergang gets cross-ref (avoids JSON-level duplication) — most templates don't render "hergang" anyway
        if not (form_data.get("hergang","") or "").strip() or len((form_data.get("hergang","") or "").strip()) < 60:
            form_data["hergang"] = "(siehe Schadenhergang)"
    # P2+P4: LLM polish — trigger on thin, generic, OR auto-constructed template patterns
    try:
        _narr_final = form_data.get("unfallhergang","") or form_data.get("schadenhergang","")
        # Detect ALL template-built patterns (ereignete sich, entstand ein, trat ein, Am X in Y)
        _is_template_built = _narr_final and any(p in _narr_final for p in (
            "entstand ein Schaden (", "folgender Schaden:", "ereignete sich",
            "entstand ein", "trat ein", "Die Schadenshoehe wird auf"
        ))
        if _narr_final and (_is_template_built or len(_narr_final) < 120) and os.environ.get("ANTHROPIC_API_KEY"):
            import anthropic as _anthropic_polish
            _polish_client = _anthropic_polish.Anthropic(api_key=os.environ["ANTHROPIC_API_KEY"])
            _ctx_parts = []
            if _n_date: _ctx_parts.append(f"Datum: {_n_date}")
            if _n_ort: _ctx_parts.append(f"Ort: {_n_ort}")
            if _n_sum: _ctx_parts.append(f"Schadenshoehe: {_n_sum} EUR")
            if form_data.get("vn_name"): _ctx_parts.append(f"VN: {form_data['vn_name']}")
            if form_data.get("fahrzeug"): _ctx_parts.append(f"Fahrzeug: {form_data['fahrzeug']}")
            if form_data.get("machine_type"): _ctx_parts.append(f"Maschine: {form_data['machine_type']}")
            _ctx = ", ".join(_ctx_parts)
            _prompt = f"""Formuliere eine professionelle 3-4 Satz Schadenschilderung auf Deutsch fuer eine Versicherungsmeldung.
Ausgangspunkt (moeglicherweise knapp): "{_narr_final}"
Kontext: {_ctx}
Regeln: 
- 3-4 Saetze (NICHT weniger) — strukturiert in: 1) Datum+Ort, 2) Schadenereignis, 3) Schaden/Betrag, 4) naechste Schritte/Nachfolgeaufgaben
- keine Spekulation, keine Erfindungen, nur faktenbasiert
- wenn Input zu vage, schreibe neutral-sachlich und fuege einen Abschluss-Satz hinzu ("Eine detaillierte Schadenaufnahme folgt.")
- professionelle Versicherungs-Terminologie
Antworte NUR mit der fertigen Schadenschilderung, ohne Anfuehrungszeichen, ohne Meta-Kommentare."""
            _polished = _polish_client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=300,
                temperature=0,
                messages=[{"role":"user","content":_prompt}]
            ).content[0].text.strip()
            if _polished and len(_polished) > len(_narr_final) and len(_polished) < 500:
                form_data["unfallhergang"] = _polished
                form_data["schadenhergang"] = _polished
                form_data["descriere_dauna"] = _polished
    except Exception as _llm_err:
        _log.debug(f"LLM narrative polish skipped: {_llm_err}")

    # === HPF TEMPLATE DEFAULTS & ALIASES (section 0, 2, 3, 4, 8) ===
    # Determine context: populate even if not strictly in HPF — harmless if field unused by template
    # Section 0 Allgemeine Vertragsdaten
    _vn_lower_check = (form_data.get("vn_name","") + " " + form_data.get("vn_firma_name","")).lower()
    # Extended company suffixes + German-specific forms
    _vn_is_company = any(s in _vn_lower_check for s in (
        "gmbh","kg","ag","e.k.","ek ","ug","ohg","gbr","se","sarl","service","gewerbe",
        "eg","eg.","e.g.","e. g.","genossenschaft","stiftung","verein","kommanditgesellschaft",
        "werke","werk","industrie","logistik","spedition","transport","autohaus","taxi",
        "verwaltung","holding","group","hotel","gastro","bau","bauunternehmen"
    ))
    if not form_data.get("haftpflicht_art"):
        form_data["haftpflicht_art"] = "Betriebs-Haftpflicht" if _vn_is_company else "Privat-Haftpflicht"
    # G4: If VN is a private person, vn_firma_name should be "Privatperson" (not the person's name)
    if not _vn_is_company and form_data.get("vn_firma_name") and form_data.get("vn_firma_name") == form_data.get("vn_name",""):
        form_data["vn_firma_name"] = "Privatperson"
    # Section 2 Geschädigte: ensure gesch_firma_name ← anspruchsteller/anspruch_name
    if not form_data.get("gesch_firma_name"):
        form_data["gesch_firma_name"] = form_data.get("anspruchsteller_name") or form_data.get("anspruch_name") or form_data.get("geschaedigter","")
    # Blocker 2: nachgereicht fallback for HPF required Geschädigter fields when STILL empty
    if not form_data.get("gesch_firma_name"):
        form_data["gesch_firma_name"] = "Angaben zum Geschaedigten werden nachgereicht"
    # Section 3.1 geschaedigter (required * on HPF)
    if not form_data.get("geschaedigter"):
        form_data["geschaedigter"] = form_data.get("gesch_firma_name") or form_data.get("anspruch_name","") or "Angaben werden nachgereicht"
    # Section 3.4 schaden_verursacher (required *) — default VN verursacht
    if not form_data.get("schaden_verursacher"):
        form_data["schaden_verursacher"] = form_data.get("vn_firma_name") or form_data.get("vn_name","") or "Versicherungsnehmer"
    # Section 4.1 Sachschäden — only populate from SPECIFIC sources (piese_avariate),
    # never echo narrative verbatim — a broker needs actual damaged-object list, not accident description
    if not form_data.get("was_beschaedigt"):
        _wb_specific = form_data.get("piese_avariate","")
        if _wb_specific and _wb_specific != form_data.get("unfallhergang","") and _wb_specific != form_data.get("schadenhergang",""):
            form_data["was_beschaedigt"] = _wb_specific
        else:
            # Cross-reference instead of echo: maps to required starred field without duplicating content
            form_data["was_beschaedigt"] = "Siehe Schadenhergang in Abschnitt 7"
    # German thousand-separator + EUR formatting (16898 → "16.898 EUR")
    def _fmt_eur(v):
        s = str(v or "").strip()
        if not s: return s
        # Already formatted
        if "EUR" in s or "€" in s: return s
        # Clean up possible decimal separator confusion
        _n = s.replace(" ","").replace(".","").replace(",","")
        if _n.isdigit() and len(_n) >= 4:
            # Add German thousand separator (.) and EUR suffix
            _formatted = format(int(_n), ",").replace(",", ".")
            return f"{_formatted} EUR"
        elif _n.isdigit():
            return f"{s} EUR"
        return s
    for _mk in ("schadenhoehe_ansprueche","schadenshoehe","anspruch_schadenshoehe","schadenhoehe_ansprueche"):
        if not form_data.get(_mk):
            # Copy from first available source
            _src = form_data.get("schadenshoehe") or form_data.get("anspruch_schadenshoehe","")
            if _src: form_data[_mk] = _src
        if form_data.get(_mk):
            form_data[_mk] = _fmt_eur(form_data[_mk])
    # Section 8 ort_datum (required * both HPF and KFZ)
    if not form_data.get("ort_datum"):
        import datetime as _od_dt
        _ort_city = (form_data.get("vn_plz_ort","").split(" ")[-1] if form_data.get("vn_plz_ort") else "") or "Berlin"
        form_data["ort_datum"] = f"{_ort_city}, {_od_dt.datetime.utcnow().strftime('%d.%m.%Y')}"

    # === KFZ TEMPLATE DEFAULTS (section 3 Fahrer, section 11 ort_datum) ===
    # Section 3.1 fahrt_zweck (required *)
    if not form_data.get("fahrt_zweck"):
        _vn_lower = (form_data.get("vn_name","") + " " + form_data.get("vn_firma_name","")).lower()
        form_data["fahrt_zweck"] = "Dienstlich" if any(s in _vn_lower for s in ("gmbh","kg","ag","e.k.","ug","spedition","taxi","service","gewerbe")) else "Privat"
    # Section 3.2 fahrer_name — default to VN ONLY if VN is a natural person (not company)
    # Companies can't hold Führerschein; mark as "nachzureichen" to avoid legal incoherence
    if not form_data.get("fahrer_name"):
        _vn_combined = (form_data.get("vn_name","") + " " + form_data.get("vn_firma_name","")).lower()
        _is_company = any(s in _vn_combined for s in ("gmbh","kg","ag","e.k.","ek","ug","ohg","gbr","se","sarl"))
        if _is_company:
            form_data["fahrer_name"] = "Fahrer wird nachgereicht"
            _co_name = form_data.get('vn_firma_name') or form_data.get('vn_name','')
            if _co_name == "Privatperson":
                _co_name = form_data.get('vn_name','')
            form_data["fahrer_anschrift"] = f"c/o {_co_name}"
            form_data["fahrer_kontakt"] = "Kontaktdaten werden mit Fahrer nachgereicht"
        else:
            form_data["fahrer_name"] = form_data.get("vn_name","")
            if not form_data.get("fahrer_anschrift"):
                form_data["fahrer_anschrift"] = form_data.get("vn_adresse","") or form_data.get("vn_strasse","")
            if not form_data.get("fahrer_kontakt"):
                form_data["fahrer_kontakt"] = form_data.get("vn_kontakt","")
    # Section 3.3 fahrerlaubnis — "Ja, wird bestätigt" if Fahrer is natural person, otherwise "zu klaeren"
    if not form_data.get("fahrerlaubnis"):
        if form_data.get("fahrer_name","").startswith("Fahrer wird"):
            form_data["fahrerlaubnis"] = "Wird mit Fahrer bestaetigt"
        else:
            form_data["fahrerlaubnis"] = "Ja"
    # Section 4 polizei_aufnahme — derive from polizei_aktenzeichen presence
    if not form_data.get("polizei_aufnahme") and form_data.get("polizei_aktenzeichen"):
        form_data["polizei_aufnahme"] = "Ja"

    # === MB TEMPLATE DEFAULTS (section 4, 5, 7b) ===
    # Section 4.3 serie_produs "Baujahr / Fabr.-Nr." — ALWAYS combine both if both exist
    _sp_cur = (form_data.get("serie_produs","") or "").strip()
    _sp_fin = (form_data.get("fahrgestellnummer","") or form_data.get("fabrikationsnummer","") or _fields.get("Fabrikationsnummer","") or _fields.get("Fabrikations-Nr","")).strip()
    _sp_by = (form_data.get("baujahr","") or _fields.get("Baujahr","")).strip()
    # Recompose if current value is just a 4-digit year (likely set from Baujahr alone) OR empty
    if not _sp_cur or (_sp_cur.isdigit() and len(_sp_cur)==4):
        if _sp_fin and _sp_by:
            form_data["serie_produs"] = f"{_sp_by} / {_sp_fin}"
        elif _sp_fin:
            form_data["serie_produs"] = _sp_fin
        elif _sp_by:
            form_data["serie_produs"] = f"Baujahr: {_sp_by}"
    # Section 5 garantie_expirata — default Nein (unknown) unless baujahr > 3 yrs old
    if not form_data.get("garantie_expirata"):
        _bj = form_data.get("baujahr","") or form_data.get("erstzulassung","")
        _year_str = str(_bj)[:4] if _bj else ""
        try:
            import datetime as _bj_dt
            if _year_str.isdigit() and (_bj_dt.datetime.utcnow().year - int(_year_str)) > 3:
                form_data["garantie_expirata"] = "Ja"
            else:
                form_data["garantie_expirata"] = "Nein"
        except Exception:
            form_data["garantie_expirata"] = "Nein"
    # Section 7a piese_avariate — if just machine name, append specificity placeholder
    if form_data.get("piese_avariate"):
        _pav = form_data["piese_avariate"].strip()
        _mt = (form_data.get("machine_type","") or form_data.get("catalog_position","")).strip()
        if _pav == _mt or _pav in _mt or _mt in _pav:
            form_data["piese_avariate"] = f"{_mt} (detaillierte Teileliste folgt nach Befundaufnahme)"
    # Section 7b piese_inlocuit — cross-reference to 7a instead of separate deferral (G6)
    if not form_data.get("piese_inlocuit"):
        _pav = (form_data.get("piese_avariate","") or "").strip()
        if _pav and ("," in _pav or ";" in _pav or "und" in _pav.lower()) and "Teileliste folgt" not in _pav:
            form_data["piese_inlocuit"] = _pav
        else:
            form_data["piese_inlocuit"] = "(siehe Abschnitt 7a)"
    # Section 1.2 / 3.2 contact_phone_email / owner_phone
    if not form_data.get("contact_phone_email"):
        form_data["contact_phone_email"] = form_data.get("vn_kontakt","")
    if not form_data.get("owner_phone"):
        form_data["owner_phone"] = form_data.get("vn_kontakt","")

    # Also try common contact field names (check multiple variants)
    client_name = (form_data.get("vn_name", "")
                   or _fields.get("VN", "")
                   or _fields.get("Versicherungsnehmer", "")
                   or _fields.get("Name", ""))
    if not client_name:
        # Try to extract from email subject (pattern: "Schadenfall - ClientName - ...")
        _subj_text = _fields.get("Betreff", "")
        if _subj_text:
            _subj_match = _re.search(r'Schadenfall\s*[-\u2013\u2014]\s*(.+?)(?:\s*[-\u2013\u2014]|$)', _subj_text)
            if _subj_match:
                client_name = _subj_match.group(1).strip()
    if not client_name:
        # Fallback to sender email display name or generic
        if sender_email and "@" in sender_email:
            _local = sender_email.split("@")[0].replace(".", " ").replace("_", " ").title()
            client_name = _local if len(_local) > 2 else "Unbekannter Kunde"
        else:
            client_name = "Unbekannter Kunde"
    client_email = _fields.get("Email", "") or _fields.get("E-Mail", "") or _fields.get("Absender", "")
    client_phone = _fields.get("Telefon", "") or _fields.get("Tel", "")
    kontaktperson = _fields.get("Ansprechpartner", "") or _fields.get("Kontaktperson", "") or form_data.get("kontaktperson", "")

    # Detect template from Formularkennung OR email body content
    formular_kennung = _fields.get("Formularkennung AlexAI", "").strip()

    # Map common kennung values to template IDs
    _kennung_map = {
        "KFZ-ALEX-AI": "tpl-kfz-schaden",
        "KFZ": "tpl-kfz-schaden",
        "HAFTPFLICHT-ALEX-AI": "tpl-haftpflicht",
        "HAFTPFLICHT": "tpl-haftpflicht",
        "MASCHINE-ALEX-AI": "tpl-maschinenbruch",
        "MASCHINENBRUCH-ALEX-AI": "tpl-maschinenbruch",
        "MASCHINENBRUCH": "tpl-maschinenbruch",
    }
    _mapped_tpl_id = _kennung_map.get(formular_kennung.upper(), None) if formular_kennung else None

    # ALWAYS run body detection — override generic KFZ-ALEX-AI if body clearly indicates another type
    _body_detected = _detect_claim_type(body_text, _fields.get("Betreff", ""))
    if not _mapped_tpl_id:
        _mapped_tpl_id = _body_detected
    elif _mapped_tpl_id == "tpl-kfz-schaden" and _body_detected != "tpl-kfz-schaden":
        # Body says Haftpflicht/Maschinenbruch but kennung said KFZ — body wins
        _mapped_tpl_id = _body_detected
        _log.info(f"Template override: kennung said KFZ but body detected {_body_detected}")

    tpl = None
    if _mapped_tpl_id:
        _tpl_d = _fs_get("form_templates", _mapped_tpl_id)
        if _tpl_d:
            tpl = {"id": _mapped_tpl_id, "name": _tpl_d.get("name", ""),
                   "sections": _tpl_d.get("sections") or _tpl_d.get("sections_json") or []}
    if not tpl:
        # Try fuzzy match from all templates
        _all_tpls = _fs_all("form_templates", limit=200)
        _fk = (formular_kennung or _mapped_tpl_id or "kfz").lower()
        for _t in _all_tpls:
            _t["id"] = _t.pop("_id")
            if _fk in _t["id"].lower() or _fk in (_t.get("name") or "").lower():
                tpl = _t; break
        if not tpl:
            for _t in _all_tpls:
                if "kfz" in _t.get("id", "").lower():
                    tpl = _t; break
        if not tpl:
            for _t in _all_tpls:
                if _t.get("status") == "published":
                    tpl = _t; break
    if not tpl:
        return {"ok": False, "message": "No matching form template found"}

    template_id = tpl["id"]
    template_name = tpl.get("name", "")

    # Create pre-filled submission
    sub_id = f"sub-{_u.uuid4().hex[:10]}"
    ref = f"FRM-{_dt.utcnow().strftime('%Y')}-{_u.uuid4().hex[:5].upper()}"
    _year = _dt.utcnow().strftime('%Y')
    _last_tickets = _fs_query("form_submissions",
                               filters=[("ticket_code", ">=", f"AKT-{_year}-")],
                               order_by=("ticket_code",), limit=1)
    if _last_tickets and _last_tickets[0].get("ticket_code"):
        try:
            _last_num = int(_last_tickets[0]["ticket_code"].split("-")[-1])
            ticket_code = f"AKT-{_year}-{_last_num + 1:05d}"
        except (ValueError, IndexError):
            ticket_code = f"AKT-{_year}-00001"
    else:
        ticket_code = f"AKT-{_year}-00001"

    now = _dt.utcnow().isoformat()

    # Calculate completeness using weighted scoring
    _completeness = _calc_completeness(form_data, template_id)
    _filled_count = sum(1 for v in form_data.values() if v and str(v).strip())
    _log.info(f"OpenVIVA completeness: {_filled_count} filled fields, weighted score = {_completeness}%")
    # P7: Detect pending-data placeholders — TEMPLATE-SCOPED (must run BEFORE readiness)
    _pending_fields = []
    # KFZ-only: driver data
    if template_id == "tpl-kfz-schaden":
        if form_data.get("fahrer_name") == "Fahrer wird nachgereicht":
            _pending_fields.append("Fahrerdaten (Name, Anschrift, Führerschein)")
    # MB-only: parts list
    if template_id == "tpl-maschinenbruch":
        if form_data.get("piese_inlocuit") == "(siehe Abschnitt 7a)" and "folgt nach Befundaufnahme" in (form_data.get("piese_avariate","") or ""):
            _pending_fields.append("Detaillierte Teileliste nach Befundaufnahme")
    # HPF-only: Geschädigter data
    if template_id == "tpl-haftpflicht":
        if "nachgereicht" in (form_data.get("gesch_firma_name","") or ""):
            _pending_fields.append("Angaben zum Geschaedigten (Name, Anschrift, Kontakt)")
    # All templates: VN contact if empty
    if not form_data.get("vn_kontakt") or len(form_data.get("vn_kontakt","").strip()) < 5:
        _pending_fields.append("Vollständige VN-Kontaktdaten")
    # P10: Versicherer-readiness score — computed after pending_fields known
    _readiness = _completeness
    _readiness -= len(_pending_fields) * 3
    if "nachgereicht" in (form_data.get("gesch_firma_name","") or ""): _readiness -= 4
    if form_data.get("fahrer_name") == "Fahrer wird nachgereicht": _readiness -= 3
    if "(siehe Abschnitt 7a)" in (form_data.get("piese_inlocuit","") or ""): _readiness -= 2
    _readiness = max(0, min(100, _readiness))
    form_data["_readiness_score"] = str(_readiness)
    # P11: SLA real timing
    _sla_dur = max(1, int(_ov_time_mod.time() - _ov_local_start_ts))
    form_data["_sla_generated_at"] = now
    form_data["_sla_processing_sec"] = str(_sla_dur)
    # Store metadata for auto-reply follow-up (sent after submission is created below)
    _pending_followup_text = None
    if _pending_fields:
        _pending_list = "\n".join([f"  • {f}" for f in _pending_fields])
        _pending_followup_text = f"""Sehr geehrte Damen und Herren,

der Schadenfall {ticket_code} wurde erstellt, es fehlen jedoch folgende Angaben für eine vollständige Meldung an den Versicherer:

{_pending_list}

Bitte senden Sie uns die fehlenden Informationen per E-Mail oder ergänzen Sie diese im Formular.

Mit freundlichen Grüßen
Ihr Alex (TPSH Versicherungsmakler)"""
    _fs_set("form_submissions", sub_id, {
        "template_id": template_id, "reference_number": ref,
        "client_name": client_name, "client_email": client_email,
        "client_phone": client_phone,
        "broker_email": sender_email,  # Store broker email for notification on completion
        "form_data": form_data, "status": "sent",
        "completeness_pct": _completeness, "submitted_at": now,
        "ticket_code": ticket_code, "created_at": now,
        "pending_fields": _pending_fields,
        "consistency_warnings": [],
        "readiness_score": _readiness,
        "sla_processing_sec": _sla_dur,
        "reminder_count": 0,
    }, merge=False)

    # Send pre-filled form link to client
    _host = os.environ.get("APP_HOST", "https://alex-insurance-broker-426485075291.europe-west3.run.app")
    _url = f"{_host}/forms/{template_id}?sub={sub_id}&client={client_email}"
    # German labels for form field display (client & broker emails)
    _FIELD_LABELS_DE = {
        "vn_name": "Versicherungsnehmer",
        "vn_adresse": "Adresse",
        "vn_plz_ort": "PLZ / Ort",
        "vn_email": "E-Mail",
        "vn_kontakt": "Telefon",
        "vn_kennzeichen": "Kennzeichen",
        "versicherungsschein_nr": "Versicherungsscheinnr.",
        "versicherer": "Versicherer",
        "kontaktperson": "Kontaktperson",
        "schadentag_uhrzeit": "Schadentag / Uhrzeit",
        "schadenort": "Schadenort",
        "schadensnummer": "Schadensnummer",
        "fahrgestellnummer": "Fahrzeug-Ident-Nr.",
        "baujahr": "Baujahr",
        "erstzulassung": "Erstzulassung",
        "unfallhergang": "Unfallhergang",
    }
    # Build data summary table for client email using German labels (only known fields, non-empty)
    _client_summary_rows = []
    for _fk, _fv in form_data.items():
        if _fv and _fk in _FIELD_LABELS_DE:
            _client_summary_rows.append(f'<tr><td style="padding:6px 0;color:#6b7280;width:40%">{_FIELD_LABELS_DE[_fk]}:</td><td style="padding:6px 0;font-weight:600">{_fv}</td></tr>')
    _client_summary_html = ""
    if _client_summary_rows:
        _client_summary_html = '<table style="width:100%;border-collapse:collapse;margin:16px 0;font-size:14px">' + "".join(_client_summary_rows) + '</table>'

    _client_html = f"""<div style="font-family:'Segoe UI',sans-serif;max-width:600px;margin:0 auto">
      <div style="background:linear-gradient(135deg,#3b82f6,#1d4ed8);padding:24px;border-radius:12px 12px 0 0;text-align:center">
        <h2 style="color:white;margin:0">📋 Ihr Schadenformular ist vorbereitet</h2>
      </div>
      <div style="background:#fff;padding:24px;border:1px solid #e5e7eb;border-radius:0 0 12px 12px">
        <p>{_greeting_for(client_name, kontaktperson=kontaktperson)}</p>
        <p>Ihr Versicherungsmakler hat ein Schadenformular für Sie vorbereitet.
           Folgende Daten wurden bereits eingetragen:</p>
        {_client_summary_html}
        <p>Bitte öffnen Sie das Formular und ergänzen Sie die fehlenden Informationen:</p>
        <div style="text-align:center;margin:24px 0">
          <a href="{_url}" style="background:#3b82f6;color:white;padding:14px 36px;border-radius:8px;text-decoration:none;font-weight:700;font-size:1.05em">Formular öffnen →</a>
        </div>
        <p style="font-size:12px;color:#9ca3af;text-align:center">
          {('Schadennummer: ' + form_data.get('schadensnummer', form_data.get('schadennummer', '')) + ' | ') if form_data.get('schadensnummer') or form_data.get('schadennummer') else ''}Ref: {ref}<br>
          TPSH Versicherungsmakler GmbH
        </p>
      </div>
    </div>"""

    if client_email:
        _ov_schadennr2 = form_data.get("schadensnummer") or form_data.get("schadennummer") or ""
        _ov_vs2 = form_data.get("versicherungsschein_nr") or form_data.get("vs_nr") or ""
        _ov_sd2 = form_data.get("schadendatum") or form_data.get("schadentag_uhrzeit") or ""
        if _ov_schadennr2 and _ov_vs2 and _ov_sd2:
            _ov_client_subj = f"KFZ-Schaden v. {_ov_sd2} / Versicherungsnr. {_ov_vs2} / TPSH Schadenr. {_ov_schadennr2} — bitte ergänzen"
        else:
            _email_ref = _ov_schadennr2 or ticket_code
            _ov_client_subj = f"📋 [{_email_ref}] Ihr Schadenformular — bitte ergänzen"
        _send_email_html([client_email],
            _ov_client_subj, _client_html)

    _log.info(f"✅ OpenVIVA email processed: {ticket_code} — {client_name} ({client_email}) — template {template_name}")
    _audit("openviva.email_processed", actor=sender_email, entity_type="form_submission",
           entity_id=ticket_code, details=f"OpenVIVA email: {client_name}, template {template_name}, {len(form_data)} fields")
    return {
        "ok": True,
        "ticket_code": ticket_code,
        "reference": ref,
        "sub_id": sub_id,
        "client_name": client_name,
        "client_email": client_email,
        "template_name": template_name,
        "prefilled_fields": len(form_data),
        "form_url": _url,
        "form_data": form_data,
        "kontaktperson": kontaktperson,
    }


@app.post("/api/commands/poll-inbox")
@app.post("/api/inbox/poll")
async def api_poll_inbox(request: _Request = None):
    """Manually trigger IMAP inbox poll for CMD emails and OpenVIVA structured emails.
    Body (optional): {"force_uids": ["262","263"]} — bypass Message-ID dedup for these UIDs.
    """
    _force_uids = []
    try:
        if request is not None:
            _b = await request.json()
            _fu = _b.get("force_uids") or []
            _force_uids = [str(u).strip() for u in _fu if str(u).strip()]
    except Exception:
        pass
    result = await poll_inbox_for_commands(force_uids=_force_uids)
    return result


@app.post("/api/debug/send-real-email")
async def api_debug_send_real_email(request: _Request):
    """Send a REAL email via SMTP (to AlexAi or any recipient) with attachments.
    Tests the full round-trip: SMTP send → IMAP pickup → OpenVIVA parse → attachments → PDF.
    Body: {to: "x@y.z", subject, body_html, body_text, attachments: [{filename, content_type, data_b64}]}
    Returns: {ok, sent}
    """
    import base64 as _rb64
    body = await request.json()
    _to = body.get("to") or [os.environ.get("SMTP_USER", "")]
    if isinstance(_to, str): _to = [_to]
    _subj = body.get("subject", "Test Email")
    _html = body.get("body_html") or body.get("body_text", "")
    _atts_in = body.get("attachments") or []
    _mime_atts = []
    for _a in _atts_in:
        try:
            _mime_atts.append({
                "filename": _a.get("filename", "attachment.bin"),
                "content": _rb64.standard_b64decode(_a.get("data_b64", "")),
                "mime": _a.get("content_type", "application/octet-stream")
            })
        except Exception:
            pass
    ok = _send_email_html(_to, _subj, _html, attachments=_mime_atts or None)
    return {"ok": ok, "sent_to": _to, "subject": _subj, "attachment_count": len(_mime_atts)}


@app.post("/api/debug/simulate-openviva")
async def api_debug_simulate_openviva(request: _Request):
    """Debug-only: directly invoke _process_openviva_email without IMAP round-trip.
    Body: {body: "email body text", sender: "broker@tpsh.ro", attachments?: [{filename, content_type, data_b64}]}
    Returns: {ok, sub_id, ...}
    """
    body = await request.json()
    _body_text = body.get("body", "")
    _sender = body.get("sender", "debug@test.local")
    _result = await _process_openviva_email(_body_text, _sender)
    # If attachments provided, process them through the same pipeline as IMAP does
    _atts_in = body.get("attachments") or []
    _sub_id = _result.get("sub_id") or _result.get("submission_id") or ""
    if _atts_in and _sub_id and _result.get("ok"):
        import base64 as _db_b64, re as _db_re
        from pathlib import Path as _db_Path
        _att_extracted_fields_merged = {}
        _att_upload_dir = _db_Path(__file__).parent / "output" / "form-attachments"
        _att_upload_dir.mkdir(parents=True, exist_ok=True)
        for _ai in _atts_in:
            try:
                from uuid import uuid4 as _db_uuid4
                _data = _db_b64.standard_b64decode(_ai.get("data_b64", ""))
                _fn = _ai.get("filename", "attachment.bin")
                _ct = _ai.get("content_type", "application/octet-stream")
                _safe = _db_re.sub(r'[^\w.\-]', '_', _fn)
                _path = _att_upload_dir / f"{_db_uuid4().hex[:12]}_{_safe}"
                _path.write_bytes(_data)
                _att_info = {
                    "filename": _fn, "name": _fn, "saved_as": _path.name,
                    "size": len(_data), "content_type": _ct, "mime": _ct,
                    "source": "debug_email_attachment",
                    "uploaded_at": __import__("datetime").datetime.utcnow().isoformat()
                }
                _is_img = _ct.startswith("image/")
                _is_pdf = _ct == "application/pdf"
                if _is_img or _is_pdf:
                    try:
                        _b64s = _db_b64.standard_b64encode(_data).decode("ascii")
                        _cli = __import__("anthropic").Anthropic()
                        if _is_img:
                            _media = _ct if _ct in ("image/jpeg","image/png","image/gif","image/webp") else "image/jpeg"
                            _cblock = {"type":"image","source":{"type":"base64","media_type":_media,"data":_b64s}}
                        else:
                            _cblock = {"type":"document","source":{"type":"base64","media_type":"application/pdf","data":_b64s}}
                        _vr = _cli.messages.create(model="claude-sonnet-4-20250514", max_tokens=4096,
                            temperature=0,
                            messages=[{"role":"user","content":[_cblock,{"type":"text","text":_UNIFIED_CLASSIFY_PROMPT}]}])
                        _vt = _vr.content[0].text.strip()
                        if _vt.startswith("```"):
                            _vt = _vt.split("\n",1)[-1].rsplit("```",1)[0].strip()
                        _cla = json.loads(_vt)
                        _att_info["category"] = _cla.get("category","OTHER")
                        _att_info["classification_confidence"] = _cla.get("confidence",0.5)
                        _att_info["summary"] = _cla.get("summary","")
                        # Heuristic upgrade: filename hints often more reliable than Vision on synthetic/low-quality images
                        _fn_lower = (_att_info.get("filename","") or "").lower()
                        import re as _heur_re
                        if _att_info["category"] == "OTHER" and _heur_re.search(r'schaden|damage|defekt|maschine|wasser|unfall|foto.*schaden|bild.*schaden', _fn_lower):
                            _att_info["category"] = "DAMAGE_PHOTO"
                            _att_info["_heuristic_upgrade"] = True
                        _rf = _cla.get("extracted_fields") or {}
                        _att_info["extracted_fields"] = {k:v for k,v in _rf.items() if v is not None and v != "null"}
                    except Exception as _ve:
                        _att_info["category"]="OTHER"; _att_info["extracted_fields"]={}
                        _att_info["classification_confidence"]=0.0
                        _att_info["_vision_error"] = str(_ve)
                _att_info = {k:v for k,v in _att_info.items() if v is not None}
                _fs_db.collection("form_submissions").document(_sub_id).update({
                    "attachments": _firestore_mod.ArrayUnion([_att_info])
                })
                _ef = _att_info.get("extracted_fields") or {}
                _att_cat = (_att_info.get("category") or "").upper()
                # Fix 1: POLICE_REPORT vehicle fields describe the OPPOSING party (gegner),
                # not the VN. Remap them to REAL KFZ Section 7 (Anspruchsteller) slots
                # BEFORE they pollute VN fields. Field names verified against
                # mcp-server/insurance_broker_mcp/data/form_templates/kfz_schadenmeldung.json
                # Section "Anspruchsteller (Geschädigter)" — only anspruch_kennzeichen,
                # anspruch_fabrikat, anspruch_name exist. fahrgestellnummer has no
                # dedicated claimant slot, so it's appended to anspruch_fabrikat.
                _police_report_remap = {
                    "kennzeichen": "anspruch_kennzeichen",
                    "fahrzeug": "anspruch_fabrikat",
                    "halter": "anspruch_name",
                }
                if _att_cat == "POLICE_REPORT":
                    # B4: Extract Dienststelle from multiple sources
                    _dst = _ef.get("dienststelle") or _ef.get("Dienststelle") or _ef.get("polizei_dienststelle") or _ef.get("behörde")
                    if not _dst:
                        # Fallback: regex on summary AND raw extracted text
                        import re as _dst_re
                        _haystack = (_att_info.get("summary","") or "") + " " + str(_ef.get("raw_text","") or "")
                        # Multi-pattern regex
                        for _pat in (
                            r'Dienststelle:?\s*([A-Za-züöäßÜÖÄ][A-Za-züöäßÜÖÄ\s\-.]{3,60})',
                            r'Polizeidienststelle:?\s*([A-Za-züöäßÜÖÄ][A-Za-züöäßÜÖÄ\s\-.]{3,60})',
                            r'(Polizeipr[aä]sidium\s+[A-ZÄÖÜ][A-Za-züöäßÜÖÄ\s\-]+)',
                            r'(Polizeiinspektion\s+[A-ZÄÖÜ][A-Za-züöäßÜÖÄ\s\-]+)',
                            r'(Autobahnpolizei\s+[A-ZÄÖÜ][A-Za-züöäßÜÖÄ\s\-]+)',
                            r'(PP\s+[A-ZÄÖÜ][A-Za-züöäßÜÖÄ\s\-]+)',
                        ):
                            _m = _dst_re.search(_pat, _haystack)
                            if _m:
                                _dst = _m.group(1).strip().rstrip(".,;")
                                break
                    if _dst and len(_dst) > 2:
                        _att_extracted_fields_merged["polizei_dienststelle"] = _dst
                        _att_extracted_fields_merged["dienststelle"] = _dst
                    # Merge fahrgestellnummer into anspruch_fabrikat (no dedicated slot)
                    _fin_val = _ef.get("fahrgestellnummer") or _ef.get("Fahrgestellnummer")
                    _veh_val = _ef.get("fahrzeug") or _ef.get("Fahrzeug")
                    if _fin_val:
                        _combo = f"{_veh_val} (FIN: {_fin_val})" if _veh_val else f"FIN: {_fin_val}"
                        if "anspruch_fabrikat" not in _att_extracted_fields_merged:
                            _att_extracted_fields_merged["anspruch_fabrikat"] = _combo
                    # Remap remaining opposing-party fields and DELETE originals from _ef
                    # to prevent VN slot poisoning during downstream smart-merge.
                    for _vn_key in ("fahrgestellnummer", "kennzeichen", "halter", "fahrzeug"):
                        if _vn_key in _ef:
                            _v_pr = _ef.pop(_vn_key, None)
                            if _v_pr and _vn_key in _police_report_remap:
                                _dest_pr = _police_report_remap[_vn_key]
                                if _dest_pr not in _att_extracted_fields_merged:
                                    _att_extracted_fields_merged[_dest_pr] = _v_pr
                for _k, _v in _ef.items():
                    if not _v: continue
                    _kk = _k
                    if _kk not in _att_extracted_fields_merged:
                        _att_extracted_fields_merged[_kk] = _v
            except Exception as _ae:
                import traceback as _tb
                _log.warning(f"debug attachment failed: {_ae}\n{_tb.format_exc()}")
        # Smart merge (same logic as IMAP poll)
        if _att_extracted_fields_merged:
            _existing_fd = _fs_db.collection("form_submissions").document(_sub_id).get()
            _current_fd = (_existing_fd.to_dict() or {}).get("form_data", {}) if _existing_fd.exists else {}
            _identity_fields = {"name","vn_name","versicherungsnehmer","halter",
                "strasse","vn_adresse","plz_ort","vn_plz_ort","telefon","vn_kontakt",
                "email","vn_email","kontaktperson","fahrer","fahrzeug",
                "kennzeichen","vn_kennzeichen","geschaedigter","anspruchsteller_name"}
            _att_to_form = {"name":"vn_name","versicherungsnehmer":"vn_name","halter":"vn_name",
                "strasse":"vn_adresse","adresse":"vn_adresse","plz_ort":"vn_plz_ort",
                "telefon":"vn_kontakt","tel":"vn_kontakt","email":"vn_email","e-mail":"vn_email",
                "kennzeichen":"vn_kennzeichen","unfallort":"schadenort",
                "unfalldatum":"schadentag_uhrzeit","schadendatum":"schadentag_uhrzeit"}
            _has_id = any(_current_fd.get(f) for f in ("vn_name","vn_email","vn_kennzeichen"))
            # Template-specific aliases: generic names (Vision) → KFZ/HPF/MB template field names
            # Vision from Polizeibericht/KV has role context — safe to populate claimant fields
            _template_aliases = {
                "schadenshoehe": ["anspruch_schadenshoehe", "schadenhoehe_ansprueche"],
                "schadenhoehe": ["anspruch_schadenshoehe", "schadenhoehe_ansprueche"],
                "aktenzeichen": ["polizei_aktenzeichen", "polizei_details"],
                # KFZ + HPF claimant mapping
                "anspruchsteller_name": ["anspruch_name", "gesch_firma_name", "geschaedigter"],
                "anspruchsteller_fahrzeug": ["anspruch_fabrikat", "fz_typ_marke"],
                "anspruchsteller_strasse": ["anspruch_strasse", "gesch_strasse"],
                "anspruchsteller_plz_ort": ["anspruch_plz_ort", "gesch_plz_ort"],
                "anspruchsteller_telefon": ["anspruch_telefon", "gesch_telefon"],
                "anspruchsteller_email": ["anspruch_email", "gesch_email"],
                "anspruchsteller_kennzeichen": ["anspruch_kennzeichen"],
                # Maschinenbruch extractions
                "machine_type": ["catalog_position"],
                "machine_manufacturer": ["producator"],
                "seriennummer": ["serie_produs"],
            }
            _new_fields = {}
            for _mk,_mv in _att_extracted_fields_merged.items():
                if not _mv: continue
                _tgt = _att_to_form.get(_mk.lower(), _mk)
                if _current_fd.get(_tgt): continue
                if _tgt in _identity_fields and _has_id: continue
                _new_fields[_tgt] = _mv
                # Also write to template-specific alias keys if empty
                for _alias_tgt in _template_aliases.get(_tgt.lower(), []):
                    if not _current_fd.get(_alias_tgt) and _alias_tgt not in _new_fields:
                        _new_fields[_alias_tgt] = _mv
            # Auto-fill polizei_aufnahme when POLICE_REPORT attached
            try:
                _snap_for_pol = _fs_db.collection("form_submissions").document(_sub_id).get()
                _sd = _snap_for_pol.to_dict() or {} if _snap_for_pol.exists else {}
                _fd_pol = _sd.get("form_data",{}) or {}
                _atts_pol = _sd.get("attachments",[]) or []
                _has_polizei = any((a.get("category","") or "").upper() == "POLICE_REPORT" for a in _atts_pol)
                if _has_polizei and not _fd_pol.get("polizei_aufnahme"):
                    _new_fields["polizei_aufnahme"] = "Ja"
                if _has_polizei and not _fd_pol.get("polizeilich_aufgenommen"):
                    _new_fields["polizeilich_aufgenommen"] = "Ja"
            except Exception: pass
            if _new_fields:
                _fd_upd = {f"form_data.{k}": v for k,v in _new_fields.items()}
                _fs_db.collection("form_submissions").document(_sub_id).update(_fd_upd)
                try:
                    _merged = dict(_current_fd); _merged.update(_new_fields)
                    _tid = _result.get("template_id","") or (_existing_fd.to_dict() or {}).get("template_id","")
                    _recalc = _calc_completeness(_merged, _tid)
                    _fs_db.collection("form_submissions").document(_sub_id).update({"completeness_pct": _recalc})
                    _result["completeness_pct_after_merge"] = _recalc
                except Exception: pass
                _result["fields_merged_from_attachments"] = list(_new_fields.keys())
            # P5: Cross-document consistency check — compare Vision-extracted fields vs email body
            try:
                _warnings = []
                _snap = _fs_db.collection("form_submissions").document(_sub_id).get()
                _sub_doc = _snap.to_dict() or {}
                _sub_atts = _sub_doc.get("attachments", []) or []
                _fd_check = _sub_doc.get("form_data", {}) or {}
                for _att in _sub_atts:
                    _ef = _att.get("extracted_fields",{}) or {}
                    _att_name = _att.get("filename","attachment")
                    # Check unfallort
                    _email_ort = (_fd_check.get("schadenort","") or _fd_check.get("schadensort","")).strip().lower()
                    _vision_ort = (_ef.get("unfallort","") or "").strip().lower()
                    if _email_ort and _vision_ort and _email_ort not in _vision_ort and _vision_ort not in _email_ort:
                        _warnings.append(f"⚠ Ort-Widerspruch: Email='{_fd_check.get('schadenort','')}' vs {_att_name}='{_ef.get('unfallort','')}'")
                    # Check schadenshoehe
                    _email_sum = (_fd_check.get("schadenshoehe","") or "").replace(".","").replace(",","").replace(" EUR","").strip()
                    _vision_sum = (_ef.get("schadenshoehe","") or "").replace(".","").replace(",","").replace(" EUR","").strip()
                    if _email_sum and _vision_sum and _email_sum.isdigit() and _vision_sum.isdigit() and abs(int(_email_sum) - int(_vision_sum)) > 500:
                        _warnings.append(f"⚠ Schadenshoehe-Differenz: Email={_fd_check.get('schadenshoehe','')} vs {_att_name}={_ef.get('schadenshoehe','')}")
                if _warnings:
                    _fs_db.collection("form_submissions").document(_sub_id).update({"consistency_warnings": _warnings})
                    _result["consistency_warnings"] = _warnings
            except Exception as _cw_err:
                pass
        _result["attachments_processed"] = len(_atts_in)
        # Fix 2 v2: MB Section 8 attachment→slot binding — ALWAYS run when attachments present
        # (independent of _att_extracted_fields_merged which skips when Vision extracts nothing)
        if _atts_in:
            try:
                import re as _re_mb
                _tpl_bind = (_fs_db.collection("form_submissions").document(_sub_id).get().to_dict() or {}).get("template_id", "")
                if _tpl_bind == "tpl-maschinenbruch":
                    _snap = _fs_db.collection("form_submissions").document(_sub_id).get()
                    _fd_now = (_snap.to_dict() or {}).get("form_data", {}) if _snap.exists else {}
                    _sub_atts_now = (_snap.to_dict() or {}).get("attachments", []) if _snap.exists else []
                    _bu = {}
                    _kv_m = None; _foto_m = None
                    for _a in (_sub_atts_now or []):
                        _cat = (_a.get("category") or "").upper()
                        _fnl = (_a.get("filename") or "").lower()
                        if _kv_m is None and (_cat == "REPAIR_ESTIMATE" or "repair" in _cat.lower() or _re_mb.search(r'kosten|rechnung|estimate', _fnl)):
                            _kv_m = _a.get("filename") or _a.get("saved_as") or ""
                        # Broader: non-REPAIR_ESTIMATE image on MB binds to foto_daune
                        if _foto_m is None and _cat != "REPAIR_ESTIMATE" and (
                            _cat in ("VEHICLE_DAMAGE","SCHADEN_FOTO","MACHINE_DAMAGE","OTHER","")
                            or _re_mb.search(r'schaden|damage|foto|bild|maschine|defekt|unfall', _fnl)
                            or str(_a.get("mime","")).startswith("image/")
                            or str(_a.get("content_type","")).startswith("image/")
                        ):
                            _foto_m = _a.get("filename") or _a.get("saved_as") or ""
                    if _kv_m and not _fd_now.get("costuri_reparatie"):
                        _bu["costuri_reparatie"] = f"beigefuegt: {_kv_m}"
                    if _foto_m and not _fd_now.get("foto_daune"):
                        _bu["foto_daune"] = f"beigefuegt: {_foto_m}"
                    if _bu:
                        _fs_db.collection("form_submissions").document(_sub_id).update({f"form_data.{k}": v for k,v in _bu.items()})
                        _log.info(f"📎 MB Sec.8 bound (debug): {list(_bu.keys())}")
            except Exception as _bind_err_dbg:
                _log.warning(f"MB Sec.8 binding (debug) failed: {_bind_err_dbg}")
    return _result


# ── Chat AI Widget: help clients fill the form ─────────────────────────
@app.post("/api/forms/chat")
async def api_form_chat(request: _Request):
    """AI chat widget — client asks questions about form fields, gets instant answers.
    If AI can't help, offers to forward question to broker via email."""
    body = await request.json()
    question = body.get("question", "").strip()
    template_id = body.get("template_id", "")
    client_name = body.get("client_name", "")
    client_email = body.get("client_email", "")
    sub_id = body.get("sub_id", "")
    lang = body.get("lang", "de")

    if not question:
        return {"ok": False, "message": "No question provided"}

    # Check if client wants to forward to broker
    if body.get("forward_to_broker"):
        _operator = os.environ.get("OPERATOR_EMAIL", "")
        if _operator:
            _fwd_html = f"""<div style="font-family:'Segoe UI',sans-serif;max-width:600px;margin:0 auto">
              <div style="background:linear-gradient(135deg,#f59e0b,#d97706);padding:20px;border-radius:12px 12px 0 0;text-align:center">
                <h2 style="color:white;margin:0">❓ Kundenfrage zum Formular</h2>
              </div>
              <div style="background:#fff;padding:24px;border:1px solid #e5e7eb;border-radius:0 0 12px 12px">
                <p><strong>Client:</strong> {client_name} ({client_email})</p>
                <p><strong>Formular:</strong> {template_id}</p>
                <p><strong>Ref:</strong> {sub_id}</p>
                <div style="background:#fffbeb;padding:16px;border-radius:8px;border:1px solid #fde68a;margin:16px 0">
                  <strong>Frage:</strong><br>{question}
                </div>
                <p>Bitte antworten Sie dem Kunden direkt oder per CMD4.</p>
                {_cmd_footer_html(sub_id)}
              </div>
            </div>"""
            _send_email_html([_operator],
                f"❓ Kundenfrage: {client_name} — {question[:50]}...", _fwd_html)
        return {
            "ok": True,
            "answer": "Ihre Frage wurde an Ihren Makler weitergeleitet. Sie werden in Kürze kontaktiert." if lang == "de"
                else "Întrebarea dvs. a fost trimisă brokerului. Veți fi contactat în curând." if lang == "ro"
                else "Your question has been forwarded to your broker. You will be contacted shortly.",
            "forwarded": True
        }

    # AI answers the question based on form template
    try:
        import anthropic
        _ai = anthropic.Anthropic(api_key=os.environ.get("ANTHROPIC_API_KEY", ""))

        # Load template info for context
        _tpl = _fs_get("form_templates", template_id) if template_id else None
        _tpl_context = ""
        if _tpl:
            _sections = _tpl.get("sections") or _tpl.get("sections_json", [])
            if isinstance(_sections, str): _sections = json.loads(_sections or "[]")
            _field_list = []
            for sec in _sections:
                for f in sec.get("fields", []):
                    _req = " (PFLICHTFELD)" if f.get("required") else ""
                    _field_list.append(f"- {f.get('label','?')}{_req}: {f.get('placeholder', f.get('type','text'))}")
            _tpl_context = f"Formular: {_tpl.get('name','')}\nFelder:\n" + "\n".join(_field_list[:50])

        _lang_instr = {"de": "Antworte auf Deutsch", "ro": "Raspunde in romana", "en": "Answer in English"}.get(lang, "Answer in the same language as the question")

        _resp = _ai.messages.create(
            model="claude-sonnet-4-20250514",
            max_tokens=400,
            messages=[{"role": "user", "content": f"""Du bist ein hilfreicher Assistent für ein Versicherungsformular.
Ein Kunde hat eine Frage beim Ausfüllen des Formulars.

{_tpl_context}

Kundenfrage: {question}

{_lang_instr}. Sei freundlich, kurz und hilfreich. Maximal 3-4 Sätze.
Wenn du die Frage nicht beantworten kannst, sage dem Kunden, dass er die Frage an seinen Makler weiterleiten kann."""}]
        )
        answer = _resp.content[0].text.strip()
        return {"ok": True, "answer": answer, "forwarded": False}
    except Exception as _e:
        _log.warning(f"Form chat AI error: {_e}")
        return {
            "ok": True,
            "answer": "Leider kann ich diese Frage nicht beantworten. Möchten Sie die Frage an Ihren Makler weiterleiten?" if lang == "de"
                else "Din păcate nu pot răspunde la această întrebare. Doriți să o trimiteți brokerului?" if lang == "ro"
                else "Sorry, I can't answer this question. Would you like to forward it to your broker?",
            "forwarded": False,
            "suggest_forward": True
        }


async def poll_inbox_for_commands(force_uids: list = None):
    """Poll Gmail IMAP inbox for operator CMD replies.
    Looks for emails with CMD1-CMD7 codes, executes them, sends result back.
    Should be called by cron every 5 minutes.

    force_uids: list of IMAP UIDs (as strings) to re-process even if already in
                processed_emails (bypasses Message-ID dedup). Useful for manual
                reprocessing of specific emails when prior runs didn't persist
                attachments to GCS correctly.
    """
    _force_uid_set = set(force_uids or [])
    import imaplib, email as _email_mod, re as _re_mod
    from datetime import datetime as _dt

    # IMAP config — portable: works with Gmail, Outlook, Exchange, any IMAP server
    # Gmail: imap.gmail.com:993  |  Outlook: outlook.office365.com:993
    imap_host = os.environ.get("IMAP_HOST", "imap.gmail.com")
    imap_port = int(os.environ.get("IMAP_PORT", "993"))
    imap_user = os.environ.get("IMAP_USER", os.environ.get("SMTP_USER", ""))
    imap_pass = os.environ.get("IMAP_PASS", os.environ.get("SMTP_PASS", ""))
    if not imap_user or not imap_pass:
        return {"ok": False, "message": "IMAP credentials not configured"}

    processed = []
    try:
        mail = imaplib.IMAP4_SSL(imap_host, imap_port)
        mail.login(imap_user, imap_pass)
        mail.select("INBOX")

        # Search for recent emails (last 1 day) — don't rely on UNSEEN flag
        # Cloud Run instances restart, so we track processed IDs in-memory
        from datetime import datetime as _imap_dt, timedelta as _imap_td
        _since_date = (_imap_dt.utcnow() - _imap_td(days=1)).strftime("%d-%b-%Y")
        _status, _msg_ids = mail.search(None, f'(SINCE {_since_date})')
        if _status != "OK" or not _msg_ids[0]:
            mail.logout()
            return {"ok": True, "processed": 0, "message": "Keine neuen E-Mails"}

        # Track processed message IDs in Firestore to avoid re-processing
        from datetime import datetime as _pe_dt, timedelta as _pe_td
        _2d_ago = (_pe_dt.utcnow() - _pe_td(days=2)).isoformat()
        _pe_docs = _fs_query("processed_emails", filters=[("processed_at", ">=", _2d_ago)], limit=500)
        _already_processed = {d["_id"] for d in _pe_docs}

        # If force_uids is specified, scan wider window (last 7 days) so old UIDs are reachable
        _scan_ids = _msg_ids[0].split()[-20:]
        if _force_uid_set:
            # Re-query with larger window for force reprocessing
            _since_wide = (_imap_dt.utcnow() - _imap_td(days=7)).strftime("%d-%b-%Y")
            _st2, _ids2 = mail.search(None, f'(SINCE {_since_wide})')
            if _st2 == "OK" and _ids2 and _ids2[0]:
                _scan_ids = _ids2[0].split()

        for msg_id in _scan_ids:
            # Check if already processed (by IMAP UID)
            _msg_uid = msg_id.decode() if isinstance(msg_id, bytes) else str(msg_id)
            _is_forced = _msg_uid in _force_uid_set
            if _msg_uid in _already_processed and not _is_forced:
                continue

            _status, _data = mail.fetch(msg_id, "(RFC822)")
            if _status != "OK":
                continue
            msg = _email_mod.message_from_bytes(_data[0][1])
            # FIX: Dedup by Message-ID header (globally unique, survives UID changes)
            _msg_id_hdr = str(msg.get("Message-ID","") or msg.get("Message-Id","") or "").strip("<>").strip()
            if _msg_id_hdr:
                _mid_key = f"mid-{_msg_id_hdr.replace('@','_at_').replace('.','_')[:100]}"
                if _mid_key in _already_processed and not _is_forced:
                    try: mail.store(msg_id, "+FLAGS", "\\Seen")
                    except: pass
                    continue
                # Mark as processed by Message-ID IMMEDIATELY (before processing)
                try:
                    _fs_set("processed_emails", _mid_key, {"processed_at": __import__("datetime").datetime.utcnow().isoformat(), "imap_uid": _msg_uid}, merge=False)
                except: pass
            _from = msg.get("From", "")
            _subject_raw = msg.get("Subject", "")
            # Decode subject (may be base64/quoted-printable encoded)
            try:
                _decoded_parts = _email_mod.header.decode_header(_subject_raw)
                _subject = ""
                for _part, _enc in _decoded_parts:
                    if isinstance(_part, bytes):
                        _subject += _part.decode(_enc or "utf-8", errors="replace")
                    else:
                        _subject += _part
            except Exception:
                _subject = str(_subject_raw)

            # Extract body text (handles S/MIME signed emails from Outlook)
            _body = ""
            _html_body = ""
            if msg.is_multipart():
                for part in msg.walk():
                    _ct = part.get_content_type()
                    if _ct == "text/plain" and not _body:
                        _payload = part.get_payload(decode=True)
                        if _payload:
                            _body = _payload.decode("utf-8", errors="replace")
                    elif _ct == "text/html" and not _html_body:
                        _payload = part.get_payload(decode=True)
                        if _payload:
                            _html_body = _payload.decode("utf-8", errors="replace")
            else:
                _payload = msg.get_payload(decode=True)
                if _payload:
                    _body = _payload.decode("utf-8", errors="replace")
            # Fallback: strip HTML if no text/plain found (S/MIME emails)
            if not _body.strip() and _html_body:
                import re as _re_html
                _body = _re_html.sub(r'<[^>]+>', ' ', _html_body)
                _body = _re_html.sub(r'\s+', ' ', _body).strip()

            # Extract file attachments from email (handles S/MIME signed emails)
            # S/MIME structure: multipart/signed -> multipart/mixed -> application/pdf
            # Real attachments may lack Content-Disposition: attachment header
            _email_attachments = []
            for part in msg.walk():
                _ct = part.get_content_type()
                _fname = part.get_filename()
                # Skip S/MIME signature files (by content type or filename)
                if _ct in ('application/pkcs7-signature', 'application/x-pkcs7-signature'):
                    continue
                if _fname and _fname.lower() == 'smime.p7s':
                    continue
                # Skip text body parts
                if _ct in ('text/plain', 'text/html'):
                    continue
                # Skip multipart containers
                if _ct.startswith('multipart/'):
                    continue
                # Accept if it has a filename OR is a known document type
                if _fname or _ct in ('application/pdf', 'application/msword',
                                     'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
                                     'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                                     'image/jpeg', 'image/png', 'image/tiff'):
                    _att_data = part.get_payload(decode=True)
                    if not _fname:
                        _ext = {'application/pdf': '.pdf', 'application/msword': '.doc',
                                'image/jpeg': '.jpg', 'image/png': '.png'}.get(_ct, '.bin')
                        _fname = f'attachment{_ext}'
                    # Decode filename if RFC2047 encoded
                    if isinstance(_fname, str):
                        try:
                            from email.header import decode_header as _dh
                            _dec_parts = _dh(_fname)
                            _fname = ""
                            for _dp, _de in _dec_parts:
                                if isinstance(_dp, bytes):
                                    _fname += _dp.decode(_de or "utf-8", errors="replace")
                                else:
                                    _fname += _dp
                        except Exception:
                            pass
                    if _att_data and len(_att_data) > 100:  # Skip tiny/empty attachments
                        _email_attachments.append({
                            "filename": _fname,
                            "data": _att_data,
                            "content_type": _ct,
                            "size": len(_att_data)
                        })
            if _email_attachments:
                _log.info(f"📎 IMAP extracted {len(_email_attachments)} attachment(s) from msg {_msg_uid}: {[a['filename'] for a in _email_attachments]}")

            # Extract sender email first — filter out no-reply, spam, notifications
            _email_match = _re_mod.search(r'[\w.+-]+@[\w-]+\.[\w.]+', _from)
            sender_email = _email_match.group(0).lower() if _email_match else ""

            # If body is empty but email has content, try harder: walk ALL parts including text/html
            if not _body.strip():
                for part in msg.walk():
                    _ct = part.get_content_type()
                    _payload = part.get_payload(decode=True)
                    if _payload:
                        _decoded = _payload.decode("utf-8", errors="replace")
                        if _ct == "text/plain" and _decoded.strip():
                            _body = _decoded
                            break
                        elif _ct == "text/html" and _decoded.strip() and not _body.strip():
                            import re as _re_html2
                            _body = _re_html2.sub(r'<[^>]+>', ' ', _decoded)
                            _body = _re_html2.sub(r'\s+', ' ', _body).strip()

            # Check for structured data patterns BEFORE skipping short bodies
            _has_structured_data = any(kw in (_body + " " + _subject) for kw in
                                       ["Formularkennung", "VN:", "Versicherer:", "CMD"])
            _is_cmd_anywhere = bool(_re_mod.search(r'CMD\s*\d', (_body or "") + ' ' + (_subject or ""), _re_mod.I))

            # Skip emails with empty/too-short body — but NEVER skip if structured data present
            if len(_body.strip()) < 10 and not _has_structured_data and not _is_cmd_anywhere:
                _log.warning(f"IMAP skipping msg {_msg_uid} (empty/short body, {len(_body.strip())} chars) subj={_subject[:50]}")
                continue

            # Skip emails from no-reply, noreply, mailer-daemon, notifications
            _skip_senders = ["no-reply", "noreply", "mailer-daemon", "notification",
                             "newsletter", "announce", "support@", "info@",
                             "postmaster", "donotreply", "automated"]
            if any(skip in sender_email for skip in _skip_senders):
                mail.store(msg_id, "+FLAGS", "\\Seen")  # Mark as read so we don't re-check
                continue

            # Skip emails from ourselves (Alex sending to itself)
            # BUT allow OpenVIVA emails (broker sends FROM AlexAi TO AlexAi)
            # AND allow CMD emails (broker sends CMD2/4/6 from own address)
            _own_email = os.environ.get("SMTP_USER", "").lower()
            _is_openviva = "Formularkennung AlexAI" in _body or "Formularkennung AlexAI" in _subject
            _is_cmd = _is_cmd_anywhere
            _log.info(f"IMAP: checking msg {_msg_uid}, from={sender_email}, subj={_subject[:40]}, body_len={len(_body)}, is_ov={_is_openviva}, is_cmd={_is_cmd}, is_self={sender_email==_own_email}")
            # ONLY skip self-emails if body is short AND no structured data patterns
            if _own_email and sender_email == _own_email and not _is_openviva and not _is_cmd and not _has_structured_data:
                if len(_body.strip()) < 50:
                    _log.info(f"📧 Skipping self-email (short, no structured data): {_subject[:50]}")
                    mail.store(msg_id, "+FLAGS", "\\Seen"); _fs_set("processed_emails", _msg_uid, {"processed_at": __import__("datetime").datetime.utcnow().isoformat()}, merge=False)
                    continue
                else:
                    _log.info(f"📧 Self-email with substantial body ({len(_body)} chars), processing: {_subject[:50]}")
            # For ANY email with structured data patterns, ALWAYS process (never skip)
            if _has_structured_data:
                _log.info(f"📧 Structured data detected in msg {_msg_uid}, forcing processing")

            # ── OpenVIVA structured email detection ──────────────────────
            # If email contains "Formularkennung AlexAI:" → parse structured data,
            # create pre-filled submission, send link to client
            if "Formularkennung AlexAI" in _body or "Formularkennung AlexAI" in _subject:
                try:
                    _log.info(f"📧 OpenVIVA structured email detected from {sender_email}")
                    _ov_result = await _process_openviva_email(_body, sender_email)
                    if _ov_result.get("ok"):
                        # Reply to sender confirming processing
                        _ov_form_url = _ov_result.get('form_url', '')
                        _ov_pdf_url = f"{os.environ.get('APP_HOST','')}/api/forms/submissions/{_ov_result.get('sub_id','')}/pdf"
                        _ov_json_url = f"{os.environ.get('APP_HOST','')}/api/forms/submissions/{_ov_result.get('sub_id','')}/export"
                        # Build data summary table for broker confirmation email using German labels
                        _ov_fd = _ov_result.get('form_data', {}) or {}
                        _ov_kp = _ov_result.get('kontaktperson', '')
                        _broker_summary_rows = []
                        _BROKER_LABELS_DE = {
                            "vn_name": "Versicherungsnehmer",
                            "vn_adresse": "Adresse",
                            "vn_plz_ort": "PLZ / Ort",
                            "vn_email": "E-Mail",
                            "vn_kontakt": "Telefon",
                            "vn_kennzeichen": "Kennzeichen",
                            "versicherungsschein_nr": "Versicherungsscheinnr.",
                            "versicherer": "Versicherer",
                            "kontaktperson": "Kontaktperson",
                            "schadentag_uhrzeit": "Schadentag / Uhrzeit",
                            "schadenort": "Schadenort",
                            "schadensnummer": "Schadensnummer",
                            "fahrgestellnummer": "Fahrzeug-Ident-Nr.",
                            "baujahr": "Baujahr",
                            "erstzulassung": "Erstzulassung",
                            "unfallhergang": "Unfallhergang",
                        }
                        for _bk, _bv in _ov_fd.items():
                            if _bv and _bk in _BROKER_LABELS_DE:
                                _broker_summary_rows.append(f'<tr><td style="padding:6px 0;color:#6b7280;width:40%">{_BROKER_LABELS_DE[_bk]}:</td><td style="padding:6px 0;font-weight:600">{_bv}</td></tr>')
                        _broker_summary_html = ""
                        if _broker_summary_rows:
                            _broker_summary_html = '<table style="width:100%;border-collapse:collapse;margin:16px 0;font-size:14px">' + "".join(_broker_summary_rows) + '</table>'

                        _reply_html = f"""<div style="font-family:'Segoe UI',sans-serif;max-width:600px;margin:0 auto">
                          <div style="background:linear-gradient(135deg,#10b981,#059669);padding:20px;border-radius:12px 12px 0 0;text-align:center">
                            <h2 style="color:white;margin:0">✅ Formular erstellt & Link gesendet</h2>
                          </div>
                          <div style="background:#fff;padding:24px;border:1px solid #e5e7eb;border-radius:0 0 12px 12px">
                            <p><strong>Client:</strong> {_ov_result.get('client_name','')} ({_ov_result.get('client_email','')})</p>
                            <p><strong>Formular:</strong> {_ov_result.get('template_name','')}</p>
                            {_broker_summary_html}
                            <p>Link wurde automatisch an den Kunden gesendet.</p>
                            <p style="text-align:center;margin:20px 0"><a href="{_ov_form_url}" style="background:#10b981;color:white;padding:12px 28px;border-radius:8px;text-decoration:none;font-weight:600">Fragebogen ansehen →</a></p>
                            <p style="text-align:center"><a href="{_ov_pdf_url}" style="color:#2563eb;font-size:0.9em">📄 PDF herunterladen</a></p>
                            <p style="text-align:center"><a href="{_ov_json_url}" style="color:#6b7280;font-size:0.85em">📋 JSON-Daten herunterladen</a></p>
                          </div>
                        </div>"""
                        _send_email_html([sender_email],
                            f"✅ [{_ov_result.get('ticket_code','')}] Formular erstellt — {_ov_result.get('client_name','')}",
                            _reply_html)
                        # Upload email attachments to the submission + AI classify+extract
                        _ov_sub_id = _ov_result.get("sub_id") or _ov_result.get("submission_id") or ""
                        _log.info(f"📎 Attachment check: {len(_email_attachments)} attachments, sub_id={_ov_sub_id}")
                        _att_extracted_fields_merged = {}  # Collect extracted fields from all attachments
                        if _email_attachments and _ov_sub_id:
                            _att_upload_dir = Path(__file__).parent / "output" / "form-attachments"
                            _att_upload_dir.mkdir(parents=True, exist_ok=True)
                            for _eatt in _email_attachments:
                                try:
                                    from uuid import uuid4 as _att_uuid4
                                    _att_safe_name = _re_mod.sub(r'[^\w.\-]', '_', _eatt["filename"])
                                    _att_path = _att_upload_dir / f"{_att_uuid4().hex[:12]}_{_att_safe_name}"
                                    _att_path.write_bytes(_eatt["data"])
                                    _att_ct = _eatt["content_type"]
                                    # Upload to GCS for persistence across Cloud Run instances
                                    _gcs_uri = None
                                    _gcs_error = None
                                    try:
                                        _gcs_bucket = os.environ.get("GCS_BUCKET","")
                                        _log.info(f"🪣 GCS upload attempt for {_eatt['filename']} bucket={_gcs_bucket}")
                                        if _gcs_bucket:
                                            from google.cloud import storage as _gcs_storage
                                            _gcs_client = _gcs_storage.Client()
                                            _bkt = _gcs_client.bucket(_gcs_bucket)
                                            _gcs_blob = _bkt.blob(f"attachments/{_att_path.name}")
                                            _gcs_blob.upload_from_string(_eatt["data"], content_type=_att_ct)
                                            _gcs_uri = f"gs://{_gcs_bucket}/attachments/{_att_path.name}"
                                            _log.info(f"✅ GCS UPLOADED: {_gcs_uri} ({_eatt['size']} bytes)")
                                        else:
                                            _gcs_error = "GCS_BUCKET env var empty"
                                    except ImportError as _imp_err:
                                        _gcs_error = f"IMPORT_ERROR: {_imp_err}"
                                        _log.error(f"❌ GCS import failed: {_imp_err}")
                                    except Exception as _gcs_err:
                                        _gcs_error = str(_gcs_err)[:200]
                                        _log.error(f"❌ GCS upload failed for {_eatt['filename']}: {_gcs_err}")
                                    _att_info = {
                                        "filename": _eatt["filename"],
                                        "saved_as": _att_path.name,
                                        "gcs_uri": _gcs_uri,
                                        "size": _eatt["size"],
                                        "content_type": _att_ct,
                                        "source": "email_attachment",
                                        "uploaded_at": __import__("datetime").datetime.utcnow().isoformat()
                                    }
                                    # AI classify+extract (same as upload endpoint)
                                    _att_is_image = _att_ct.startswith("image/") or (_eatt["filename"].lower().endswith((".jpg",".jpeg",".png",".gif",".webp")))
                                    _att_fn_lower = _eatt["filename"].lower()
                                    _att_is_pdf = _att_ct == "application/pdf" or _att_fn_lower.endswith(".pdf") or _eatt.get("data","")[:4] == b"%PDF"
                                    if _att_is_image or _att_is_pdf:
                                        try:
                                            import base64 as _att_b64
                                            _att_file_b64 = _att_b64.standard_b64encode(_eatt["data"]).decode("ascii")
                                            _att_vision_client = __import__("anthropic").Anthropic()
                                            if _att_is_image:
                                                _att_media = _att_ct if _att_ct in ("image/jpeg", "image/png", "image/gif", "image/webp") else "image/jpeg"
                                                _att_content_block = {"type": "image", "source": {"type": "base64", "media_type": _att_media, "data": _att_file_b64}}
                                            else:
                                                _att_content_block = {"type": "document", "source": {"type": "base64", "media_type": "application/pdf", "data": _att_file_b64}}
                                            _att_vision_resp = _att_vision_client.messages.create(
                                                model="claude-sonnet-4-20250514",
                                                max_tokens=4096,
                                                temperature=0,
                                                messages=[{"role": "user", "content": [_att_content_block, {"type": "text", "text": _UNIFIED_CLASSIFY_PROMPT}]}]
                                            )
                                            _att_vision_text = _att_vision_resp.content[0].text.strip()
                                            if _att_vision_text.startswith("```"):
                                                _att_vision_text = _att_vision_text.split("\n", 1)[-1].rsplit("```", 1)[0].strip()
                                            _att_classify = json.loads(_att_vision_text)
                                            _att_info["category"] = _att_classify.get("category", "OTHER")
                                            _att_info["classification_confidence"] = _att_classify.get("confidence", 0.5)
                                            _att_info["summary"] = _att_classify.get("summary", "")
                                            _att_raw_fields = _att_classify.get("extracted_fields") or {}
                                            _att_info["extracted_fields"] = {k: v for k, v in _att_raw_fields.items() if v is not None and v != "null"}
                                            if _att_info["category"] in ("VEHICLE_DAMAGE", "ACCIDENT_SCENE"):
                                                _att_info["ai_analysis"] = _att_classify.get("damage_info")
                                            else:
                                                _att_info["ai_analysis"] = None
                                            _log.info(f"📎 AI classify attachment: {_eatt['filename']} -> category={_att_info['category']} fields={len(_att_info['extracted_fields'])}")
                                        except Exception as _att_vis_err:
                                            _log.warning(f"📎 AI classify failed for {_eatt['filename']} (non-blocking): {_att_vis_err}")
                                            _att_info["category"] = "OTHER"
                                            _att_info["extracted_fields"] = {}
                                            _att_info["classification_confidence"] = 0.0
                                    # Compress images and save thumbnail
                                    if _att_is_image:
                                        try:
                                            _att_thumb_name = f"{_att_uuid4().hex[:12]}_thumb.jpg"
                                            _att_thumb_bytes = _compress_image(_eatt["data"])
                                            (_att_upload_dir / _att_thumb_name).write_bytes(_att_thumb_bytes)
                                            _att_info["compressed_path"] = _att_thumb_name
                                            _att_info["compressed_size"] = len(_att_thumb_bytes)
                                        except Exception:
                                            pass
                                    # Collect extracted fields for merge into form_data
                                    _ef = _att_info.get("extracted_fields", {})
                                    if _ef:
                                        _att_cat_upper = (_att_info.get("category") or "").upper()
                                        # Fix 1: POLICE_REPORT vehicle fields belong to the
                                        # OPPOSING party (gegner), not the VN. Route them to
                                        # REAL KFZ Section 7 (Anspruchsteller) slots verified
                                        # against kfz_schadenmeldung.json. Delete VN-side keys
                                        # from _ef after remap to prevent VN slot poisoning.
                                        _police_report_remap = {
                                            "kennzeichen": "anspruch_kennzeichen",
                                            "fahrzeug": "anspruch_fabrikat",
                                            "halter": "anspruch_name",
                                        }
                                        if _att_cat_upper == "POLICE_REPORT":
                                            # CRITICAL: directly populate form_data.polizei_* fields
                                            # via explicit update (bypass complex merge pipeline)
                                            _direct_polizei = {}
                                            if _ef.get("aktenzeichen") or _ef.get("Aktenzeichen"):
                                                _direct_polizei["polizei_aktenzeichen"] = _ef.get("aktenzeichen") or _ef.get("Aktenzeichen")
                                                _direct_polizei["aktenzeichen"] = _direct_polizei["polizei_aktenzeichen"]
                                            if _ef.get("dienststelle") or _ef.get("Dienststelle"):
                                                _direct_polizei["polizei_dienststelle"] = _ef.get("dienststelle") or _ef.get("Dienststelle")
                                                _direct_polizei["dienststelle"] = _direct_polizei["polizei_dienststelle"]
                                            if _ef.get("unfallort") and not _ef.get("_skip_unfallort"):
                                                _direct_polizei.setdefault("schadenort_polizei", _ef.get("unfallort"))
                                            # Also auto-set polizei_aufnahme=Ja + polizeilich_aufgenommen=Ja
                                            _direct_polizei["polizei_aufnahme"] = "Ja"
                                            _direct_polizei["polizeilich_aufgenommen"] = "Ja"
                                            if _direct_polizei:
                                                _fd_pol_upd = {f"form_data.{k}": v for k, v in _direct_polizei.items()}
                                                try:
                                                    _fs_db.collection("form_submissions").document(_ov_sub_id).update(_fd_pol_upd)
                                                    _log.info(f"🚔 Direct polizei fields written: {list(_direct_polizei.keys())}")
                                                except Exception as _dp_err:
                                                    _log.warning(f"Direct polizei write failed: {_dp_err}")
                                            # fahrgestellnummer has no claimant slot —
                                            # merge into anspruch_fabrikat.
                                            _fin_val2 = _ef.get("fahrgestellnummer") or _ef.get("Fahrgestellnummer")
                                            _veh_val2 = _ef.get("fahrzeug") or _ef.get("Fahrzeug")
                                            if _fin_val2:
                                                _combo2 = f"{_veh_val2} (FIN: {_fin_val2})" if _veh_val2 else f"FIN: {_fin_val2}"
                                                if "anspruch_fabrikat" not in _att_extracted_fields_merged:
                                                    _att_extracted_fields_merged["anspruch_fabrikat"] = _combo2
                                            for _vn_key2 in ("fahrgestellnummer", "kennzeichen", "halter", "fahrzeug"):
                                                if _vn_key2 in _ef:
                                                    _v_pr2 = _ef.pop(_vn_key2, None)
                                                    if _v_pr2 and _vn_key2 in _police_report_remap:
                                                        _dest_pr2 = _police_report_remap[_vn_key2]
                                                        if _dest_pr2 not in _att_extracted_fields_merged:
                                                            _att_extracted_fields_merged[_dest_pr2] = _v_pr2
                                        # CRITICAL: For VEHICLE_ID / DOCUMENT_SCAN (Fahrzeugschein/Poliza),
                                        # fields belong to VN. Direct-write VN fields.
                                        if _att_cat_upper in ("VEHICLE_ID", "DOCUMENT_SCAN", "INSURANCE_DOC"):
                                            _direct_vn = {}
                                            if _ef.get("fahrgestellnummer"):
                                                _direct_vn["fahrgestellnummer"] = _ef["fahrgestellnummer"]
                                            if _ef.get("erstzulassung"):
                                                _direct_vn["erstzulassung"] = _ef["erstzulassung"]
                                            if _ef.get("versicherungsschein_nr"):
                                                _direct_vn.setdefault("versicherungsschein_nr", _ef["versicherungsschein_nr"])
                                            if _direct_vn:
                                                _fd_vn_upd = {f"form_data.{k}": v for k, v in _direct_vn.items()}
                                                try:
                                                    _fs_db.collection("form_submissions").document(_ov_sub_id).update(_fd_vn_upd)
                                                    _log.info(f"📇 Direct VEHICLE_ID/DOCUMENT_SCAN fields: {list(_direct_vn.keys())}")
                                                except Exception: pass
                                        for _efk, _efv in _ef.items():
                                            if not _efv: continue
                                            _dest_key = _efk
                                            if _dest_key not in _att_extracted_fields_merged:
                                                _att_extracted_fields_merged[_dest_key] = _efv
                                    # Remove None values for Firestore serialization
                                    _att_info = {k: v for k, v in _att_info.items() if v is not None}
                                    _fs_db.collection("form_submissions").document(_ov_sub_id).update({
                                        "attachments": _firestore_mod.ArrayUnion([_att_info])
                                    })
                                    _log.info(f"📎 Email attachment saved: {_eatt['filename']} ({_eatt['size']} bytes) -> {_att_path.name} for sub={_ov_sub_id}")
                                except Exception as _eatt_err:
                                    _log.warning(f"📎 Failed to save email attachment {_eatt['filename']}: {_eatt_err}")
                            # Merge extracted fields from attachments into form_data
                            # Smart cross-contamination protection:
                            #  - If form_data has NO identity yet → merge all fields (first case has priority)
                            #  - If form_data already has identity fields with DIFFERENT values → skip those
                            #  - Non-identity fields (kennzeichen, unfallhergang, etc.) always merge if absent
                            if _att_extracted_fields_merged:
                                _existing_fd = _fs_db.collection("form_submissions").document(_ov_sub_id).get()
                                _current_fd = (_existing_fd.to_dict() or {}).get("form_data", {}) if _existing_fd.exists else {}
                                _identity_fields = {"name", "vn_name", "versicherungsnehmer", "halter",
                                    "strasse", "vn_adresse", "plz_ort", "vn_plz_ort", "telefon", "vn_kontakt",
                                    "email", "vn_email", "kontaktperson", "fahrer", "fahrzeug",
                                    "kennzeichen", "vn_kennzeichen", "geschaedigter", "anspruchsteller_name"}
                                # Field-name synonyms (extracted -> canonical form field)
                                _att_to_form = {
                                    "name": "vn_name", "versicherungsnehmer": "vn_name", "halter": "vn_name",
                                    "strasse": "vn_adresse", "adresse": "vn_adresse",
                                    "plz_ort": "vn_plz_ort",
                                    "telefon": "vn_kontakt", "tel": "vn_kontakt",
                                    "email": "vn_email", "e-mail": "vn_email",
                                    "kennzeichen": "vn_kennzeichen",
                                    "unfallort": "schadenort",
                                    "unfalldatum": "schadentag_uhrzeit",
                                    "schadendatum": "schadentag_uhrzeit",
                                }
                                # Check if current form_data has any identity established
                                _has_identity = any(_current_fd.get(f) for f in ("vn_name", "vn_email", "vn_kennzeichen"))
                                # Template-specific aliases for KFZ/HPF/MB (generic → template field name)
                                _template_aliases = {
                                    "schadenshoehe": ["anspruch_schadenshoehe", "kasko_schadenshoehe"],
                                    "schadenhoehe": ["anspruch_schadenshoehe", "kasko_schadenshoehe"],
                                    "aktenzeichen": ["polizei_aktenzeichen"],
                                    "dienststelle": ["polizei_dienststelle"],
                                    "polizei_dienststelle": ["dienststelle"],
                                    "anspruchsteller_name": ["anspruch_name"],
                                    "anspruchsteller_fahrzeug": ["anspruch_fabrikat"],
                                    "anspruchsteller_strasse": ["anspruch_strasse"],
                                    "anspruchsteller_plz_ort": ["anspruch_plz_ort"],
                                    "anspruchsteller_telefon": ["anspruch_telefon"],
                                    "anspruchsteller_email": ["anspruch_email"],
                                    "anspruchsteller_kennzeichen": ["anspruch_kennzeichen"],
                                }
                                _new_fields = {}
                                for _mfk, _mfv in _att_extracted_fields_merged.items():
                                    if not _mfv: continue
                                    # Map synonym to canonical form field
                                    _target_key = _att_to_form.get(_mfk.lower(), _mfk)
                                    # Skip if canonical field already filled in current form_data
                                    if _current_fd.get(_target_key): continue
                                    # Identity field handling
                                    if _target_key in _identity_fields and _has_identity:
                                        _log.info(f"📎 Skipping identity field {_target_key}={_mfv} (identity already established)")
                                        continue
                                    _new_fields[_target_key] = _mfv
                                    # Also write to template-specific alias keys if empty
                                    for _alias_tgt in _template_aliases.get(_target_key.lower(), []):
                                        if not _current_fd.get(_alias_tgt) and _alias_tgt not in _new_fields:
                                            _new_fields[_alias_tgt] = _mfv
                                if _new_fields:
                                    _fd_update = {f"form_data.{k}": v for k, v in _new_fields.items()}
                                    _fs_db.collection("form_submissions").document(_ov_sub_id).update(_fd_update)
                                    # Recalculate completeness after merge
                                    try:
                                        _merged_fd = dict(_current_fd or {}); _merged_fd.update(_new_fields)
                                        _ov_tpl_id = _ov_result.get('template_id','') or (_existing_fd.to_dict() or {}).get('template_id','')
                                        _recalc = _calc_completeness(_merged_fd, _ov_tpl_id)
                                        _fs_db.collection("form_submissions").document(_ov_sub_id).update({"completeness_pct": _recalc})
                                    except Exception:
                                        pass
                                    _log.info(f"📎 Merged {len(_new_fields)} extracted fields from attachments into form_data for sub={_ov_sub_id}: {list(_new_fields.keys())}")
                            # Fix 2: MB Section 8 attachment→slot binding
                            # If template is Maschinenbruch, populate foto_daune / costuri_reparatie
                            # slots with the filename of a matching attachment when empty.
                            try:
                                _ov_tpl_id_bind = _ov_result.get('template_id','') or ''
                                if _ov_tpl_id_bind == 'tpl-maschinenbruch' and _email_attachments:
                                    _fd_now_snap = _fs_db.collection("form_submissions").document(_ov_sub_id).get()
                                    _fd_now = (_fd_now_snap.to_dict() or {}).get("form_data", {}) if _fd_now_snap.exists else {}
                                    _sub_atts_now = (_fd_now_snap.to_dict() or {}).get("attachments", []) if _fd_now_snap.exists else []
                                    _bind_updates = {}
                                    _kv_match = None
                                    _foto_match = None
                                    for _a in (_sub_atts_now or []):
                                        _cat = (_a.get("category") or "").upper()
                                        _fn_l = (_a.get("filename") or "").lower()
                                        if _kv_match is None and (_cat == "REPAIR_ESTIMATE" or "repair" in _cat.lower() or _re_mod.search(r'kosten|rechnung|estimate', _fn_l)):
                                            _kv_match = _a.get("filename") or _a.get("saved_as") or ""
                                        if _foto_match is None and (_cat in ("VEHICLE_DAMAGE","SCHADEN_FOTO") or _re_mod.search(r'schaden|damage|foto|bild', _fn_l)):
                                            _foto_match = _a.get("filename") or _a.get("saved_as") or ""
                                    if _kv_match and not _fd_now.get("costuri_reparatie"):
                                        _bind_updates["costuri_reparatie"] = f"beigefuegt: {_kv_match}"
                                    if _foto_match and not _fd_now.get("foto_daune"):
                                        _bind_updates["foto_daune"] = f"beigefuegt: {_foto_match}"
                                    if _bind_updates:
                                        _bind_upd = {f"form_data.{k}": v for k, v in _bind_updates.items()}
                                        _fs_db.collection("form_submissions").document(_ov_sub_id).update(_bind_upd)
                                        _log.info(f"📎 MB Section 8 bound: {list(_bind_updates.keys())}")
                            except Exception as _bind_err:
                                _log.warning(f"MB Section 8 binding failed (non-blocking): {_bind_err}")
                    processed.append({"cmd": "OPENVIVA_PREFILL", "ref": _ov_result.get("ticket_code",""), "result": _ov_result})
                except Exception as _ov_err:
                    _log.warning(f"OpenVIVA email processing failed: {_ov_err}")
                    processed.append({"cmd": "OPENVIVA_PREFILL", "ref": "", "result": f"error: {_ov_err}"})
                mail.store(msg_id, "+FLAGS", "\\Seen"); _fs_set("processed_emails", _msg_uid, {"processed_at": __import__("datetime").datetime.utcnow().isoformat()}, merge=False)
                pass  # Firestore writes are immediate
                continue

            # Parse CMD from body — check NON-QUOTED lines first (operator types CMD as reply)
            # Filter out quoted lines (starting with >) to find the actual reply text
            _non_quoted = "\n".join(
                line for line in (_body or "").split("\n")
                if not line.strip().startswith(">") and not line.strip().startswith("On ")
            )
            _cmd_pattern = _re_mod.compile(r'(CMD[1-7])\s*((?:AKT|FRM)-[\w-]+)?', _re_mod.IGNORECASE)
            _match = _cmd_pattern.search(_non_quoted) or _cmd_pattern.search(_subject)
            if not _match:
                # Not a CMD email — mark as read to avoid re-processing
                mail.store(msg_id, "+FLAGS", "\\Seen"); _fs_set("processed_emails", _msg_uid, {"processed_at": __import__("datetime").datetime.utcnow().isoformat()}, merge=False)
                continue

            cmd_code = _match.group(1).upper()
            cmd_ref = (_match.group(2) or "").strip()

            # If no ref in CMD text, try to extract from email subject (Re: [AKT-2026-00001] ...)
            if not cmd_ref:
                _ref_in_subject = _re_mod.search(r'\[(AKT-[\w-]+)\]', _subject)
                if not _ref_in_subject:
                    _ref_in_subject = _re_mod.search(r'\[(FRM-[\w-]+)\]', _subject)
                if _ref_in_subject:
                    cmd_ref = _ref_in_subject.group(1)

            _log.info(f"📧 CMD from inbox: {cmd_code} {cmd_ref} from {sender_email}")

            # For CMD6: extract body_text (questions in quotes) from non-quoted reply
            _cmd_body_text = ""
            if cmd_code == "CMD6":
                _cmd_body_text = _non_quoted.strip()

            # Execute the command via existing endpoint logic (direct call)
            try:
                _result = await execute_command({
                    "command": cmd_code,
                    "ref": cmd_ref,
                    "reply_to": sender_email,
                    "body_text": _cmd_body_text
                })
            except Exception as _e:
                _result = {"ok": False, "message": f"Execution error: {_e}"}

            processed.append({
                "from": sender_email,
                "cmd": cmd_code,
                "ref": cmd_ref,
                "result": _result.get("message", "")[:200]
            })

            # Wiki: log CMD execution to Activity Log
            try:
                _wiki_append_log(
                    "Activity Log",
                    f"{cmd_code} {cmd_ref} from {sender_email} — {_result.get('message', '')[:80]}",
                    tags=["activity", "cmd", "auto"],
                )
            except Exception:
                pass

            # Mark as read + track as processed
            mail.store(msg_id, "+FLAGS", "\\Seen"); _fs_set("processed_emails", _msg_uid, {"processed_at": __import__("datetime").datetime.utcnow().isoformat()}, merge=False)
            _fs_set("processed_emails", _msg_uid, {"processed_at": __import__("datetime").datetime.utcnow().isoformat()}, merge=False)
            pass  # Firestore writes are immediate

        pass  # Firestore: no connection to close
        mail.logout()
    except Exception as e:
        _log.error(f"IMAP poll error: {e}")
        return {"ok": False, "message": f"IMAP error: {str(e)}"}

    # Show recently processed cases even if this poll found 0 new
    _recent_cases = []
    try:
        _recent = _cached_fs_all("form_submissions")
        _recent.sort(key=lambda x: x.get("created_at", ""), reverse=True)
        for r in _recent[:5]:
            _recent_cases.append({"ticket": r.get("ticket_code", ""), "client": r.get("client_name", ""), "created": r.get("created_at", "")[:16]})
    except: pass
    _all_uids = [m.decode() if isinstance(m, bytes) else str(m) for m in _msg_ids[0].split()[-20:]] if _msg_ids and _msg_ids[0] else []
    return {
        "ok": True,
        "processed": len(processed),
        "already_seen": len([u for u in _all_uids if u in _already_processed]),
        "recent_cases": _recent_cases,
        "details": processed
    }


# ── Escalation: check overdue submissions ──────────────────────────────────
@app.post("/api/forms/check-overdue")
async def api_check_overdue():
    """Check for overdue submissions and escalate to broker.
    Finds submissions where follow_up_at < now AND status not in (forwarded, closed, validated).
    Sends escalation email to broker for each.
    """
    from datetime import datetime as _dt_ov
    from datetime import datetime as _dt_ov_now
    _now_iso = _dt_ov_now.utcnow().isoformat()
    _all_subs_ov = _fs_all("form_submissions", limit=2000)
    _overdue = [s for s in _all_subs_ov
                if s.get("follow_up_at") and s["follow_up_at"] < _now_iso
                and s.get("status") not in ("forwarded", "closed", "validated")]
    _overdue.sort(key=lambda x: x.get("follow_up_at", ""))
    _overdue = _overdue[:20]
    escalated = []
    _operator = os.environ.get("OPERATOR_EMAIL", os.environ.get("SMTP_USER", ""))
    for row in _overdue:
        r = dict(row)
        _days = ((_dt_ov.utcnow() - _dt_ov.fromisoformat(r["follow_up_at"].replace("Z",""))).days) if r.get("follow_up_at") else 0
        _phone_info = f"<br>📞 <strong>Telefon:</strong> <a href='tel:{r['client_phone']}'>{r['client_phone']}</a>" if r.get("client_phone") else ""
        _host = os.environ.get("APP_HOST", "")
        _form_url = f"{_host}/forms/{r['template_id']}?sub={r['id']}" if _host else ""
        _esc_html = f"""<div style="font-family:'Segoe UI',sans-serif;max-width:600px;margin:0 auto">
          <div style="background:linear-gradient(135deg,#ef4444,#dc2626);padding:24px;border-radius:12px 12px 0 0;text-align:center">
            <h2 style="color:white;margin:0">⚠️ Eskalation — Kunde antwortet nicht</h2>
          </div>
          <div style="background:#fff;padding:24px;border:1px solid #e5e7eb;border-radius:0 0 12px 12px">
            <p><strong>Aktenzeichen:</strong> {r.get('ticket_code','')}</p>
            <p><strong>Kunde:</strong> {r['client_name']} ({r.get('client_email','')}){_phone_info}</p>
            <p><strong>Vollständigkeit:</strong> {r.get('completeness_pct',0)}%</p>
            <p><strong>Überfällig seit:</strong> {_days} Tagen (Frist: {r.get('follow_up_at','')[:10]})</p>
            <p><strong>Erinnerungen gesendet:</strong> {r.get('reminder_count',0)}</p>
            <div style="background:#fef2f2;border:1px solid #fecaca;border-radius:8px;padding:16px;margin:16px 0">
              <p style="color:#991b1b;font-weight:600;margin:0">Bitte rufen Sie den Kunden an und bitten Sie um Vervollständigung des Formulars.</p>
            </div>
            {f'<p><a href="{_form_url}" style="background:#6366f1;color:white;padding:10px 24px;border-radius:8px;text-decoration:none;font-weight:600">Formular ansehen →</a></p>' if _form_url else ''}
            {_cmd_footer_html(r.get('ticket_code',''))}
          </div>
        </div>"""
        if _operator:
            _send_email_html([_operator], f"⚠️ Eskalation: {r.get('ticket_code','')} — {r['client_name']} antwortet nicht", _esc_html)
        # Update follow_up to +3 days to avoid spamming
        from datetime import timedelta as _ov_td
        _fs_set("form_submissions", r["id"], {
            "follow_up_at": (__import__("datetime").datetime.utcnow() + _ov_td(days=3)).isoformat()
        }, merge=True)
        escalated.append({"ticket_code": r.get("ticket_code",""), "client": r.get("client_name","?"), "days_overdue": _days})
    return {"ok": True, "escalated": len(escalated), "details": escalated}


# ── Status Report Cron (every 4 days) ──────────────────────────────────────

@app.post("/api/forms/status-report")
async def api_form_status_report():
    """Generate comprehensive status report with engagement data.
    Sent to operator every 4 days via cron. Includes CMD codes in footer.
    """
    from datetime import datetime as _dt
    _all_subs_rpt = _fs_all("form_submissions", limit=2000)
    rows = [s for s in _all_subs_rpt if s.get("status") not in ("closed",)]
    rows.sort(key=lambda x: x.get("created_at", ""), reverse=True)

    # Build HTML report
    _lines = []
    _urgent = []
    for r in rows:
        s = dict(r)
        pct = s.get("completeness_pct") or 0
        ref = s.get("reference_number", "?")
        name = s.get("client_name", "?")
        status = s.get("status", "?")

        # Engagement emoji
        if s.get("form_viewed_at"):
            eng = "🟡 geöffnet"
        elif s.get("email_opened_at"):
            eng = "🟠 Email gesehen"
        else:
            eng = "🔴 kein Kontakt"

        if status == "forwarded":
            emoji = "🟢"
            eng = "✅ weitergeleitet"
        elif pct >= 80:
            emoji = "🟢"
        elif pct >= 40:
            emoji = "🟡"
        else:
            emoji = "🔴"

        line = f"{emoji} {ref} — {name} — {pct}% — {eng} — Erinnerungen: {s.get('reminder_count', 0)}/3"
        _lines.append(line)

        # Flag urgent cases (no contact, >4 days old)
        if not s.get("email_opened_at") and not s.get("form_viewed_at") and status not in ("forwarded", "completed"):
            _urgent.append(f"→ {name}: Anruf empfohlen (kein Fortschritt)")

    _host = os.environ.get("APP_HOST", "https://alex-insurance-broker-426485075291.europe-west3.run.app")
    _report_html = f"""
    <div style="font-family:'Segoe UI',sans-serif;max-width:700px;margin:0 auto">
      <div style="background:linear-gradient(135deg,#1e40af,#3b82f6);padding:28px;border-radius:12px 12px 0 0;text-align:center">
        <h1 style="color:white;margin:0;font-size:22px">📊 Statusbericht — Formulare</h1>
        <p style="color:rgba(255,255,255,0.8);margin:8px 0 0">{_dt.utcnow().strftime('%d.%m.%Y %H:%M')} UTC</p>
      </div>
      <div style="background:#fff;padding:24px;border:1px solid #e5e7eb">
        <h3 style="color:#1e293b;border-bottom:2px solid #e5e7eb;padding-bottom:8px">Alle Fälle ({len(rows)})</h3>
        <pre style="background:#f8fafc;padding:16px;border-radius:8px;font-size:13px;line-height:1.8;white-space:pre-wrap">{'&#10;'.join(_lines) if _lines else 'Keine Fälle.'}</pre>
        {'<h3 style="color:#dc2626;margin-top:20px">⚠️ Aktionen empfohlen</h3><ul style="color:#dc2626">' + "".join(f"<li>{u}</li>" for u in _urgent) + '</ul>' if _urgent else ''}
        {_cmd_footer_html()}
      </div>
      <div style="background:#f8fafc;padding:12px;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 12px 12px;text-align:center">
        <a href="{_host}/dashboard/forms" style="color:#3b82f6;font-size:13px">Dashboard öffnen →</a>
        <span style="color:#9ca3af;font-size:12px;margin-left:12px">Alex — TPSH Versicherungsmakler GmbH</span>
      </div>
    </div>"""

    # Send to operator
    _operator = os.environ.get("OPERATOR_EMAIL", os.environ.get("SMTP_USER", ""))
    email_sent = False
    if _operator:
        email_sent = _send_email_html([_operator],
            f"📊 Statusbericht Formulare — {_dt.utcnow().strftime('%d.%m.%Y')}",
            _report_html)

    return {
        "ok": True,
        "total": len(rows),
        "urgent": len(_urgent),
        "email_sent": email_sent,
        "report_to": _operator
    }


# ── Integrations Status API ───────────────────────────────────────────────

@app.get("/api/integrations/status")
async def integrations_status():
    """Get status of all connectors in one call — for the Interconectare dashboard."""

    status = {}

    # 1. SMTP Email
    smtp_user = os.environ.get("SMTP_USER", "")
    smtp_host = os.environ.get("SMTP_HOST", "smtp.gmail.com")
    status["smtp"] = {
        "name": "Email SMTP",
        "status": "connected" if smtp_user else "not_configured",
        "host": smtp_host,
        "user": smtp_user[:20] + "..." if len(smtp_user) > 20 else smtp_user,
    }

    # 1b. IMAP Inbox (CMD polling)
    imap_host = os.environ.get("IMAP_HOST", "imap.gmail.com")
    imap_user = os.environ.get("IMAP_USER", os.environ.get("SMTP_USER", ""))
    poll_interval = os.environ.get("INBOX_POLL_INTERVAL", "30")
    status["imap"] = {
        "name": "IMAP Inbox (CMD Polling)",
        "status": "connected" if imap_user else "not_configured",
        "host": imap_host,
        "user": imap_user[:20] + "..." if len(imap_user) > 20 else imap_user,
        "hint": f"Polling alle {poll_interval}s — CMD1-CMD6 auto-reply",
    }

    # 2. Oracle DB
    _ora_auto = _oracle_auto_sync_enabled()
    try:
        ora_status = await oracle_status()
        status["oracle"] = {
            "name": "Oracle DB",
            "status": ora_status.get("status", "disconnected"),
            "dsn": _ORACLE_CONFIG["dsn"],
            "tables": len(ora_status.get("tables", [])),
            "version": ora_status.get("version", "N/A"),
            "auto_sync": _ora_auto,
        }
    except Exception:
        status["oracle"] = {"name": "Oracle DB", "status": "disconnected", "dsn": _ORACLE_CONFIG["dsn"], "auto_sync": _ora_auto}

    # 3. OpenVIVA Email
    ov_email = os.environ.get("OPENVIVA_EMAIL", "")
    status["openviva_email"] = {
        "name": "OpenVIVA Email",
        "status": "configured" if ov_email else "not_configured",
        "email": ov_email or "Nicht konfiguriert — setze OPENVIVA_EMAIL",
    }

    # 4. OpenVIVA Oracle
    try:
        ov_status = await openviva_status()
        status["openviva_oracle"] = {
            "name": "OpenVIVA Oracle",
            "status": ov_status.get("status", "not_configured"),
            "mode": ov_status.get("mode", "N/A"),
            "dsn": _OPENVIVA_ORACLE_CONFIG["dsn"]
        }
    except Exception:
        status["openviva_oracle"] = {"name": "OpenVIVA Oracle", "status": "not_configured"}

    # 5. BiPRO / b-OX
    status["bipro"] = {
        "name": "BiPRO / b-OX",
        "status": "pending",
        "hint": "Warte auf IHK-Registrierungsnummer von Angelo",
        "local_tools": 5,
        "box_tools": 5,
        "active_tools": 5
    }

    # 6. WhatsApp / n8n
    n8n_url = os.environ.get("N8N_WHATSAPP_WEBHOOK", "")
    status["whatsapp"] = {
        "name": "WhatsApp / n8n",
        "status": "configured" if n8n_url else "not_configured",
        "webhook": n8n_url[:40] + "..." if len(n8n_url) > 40 else n8n_url
    }

    # 7. SMTP Profiles
    try:
        profiles = _fs_all("smtp_profiles", limit=50)
        for p in profiles: p["id"] = p.pop("_id", p.get("id"))
        status["smtp_profiles"] = profiles
    except Exception:
        status["smtp_profiles"] = []

    # 8. Recent sync log
    try:
        logs = _fs_all("integration_sync_log", limit=500)
        status["sync_log"] = [dict(l) for l in logs]
    except Exception:
        status["sync_log"] = []

    return status


