@app.post("/api/integrations/test-email")
async def test_integration_email(body: dict):
    """Send a test email to verify SMTP configuration."""
    to = body.get("to", os.environ.get("OPERATOR_EMAIL", os.environ.get("SMTP_USER", "")))
    if not to:
        return {"ok": False, "error": "No recipient specified"}
    ok = _send_email_html([to], "🧪 Alex — Test Email",
        """<div style="font-family:'Segoe UI',sans-serif;max-width:500px;margin:0 auto;padding:20px">
          <div style="background:linear-gradient(135deg,#10b981,#059669);padding:20px;border-radius:12px 12px 0 0;text-align:center">
            <h2 style="color:white;margin:0">✅ Email funktioniert!</h2>
          </div>
          <div style="background:#fff;padding:20px;border:1px solid #e5e7eb;border-radius:0 0 12px 12px">
            <p>Wenn Sie diese Email sehen, ist die SMTP-Konfiguration korrekt.</p>
            <p style="font-size:12px;color:#9ca3af">Alex — TPSH Versicherungsmakler GmbH</p>
          </div>
        </div>""")
    # Log
    try:
        from datetime import datetime as _dt
        _fs_add("integration_sync_log", {
            "connector": "smtp", "action": "test_email", "reference": "TEST",
            "details": f"Sent to {to}", "status": "ok" if ok else "failed",
            "created_at": _dt.utcnow().isoformat()
        });
    except Exception:
        pass
    return {"ok": ok, "sent_to": to}


