# ── Background inbox polling — auto-reply to CMD emails ───────────────────
# Polls Gmail IMAP every 2 minutes for operator CMD replies.
# When Ioana replies with CMD1/CMD3/etc, Alex auto-executes and replies.

async def _inbox_poll_loop():
    """Background loop: poll inbox every 120s for CMD emails.
    Portable: uses IMAP_HOST env var — works with Gmail, Outlook, Exchange.
    """
    import asyncio as _aio_poll
    await _aio_poll.sleep(120)  # wait 120s after startup before first poll
    _poll_interval = int(os.environ.get("INBOX_POLL_INTERVAL", "120"))
    while True:
        try:
            result = await poll_inbox_for_commands()
            processed = result.get("processed", 0) if isinstance(result, dict) else 0
            if processed > 0:
                _log.info(f"📧 Inbox poll: {processed} CMD(s) processed")
        except Exception as _poll_err:
            _log.warning(f"Inbox poll error: {_poll_err}")
        await _aio_poll.sleep(_poll_interval)

@app.on_event("startup")
async def _start_inbox_polling():
    import asyncio as _aio_start
    _aio_start.create_task(_inbox_poll_loop())
    _log.info("📧 Inbox CMD polling started (every 2 min)")


# ── 1. Equipment Excel Import ────────────────────────────────────────────────

@app.post("/api/equipment/import-excel")
async def api_import_equipment_excel(file: UploadFile = FastFile(...)):
    """Import equipment list from Excel file. Columns: serial_no, machine_type, brand,
    client_name, client_company, delivery_date, insured_months, max_hours_year, current_hours, status."""
    from datetime import datetime as _dt, timedelta as _td
    from openpyxl import load_workbook
    import io
    contents = await file.read()
    wb = load_workbook(io.BytesIO(contents), read_only=True)
    ws = wb.active
    rows = list(ws.iter_rows(min_row=1, values_only=True))
    if not rows:
        return {"ok": False, "error": "Empty spreadsheet"}
    # Detect header row
    header = [str(c).strip().lower().replace(" ", "_") if c else f"col_{i}" for i, c in enumerate(rows[0])]
    # Map common column name variants
    col_map = {}
    for i, h in enumerate(header):
        if "serial" in h or "serie" in h or "seriennr" in h:
            col_map["serial_no"] = i
        elif "type" in h or "typ" in h or "machine" in h or "maschi" in h or "utilaj" in h:
            col_map["machine_type"] = i
        elif "brand" in h or "marke" in h or "marca" in h or "hersteller" in h:
            col_map["brand"] = i
        elif "client" in h or "kunde" in h or "name" in h or "proprietar" in h:
            col_map["client_name"] = i
        elif "company" in h or "firma" in h or "societate" in h:
            col_map["client_company"] = i
        elif "delivery" in h or "lieferung" in h or "livrare" in h or "datum" in h or "date" in h:
            col_map["delivery_date"] = i
        elif "insured_months" in h or "versichert" in h or "luni" in h or "monate" in h:
            col_map["insured_months"] = i
        elif "max_hours" in h or "max_ore" in h or "maxstunden" in h:
            col_map["max_hours_year"] = i
        elif "current_hours" in h or "ore_curente" in h or "betriebsstunden" in h or "hours" in h or "ore" in h:
            col_map["current_hours"] = i
        elif "status" in h or "stare" in h:
            col_map["status"] = i
        elif "value" in h or "wert" in h or "valoare" in h or "insured" in h:
            col_map["insured_value_eur"] = i
        elif "contract" in h or "vertrag" in h:
            col_map["contract_no"] = i
        elif "deductible" in h or "selbstbeteiligung" in h or "fransize" in h:
            col_map["deductible_eur"] = i
        elif "address" in h or "adresse" in h or "adresa" in h:
            col_map["address"] = i
        elif "category" in h or "kategorie" in h or "categorie" in h:
            col_map["category"] = i
    if "serial_no" not in col_map:
        return {"ok": False, "error": f"No serial number column found. Headers: {header}"}
    now = _dt.utcnow()
    imported = 0
    updated = 0
    skipped = 0
    errors = []
    for row_idx, row in enumerate(rows[1:], start=2):
        try:
            serial = str(row[col_map["serial_no"]]).strip() if row[col_map["serial_no"]] else None
            if not serial:
                skipped += 1
                continue
            machine_type = str(row[col_map.get("machine_type", 0)]).strip() if col_map.get("machine_type") is not None and row[col_map["machine_type"]] else "Unknown"
            brand = str(row[col_map.get("brand", 0)]).strip() if col_map.get("brand") is not None and row[col_map.get("brand", 0)] else ""
            client_name = str(row[col_map.get("client_name", 0)]).strip() if col_map.get("client_name") is not None and row[col_map.get("client_name", 0)] else ""
            client_company = str(row[col_map.get("client_company", 0)]).strip() if col_map.get("client_company") is not None and row[col_map.get("client_company", 0)] else ""
            # Parse delivery date
            dd_raw = row[col_map.get("delivery_date", 0)] if col_map.get("delivery_date") is not None else None
            delivery_date = ""
            if dd_raw:
                if isinstance(dd_raw, _dt):
                    delivery_date = dd_raw.strftime("%Y-%m-%d")
                else:
                    for fmt in ("%Y-%m-%d", "%d.%m.%Y", "%d/%m/%Y", "%m/%d/%Y"):
                        try:
                            delivery_date = _dt.strptime(str(dd_raw).strip(), fmt).strftime("%Y-%m-%d")
                            break
                        except ValueError:
                            continue
            insured_months = int(row[col_map.get("insured_months", 0)] or 36) if col_map.get("insured_months") is not None else 36
            max_hours = int(row[col_map.get("max_hours_year", 0)] or 800) if col_map.get("max_hours_year") is not None else 800
            current_hours = int(row[col_map.get("current_hours", 0)] or 0) if col_map.get("current_hours") is not None else 0
            status_raw = str(row[col_map.get("status", 0)]).strip().lower() if col_map.get("status") is not None and row[col_map.get("status", 0)] else "active"
            insured_value = float(row[col_map.get("insured_value_eur", 0)] or 0) if col_map.get("insured_value_eur") is not None else 0
            contract_no = str(row[col_map.get("contract_no", 0)]).strip() if col_map.get("contract_no") is not None and row[col_map.get("contract_no", 0)] else ""
            deductible = float(row[col_map.get("deductible_eur", 0)] or 250) if col_map.get("deductible_eur") is not None else 250
            address = str(row[col_map.get("address", 0)]).strip() if col_map.get("address") is not None and row[col_map.get("address", 0)] else ""
            category = str(row[col_map.get("category", 0)]).strip() if col_map.get("category") is not None and row[col_map.get("category", 0)] else "machinery"
            # Auto-detect expired insurance
            if delivery_date and status_raw in ("active", "activ", "aktiv"):
                try:
                    d_date = _dt.strptime(delivery_date, "%Y-%m-%d")
                    insured_end = d_date + _td(days=insured_months * 30)
                    if insured_end < now:
                        status_raw = "expired"
                except Exception:
                    pass
            # Map status
            status = "active" if status_raw in ("active", "activ", "aktiv", "yes", "da", "ja") else \
                     "expired" if status_raw in ("expired", "expirat", "abgelaufen") else \
                     "suspended" if status_raw in ("suspended", "suspendat", "gesperrt", "neplatit", "unpaid") else status_raw
            # Upsert
            eq_id = f"EQ-{serial.replace(' ', '').upper()[-8:]}"
            eq_data = {
                    "machine_type": machine_type, "brand": brand, "client_name": client_name,
                    "client_company": client_company, "delivery_date": delivery_date,
                    "insured_months": insured_months, "max_hours_year": max_hours,
                    "current_hours": current_hours, "status": status,
                    "insured_value_eur": insured_value, "contract_no": contract_no,
                    "deductible_eur": deductible, "address": address, "category": category,
                }
            existing = (_fs_query("equipment", filters=[("serial_no", "==", serial)], limit=1) or [None])[0]
            if existing:
                _fs_update("equipment", existing["_id"], eq_data)
                updated += 1
            else:
                eq_data["serial_no"] = serial
                _fs_set("equipment", eq_id, eq_data, merge=False)
                imported += 1
        except Exception as e:
            errors.append(f"Row {row_idx}: {str(e)[:80]}")
            skipped += 1
    wb.close()
    emit_hook("equipment.excel_imported", f"Excel import: {imported} new, {updated} updated, {skipped} skipped",
              entity_type="equipment", entity_id="batch", tags=["equipment", "import", "excel"], relevance_score=7)
    return {"ok": True, "imported": imported, "updated": updated, "skipped": skipped,
            "errors": errors[:10], "total_rows": len(rows) - 1}


# ── 2. Photo Analysis with Claude Vision ────────────────────────────────────

