async def api_analyze_claim_photo(claim_id: str, file: UploadFile = FastFile(...), photo_type: str = "general"):
    """Analyze a claim photo with Claude Vision. photo_type: nameplate, hours_meter, damage, general."""
    import anthropic
    contents = await file.read()
    b64_data = _b64.b64encode(contents).decode()
