# ── 3. Insurer Response Parser (German) ─────────────────────────────────────

@app.post("/api/claims/{claim_id}/insurer-response")
async def api_parse_insurer_response(claim_id: str, request: _Request):
    """Parse insurer response (German text) using Claude AI. Extracts: response_type, conditions, approved amount."""
    import anthropic
    body = await request.json()
    response_text = body.get("text", "")
    if not response_text:
        return {"ok": False, "error": "text is required (German insurer response)"}
    client = anthropic.Anthropic(api_key=os.environ.get("ANTHROPIC_API_KEY", ""))
    msg = client.messages.create(
        model="claude-sonnet-4-20250514",
        max_tokens=2048,
        messages=[{"role": "user", "content": f"""Analyze this German insurance company response for a machinery damage claim.

Response text:
\"\"\"{response_text}\"\"\"

Classify and extract information as JSON:
{{
  "response_type": "approved|conditional|rejected|waiting_invoice|information_request",
  "summary": "brief summary in English",
  "summary_ro": "brief summary in Romanian",
  "approved_amount_eur": 0,
  "conditions": [
    {{"item": "part/position name", "pct": 30, "reason": "reason for deduction (e.g. wear, age)", "reason_ro": "reason in Romanian"}}
  ],
  "waiting_for": "what they are waiting for, if applicable",
  "deadline": "any mentioned deadline",
  "contact_person": "insurer contact if mentioned",
  "reference_number": "insurer reference/Aktenzeichen if mentioned"
}}

For response_type:
- "approved": full approval, no deductions
- "conditional": approved with deductions/conditions (30% wear, excluded parts, etc.)
- "rejected": claim denied
- "waiting_invoice": insurer needs final invoice before deciding
- "information_request": insurer needs more information

Extract ALL conditions/deductions mentioned. Common patterns:
- "Abzug X% wegen Verschleiss/Abnutzung" → wear deduction
- "Position X wird nicht anerkannt" → excluded item
- "Selbstbeteiligung" → deductible
- "Restwert" → salvage value

Return ONLY valid JSON."""}]
    )
    text = msg.content[0].text
    if "```json" in text:
        text = text.split("```json")[1].split("```")[0]
    elif "```" in text:
        text = text.split("```")[1].split("```")[0]
    try:
        parsed = json.loads(text.strip())
    except json.JSONDecodeError:
        parsed = {"response_type": "unknown", "raw": text}
    # Save to claim
    claim = _fs_get("claims", claim_id)
    if claim:
        claim_d = dict(claim)
        note = f"\n[Insurer Response] Type: {parsed.get('response_type', '?')}, Summary: {parsed.get('summary', '')}"
        _existing_claim = _fs_get("claims", claim_id)
        _fs_update("claims", claim_id, {
            "notes": ((_existing_claim or {}).get("notes") or "") + note,
            "insurer_response_type": parsed.get("response_type", "unknown"),
            "updated_at": __import__("datetime").datetime.utcnow().isoformat()
        })
        # If conditional → auto-populate deductions in settlement
        if parsed.get("response_type") == "conditional" and parsed.get("conditions"):
            _fs_update("claims", claim_id, {
                "deductions_json": json.dumps(parsed["conditions"], ensure_ascii=False),
                "approved_amount_eur": parsed.get("approved_amount_eur", 0)
            })
        # Auto-advance to step 10 (Settlement Calculation)
        current_step = claim_d.get("claim_step", 0) or 0
        if current_step == 9:  # Waiting Response
            _fs_update("claims", claim_id, {"claim_step": 10, "step_updated_at": __import__("datetime").datetime.utcnow().isoformat()})
    emit_hook("claim.insurer_response_parsed", f"Claim {claim_id}: insurer response type={parsed.get('response_type', '?')}",
              entity_type="claim", entity_id=claim_id, tags=["claim", "insurer", "response"], relevance_score=8)
    return {"ok": True, "claim_id": claim_id, "parsed": parsed}


# ── 4. Claim Follow-up Cron (14-day insurer reminder) ───────────────────────

@app.post("/api/cron/claim-followup")
async def api_cron_claim_followup():
    """Check claims at step 9 (Waiting Response). If >14 days without response, notify broker."""
    from datetime import datetime as _dt, timedelta as _td
    all_open = _fs_query("claims", filters=[("status", "==", "open")], limit=500)
    from datetime import timedelta as _td_fu
    _14days_ago = (__import__("datetime").datetime.utcnow() - _td_fu(days=14)).isoformat()
    overdue_claims = []
    for c in all_open:
        if c.get("claim_step") == 9 and (c.get("step_updated_at", "") or "") < _14days_ago:
            eq = _fs_get("equipment", c.get("equipment_id", "")) if c.get("equipment_id") else {}
            c["machine_type"] = (eq or {}).get("machine_type")
            c["serial_no"] = (eq or {}).get("serial_no")
            c["eq_client"] = (eq or {}).get("client_name")
            overdue_claims.append(c)
    if not overdue_claims:
        return {"ok": True, "message": "No overdue claims", "notified": 0}
    operator_email = os.environ.get("OPERATOR_EMAIL", os.environ.get("SMTP_USER", ""))
    notified = 0
    for row in overdue_claims:
        c = dict(row)
        days_waiting = 0
        try:
            step_dt = _dt.strptime(c["step_updated_at"][:19], "%Y-%m-%d %H:%M:%S")
            days_waiting = (_dt.utcnow() - step_dt).days
        except Exception:
            days_waiting = 14
        insurer = c.get("insurer_name", "Baloise")
        machine = c.get("machine_type", "N/A")
        serial = c.get("serial_no", "N/A")
        html = f"""<div style="font-family:Arial;max-width:600px;margin:auto;background:#fff;padding:20px;border-radius:8px">
<h2 style="color:#dc2626">Keine Antwort vom Versicherer - {days_waiting} Tage</h2>
<table style="width:100%;border-collapse:collapse;margin:15px 0">
<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold">Schadenfall</td><td style="padding:8px;border:1px solid #ddd">{c['id']}</td></tr>
<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold">Versicherer</td><td style="padding:8px;border:1px solid #ddd">{insurer}</td></tr>
<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold">Maschine</td><td style="padding:8px;border:1px solid #ddd">{machine} (SN: {serial})</td></tr>
<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold">Wartezeit</td><td style="padding:8px;border:1px solid #ddd;color:#dc2626;font-weight:bold">{days_waiting} Tage</td></tr>
<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold">Zugewiesen an</td><td style="padding:8px;border:1px solid #ddd">{c.get('assigned_to', 'Vali')}</td></tr>
</table>
<p style="color:#dc2626;font-weight:bold">Empfehlung: Nachfassen beim Versicherer {insurer}</p>
</div>"""
        subject = f"[REMINDER] Keine Antwort - {c['id']} - {machine} - {days_waiting} Tage"
        if operator_email:
            _send_email_html([operator_email], subject, html)
            notified += 1
    emit_hook("claim.followup_check", f"Claim follow-up: {notified} overdue notifications sent",
              entity_type="system", entity_id="claim_followup", tags=["claim", "followup", "cron"], relevance_score=6)
    return {"ok": True, "notified": notified, "overdue_count": len(overdue_claims)}

# Register claim followup cron job
try:
    if not _fs_get("cron_jobs", "cron_claim_followup"):
        _fs_set("cron_jobs", "cron_claim_followup", {
            "name": "Claim Follow-up (14 Tage)",
            "description": "Check machinery claims waiting for insurer response >14 days, notify broker",
            "schedule": "0 10 * * 1-5", "task_type": "claim_followup",
            "parameters": {"reminder_days": 14}, "is_active": True,
        });
except Exception:
    pass


