                _sn = _fd.get("schadensnummer") or _fd.get("schadennummer") or _fd.get("schadensnr") or ""
                _vs = _fd.get("versicherungsschein_nr") or _fd.get("vs_nr") or ""
                _primary = _sn or _vs or _sub.get("ticket_code", "")
                _status_map = {"validated":"Validiert","forwarded":"Weitergeleitet","closed":"Geschlossen","incomplete":"Unvollständig","submitted":"Eingereicht","sent":"Gesendet","draft":"Entwurf","in_progress":"In Bearbeitung"}
                _st = _status_map.get(_sub.get("status",""), _sub.get("status","?"))
                # Build comprehensive response with ALL available data
                _hergang = _fd.get("unfallhergang") or _fd.get("schadenhergang") or _fd.get("schaden_hergang") or _fd.get("damage_description") or ""
