                _r = dict(_r)
                _akt = _r.get("ticket_code","") or _r.get("reference_number","")
                _events = []
                if _r.get("created_at",""): _events.append(f"Erstellt: {_r['created_at'][:16]}")
                if _r.get("email_opened_at",""): _events.append(f"Email gelesen: {_r['email_opened_at'][:16]}")
                if _r.get("form_viewed_at",""): _events.append(f"Formular geöffnet: {_r['form_viewed_at'][:16]}")
