                _total = sum(_status_counts.values())
                _completed = _status_counts.get("validated", 0) + _status_counts.get("submitted", 0) + _status_counts.get("processing", 0) + _status_counts.get("review", 0)
                _completion_rate = round((_completed / _total * 100) if _total > 0 else 0, 1)
