# ── Streaming Chat Endpoint ──────────────────────────────────────────────────
from starlette.responses import StreamingResponse as _StreamingResponse

@app.post("/api/chat/stream")
async def api_chat_stream(request: _Request):
    """Streaming chat endpoint — sends SSE events as the AI generates tokens."""
    try:
        body = await request.json()
    except Exception:
        return _StreamingResponse(
            iter([f'data: {json.dumps({"error": "Invalid JSON body"})}\n\n']),
            media_type="text/event-stream"
        )

    user_message = (body.get("message") or "").strip()
    if not user_message:
        return _StreamingResponse(
            iter([f'data: {json.dumps({"error": "No message provided"})}\n\n']),
            media_type="text/event-stream"
        )

    # Session management
    _session_id_in = body.get("session_id")
    _session_id, _session = _chat_session_get(_session_id_in)

    # Fast path for greetings (non-streaming)
    _msg_lower = user_message.lower().strip()
    _GREETINGS_STREAM = {"hallo", "hi", "hey", "guten tag", "guten morgen", "guten abend",
                         "buna", "salut", "buna ziua", "hello", "good morning", "moin"}
    if _msg_lower in _GREETINGS_STREAM:
        _fast = "Hallo! \U0001f44b Ich bin Alex, dein KI-Versicherungsassistent. Wie kann ich dir helfen?\n\nVerfuegbare Befehle: CMD1 (Status), CMD2 (Reminder), CMD3 (Historie), CMD4 (Formular), CMD5 (Schliessen), CMD6 (Frage), CMD8 (Bericht)."
        _chat_session_append(_session_id, user_message, _fast)

        async def _fast_gen():
            yield f'data: {json.dumps({"text": _fast})}\n\n'
            yield f'data: {json.dumps({"done": True, "full_response": _fast, "session_id": _session_id})}\n\n'
        return _StreamingResponse(_fast_gen(), media_type="text/event-stream")

    async def _stream_gen():
        try:
            import anthropic as _anth_s
            import httpx as _httpx_s
            _client_s = _anth_s.Anthropic(api_key=os.environ.get("ANTHROPIC_API_KEY", ""), timeout=_httpx_s.Timeout(120.0, connect=10.0))

            tier = _context_tier(user_message)
            _live_context = _chat_build_context(user_message=user_message, tier=tier)

            # Build system prompt (same as non-streaming)
            _system_s = f"""Du bist Alex, ein professioneller KI-Versicherungsassistent fuer Makler.
Antworte auf Deutsch. Sei kurz, professionell und hilfreich.
Erfinde KEINE Daten. Nutze NUR den Live-Kontext und die Tools.

LIVE-KONTEXT (aktuell, direkt aus der Datenbank):
{_live_context}"""

            # Build messages from session
            _messages_s = []
            _sess_msgs = _session.get("messages", [])[-10:]
            for _h in _sess_msgs:
                _role = _h.get("role", "user")
                _content = _h.get("content", "")
                if _role in ("user", "assistant") and _content:
                    _messages_s.append({"role": _role, "content": _content})
            _messages_s.append({"role": "user", "content": user_message})

            # Stream from Anthropic (no tools for streaming — simpler path)
            full_text = ""
            with _client_s.messages.stream(
                model="claude-sonnet-4-20250514",
                max_tokens=1024,
                system=_system_s,
                messages=_messages_s
            ) as stream:
                for text_chunk in stream.text_stream:
                    full_text += text_chunk
                    yield f'data: {json.dumps({"text": text_chunk})}\n\n'

            # Post-process
            import re as _re_s
            full_text = _re_s.sub(r'<[a-zA-Z_][a-zA-Z0-9_-]*(?:\s[^>]*)?>.*?</[a-zA-Z_][a-zA-Z0-9_-]*>', '', full_text, flags=_re_s.DOTALL)
            full_text = _re_s.sub(r'</?[a-zA-Z_][a-zA-Z0-9_:-]*(?:\s[^>]*)?/?>', '', full_text)
            full_text = _re_s.sub(r'\n{3,}', '\n\n', full_text).strip()

            _chat_session_append(_session_id, user_message, full_text)
            yield f'data: {json.dumps({"done": True, "full_response": full_text, "session_id": _session_id})}\n\n'
        except Exception as _e_stream:
            _log.warning(f"Streaming chat error: {_e_stream}")
            yield f'data: {json.dumps({"error": str(_e_stream), "session_id": _session_id})}\n\n'

    return _StreamingResponse(_stream_gen(), media_type="text/event-stream")


