# ── 1. Background Scheduler (APScheduler) ─────────────────────────────────────
from apscheduler.schedulers.asyncio import AsyncIOScheduler

_scheduler = AsyncIOScheduler()

async def _scheduled_imap_poll():
    """Poll IMAP every 5 minutes for CMD emails."""
    try:
        result = await poll_inbox_for_commands()
        processed = result.get("processed", 0) if isinstance(result, dict) else 0
        if processed > 0:
            _log.info(f"Scheduled IMAP poll: processed {processed} email(s)")
    except Exception as e:
        _log.warning(f"Scheduled IMAP poll failed: {e}")

async def _scheduled_overdue_check():
    """Check for overdue submissions every 2 hours."""
    try:
        from datetime import datetime as _oc_dt, timedelta as _oc_td
        _4days_ago = (_oc_dt.utcnow() - _oc_td(days=4)).isoformat()
        _all_subs_oc = _cached_fs_all("form_submissions", ttl=120)
        _overdue = [s for s in _all_subs_oc
                    if s.get("status") in ("incomplete", "incomplete_resent", "sent")
                    and s.get("created_at", "") < _4days_ago]
        if _overdue:
            _log.info(f"Overdue check: {len(_overdue)} case(s) overdue >4 days")
    except Exception as e:
        _log.warning(f"Scheduled overdue check failed: {e}")

async def _scheduled_auto_remind():
    """Auto-send reminders for incomplete forms older than 2 days. Queries Firestore directly."""
    try:
        from datetime import timedelta as _remind_td, datetime as _remind_dt
        _2days_ago = (_remind_dt.utcnow() - _remind_td(days=2)).isoformat()
        _all_subs_remind = _fs_all("form_submissions", limit=1000)
        stale = [s for s in _all_subs_remind
                 if s.get("status") in ("incomplete", "incomplete_resent", "sent")
                 and (int(s.get("reminder_count") or 0) if str(s.get("reminder_count", 0)).isdigit() else 0) < 3
                 and (s.get("created_at") or "") < _2days_ago
                 and (not s.get("last_reminder_at") or s["last_reminder_at"] < _2days_ago)][:5]
        _reminded = 0
        for row in stale:
            r = dict(row)
            _sub_id = r.get("_id", r.get("id", ""))
            _client_email = r.get("client_email", "")
            _tpl_id = r.get("template_id", "")
            if not _client_email or not _sub_id:
                continue
            try:
                _form_url = f"{os.environ.get('APP_HOST', '')}/forms/{_tpl_id}?sub={_sub_id}"
                _send_email_html(
                    [_client_email],
                    f"Erinnerung: Bitte füllen Sie Ihr Formular aus",
                    f"<p>Sehr geehrte(r) {r.get('client_name', '')},</p>"
                    f"<p>Bitte füllen Sie Ihr Versicherungsformular aus:</p>"
                    f"<p><a href='{_form_url}'>Formular öffnen</a></p>",
                    auto_bcc_operator=True
                )
                _rc = int(r.get("reminder_count") or 0) + 1
                _fs_set("form_submissions", _sub_id, {
                    "reminder_count": _rc,
                    "last_reminder_at": _remind_dt.utcnow().isoformat()
                }, merge=True)
                _reminded += 1
                _log.info(f"Auto-reminder sent: {r.get('ticket_code', _sub_id)} -> {_client_email} (reminder #{_rc})")
            except Exception as _send_e:
                _log.warning(f"Auto-remind send failed for {_sub_id}: {_send_e}")
        if _reminded:
            _log.info(f"Auto-remind complete: {_reminded}/{len(stale)} reminders sent")
    except Exception as e:
        _log.warning(f"Scheduled auto-remind failed: {e}")

@app.on_event("startup")
async def _start_scheduler():
    _scheduler.add_job(_scheduled_imap_poll, 'interval', minutes=2, id='imap_poll', replace_existing=True)
    _scheduler.add_job(_scheduled_overdue_check, 'interval', hours=2, id='overdue_check', replace_existing=True)
    _scheduler.add_job(_scheduled_auto_remind, 'interval', hours=6, id='auto_remind', replace_existing=True)
    _scheduler.add_job(_wiki_daily_digest, 'cron', hour=0, minute=5, id='wiki_daily_digest', replace_existing=True)
    _scheduler.add_job(_chat_session_cleanup, 'interval', minutes=10, id='chat_session_cleanup', replace_existing=True)
    _scheduler.start()
    _log.info("Alex Agent Scheduler started: IMAP/5min, Overdue/2h, AutoRemind/6h, WikiDigest/midnight, SessionCleanup/10min")


