@app.get("/api/knowledge/patterns")
async def api_knowledge_patterns_list():
    """Analyze alex_knowledge entries to extract patterns (hook types, common actions, peak hours)."""
    # First check stored patterns
    stored = _fs_query("knowledge_patterns", order_by=("created_at",), limit=50)
    stored_entries = []
    for d in stored:
        d["id"] = d.pop("_id")
        stored_entries.append(d)

    # Analyze alex_knowledge collection for dynamic patterns
    knowledge_docs = _fs_all("alex_knowledge", limit=500)
    if not knowledge_docs:
        return {"total_entries": len(stored_entries), "entries": stored_entries, "analysis": {}}

    # Aggregate patterns from knowledge entries
    from collections import Counter
    type_counts = Counter()
    tool_counts = Counter()
    hour_counts = Counter()
    category_counts = Counter()
    total_interactions = 0

    for doc in knowledge_docs:
        _type = doc.get("type", "unknown")
        type_counts[_type] += 1
        if _type == "interaction":
            total_interactions += 1
        # Count tools used
        for tool in (doc.get("tools_used") or []):
            tool_counts[tool] += 1
        # Count hours for peak analysis
        created = doc.get("created_at", "")
        if created and len(created) >= 13:
            try:
                _hour = int(created[11:13])
                hour_counts[_hour] += 1
            except (ValueError, IndexError):
                pass
        # Count categories
        cat = doc.get("category", "")
        if cat:
            category_counts[cat] += 1

    # Build peak hours (top 3)
    peak_hours = [{"hour": h, "count": c} for h, c in hour_counts.most_common(5)]
    # Build top tools
    top_tools = [{"tool": t, "count": c} for t, c in tool_counts.most_common(10)]
    # Build type distribution
    type_dist = [{"type": t, "count": c} for t, c in type_counts.most_common(10)]

    analysis = {
        "total_knowledge_entries": len(knowledge_docs),
        "total_interactions": total_interactions,
        "type_distribution": type_dist,
        "most_used_tools": top_tools,
        "peak_activity_hours": peak_hours,
        "categories": [{"category": c, "count": n} for c, n in category_counts.most_common(10)],
    }

    return {"total_entries": len(stored_entries), "entries": stored_entries, "analysis": analysis}

@app.get("/api/knowledge/patterns/{pattern_id}")
async def api_knowledge_pattern_get(pattern_id: str):
    """Get a specific knowledge pattern and increment its used_count."""
    d = _fs_get("knowledge_patterns", pattern_id)
    if not d:
        return JSONResponse({"error": "Pattern not found"}, status_code=404)
    # Increment used_count
    new_count = (d.get("used_count") or 0) + 1
    _fs_set("knowledge_patterns", pattern_id, {"used_count": new_count}, merge=True)
    d["id"] = pattern_id
    d["used_count"] = new_count
    return d


# ── Wiki Semantic Search — BM25 in-memory index ──────────────────────────────

import math as _math_bm25
from collections import Counter as _Counter_bm25

class _SimpleSearchIndex:
    """Lightweight BM25 search index for wiki pages. No external dependencies."""
    def __init__(self):
        self.docs = {}       # id -> {title, content, tokens, tf}
        self.df = _Counter_bm25()   # document frequency per term
        self.avg_dl = 0
        self.k1 = 1.5
        self.b = 0.75

    def add(self, doc_id, title, content):
        """Add or update a document in the index."""
        # Remove old doc stats if updating
        if doc_id in self.docs:
            for term in set(self.docs[doc_id]["tokens"]):
                self.df[term] = max(0, self.df.get(term, 0) - 1)
        text = f"{title} {title} {content}".lower()  # title weighted 2x
        tokens = text.split()
        self.docs[doc_id] = {"title": title, "content": content, "tokens": tokens, "tf": _Counter_bm25(tokens)}
        for term in set(tokens):
            self.df[term] += 1
        self._update_avg()

    def remove(self, doc_id):
        """Remove a document from the index."""
        if doc_id in self.docs:
            for term in set(self.docs[doc_id]["tokens"]):
                self.df[term] = max(0, self.df.get(term, 0) - 1)
            del self.docs[doc_id]
            self._update_avg()

    def _update_avg(self):
        if self.docs:
            self.avg_dl = sum(len(d["tokens"]) for d in self.docs.values()) / len(self.docs)

    def search(self, query, limit=5):
        """BM25 search. Returns list of (doc_id, score, title, preview)."""
        query_tokens = query.lower().split()
        scores = []
        N = len(self.docs)
        if N == 0:
            return []
        for doc_id, doc in self.docs.items():
            score = 0
            dl = len(doc["tokens"])
            for term in query_tokens:
                tf = doc["tf"].get(term, 0)
                df = self.df.get(term, 0)
                if df == 0:
                    # Fuzzy: try substring match on tokens
                    for tok in doc["tf"]:
                        if term in tok or tok in term:
                            tf += doc["tf"][tok] * 0.5
                            df += 1
                    if df == 0:
                        continue
                idf = _math_bm25.log((N - df + 0.5) / (df + 0.5) + 1)
                score += idf * (tf * (self.k1 + 1)) / (tf + self.k1 * (1 - self.b + self.b * dl / max(self.avg_dl, 1)))
            # Bonus for title match
            title_lower = doc["title"].lower()
            for term in query_tokens:
                if term in title_lower:
                    score += 2.0
            if score > 0:
                scores.append((doc_id, score, doc["title"], doc["content"][:300]))
        scores.sort(key=lambda x: -x[1])
        return scores[:limit]


_wiki_search_index = _SimpleSearchIndex()


def _rebuild_wiki_index():
    """Rebuild the BM25 search index from all wiki pages in Firestore.
    Retries up to 3 times with 3s delay if Firestore returns empty (cold start)."""
    import time as _wiki_time
    for _attempt in range(1, 4):
        try:
            all_pages = _fs_all("alex_wiki", limit=500) or []
            if not all_pages and _attempt < 3:
                _log.info(f"[wiki-search] Firestore returned 0 pages on attempt {_attempt}/3, retrying in 3s...")
                _wiki_time.sleep(3)
                continue
            count = 0
            for p in all_pages:
                pid = p.get("_id") or p.get("id", "")
                if pid:
                    _wiki_search_index.add(pid, p.get("title", ""), p.get("content", ""))
                    count += 1
            _log.info(f"Wiki search index rebuilt: {len(all_pages)} pages")
            return
        except Exception as _e:
            _log.warning(f"[wiki-search] Index rebuild failed (attempt {_attempt}/3): {_e}")
            if _attempt < 3:
                _wiki_time.sleep(3)
    _log.warning("[wiki-search] Index rebuild exhausted all 3 retries")


