@app.get("/api/wiki/graph")
async def api_wiki_graph():
    """Return nodes and edges for the wiki graph view."""
    import re as _re_g
    all_pages = _fs_all("alex_wiki", limit=500)
    title_to_id = {}
    nodes = []
    for p in all_pages:
        pid = p.get("_id", "")
        title = p.get("title", "")
        tags = p.get("tags", [])
        title_to_id[title.lower()] = pid
        # Color by first tag
        color = "#94a3b8"  # default gray
        for t in tags:
            tl = t.lower()
            if tl == "client":
                color = "#3b82f6"; break
            elif tl == "template":
                color = "#22c55e"; break
            elif tl == "case":
                color = "#f97316"; break
            elif tl in ("auto", "activity", "log"):
                color = "#94a3b8"; break
        nodes.append({"id": pid, "title": title, "tags": tags, "color": color,
                       "auto_generated": p.get("auto_generated", False)})
    edges = []
    link_pat = _re_g.compile(r"\[\[([^\]]+)\]\]")
    seen_edges = set()
    for p in all_pages:
        pid = p.get("_id", "")
        content = p.get("content", "")
        for m in link_pat.finditer(content):
            linked_title = m.group(1).strip().lower()
            target_id = title_to_id.get(linked_title)
            if target_id and target_id != pid:
                edge_key = f"{pid}->{target_id}"
                if edge_key not in seen_edges:
                    seen_edges.add(edge_key)
                    edges.append({"source": pid, "target": target_id})
    # ── Implicit edges: client names in other pages' content ──────────────
    _client_pages = {p.get("_id"): p.get("title", "") for p in all_pages if "client" in [t.lower() for t in p.get("tags", [])]}
    _template_pages = {p.get("_id"): p.get("title", "") for p in all_pages if "template" in [t.lower() for t in p.get("tags", [])]}
    for p in all_pages:
        pid = p.get("_id", "")
        content_lower = (p.get("content", "") or "").lower()
        # If a client name appears in another page's content, add edge
        for cid, ctitle in _client_pages.items():
            if cid != pid and ctitle and ctitle.lower() in content_lower:
                edge_key = f"{pid}->{cid}"
                if edge_key not in seen_edges:
                    seen_edges.add(edge_key)
                    edges.append({"source": pid, "target": cid, "type": "implicit"})
        # Connect Client pages to Template pages via shared submission data
        if pid in _client_pages:
            for tp_id, tp_title in _template_pages.items():
                if tp_title and tp_title.lower() in content_lower:
                    edge_key = f"{pid}->{tp_id}"
                    if edge_key not in seen_edges:
                        seen_edges.add(edge_key)
                        edges.append({"source": pid, "target": tp_id, "type": "template_link"})

    return {"nodes": nodes, "edges": edges}


@app.post("/api/wiki/query")
async def api_wiki_query(request: _Request):
    """Dataview-style query for wiki pages or form_submissions."""
    body = await request.json()
    collection = body.get("collection", "alex_wiki")
    filter_str = body.get("filter", "")
    search_str = body.get("search", "").lower().strip()
    sort_field = body.get("sort", "updated_at")
    sort_dir = body.get("sort_dir", "desc")
    limit = min(int(body.get("limit", 50)), 200)

    if collection == "form_submissions":
        all_docs = _fs_all("form_submissions", limit=5000)
        for d in all_docs:
            d = _fs_sub_to_dict(d)
    else:
        all_docs = _fs_all("alex_wiki", limit=500)

    results = []
    for d in all_docs:
        if not _wiki_query_match(d, filter_str, collection):
            continue
        if search_str:
            haystack = json.dumps(d, default=str).lower()
            if search_str not in haystack:
                continue
        results.append(d)

    # Sort
    reverse = sort_dir.lower() == "desc"
    results.sort(key=lambda x: str(x.get(sort_field, "")), reverse=reverse)
    results = results[:limit]

    # Slim down for response
    slim = []
    for r in results:
        if collection == "form_submissions":
            slim.append({
                "id": r.get("_id", ""),
                "client_name": r.get("client_name", ""),
                "template_id": r.get("template_id", ""),
                "status": r.get("status", ""),
                "completeness_pct": r.get("completeness_pct", 0),
                "updated_at": r.get("updated_at", r.get("created_at", "")),
            })
        else:
            slim.append({
                "id": r.get("_id", ""),
                "title": r.get("title", ""),
                "tags": r.get("tags", []),
                "updated_at": r.get("updated_at", r.get("created_at", "")),
                "auto_generated": r.get("auto_generated", False),
            })
    return {"results": slim, "total": len(slim), "collection": collection}


