@app.post("/api/wiki")
async def api_wiki_create(request: _Request):
    """Create a new wiki page."""
    from datetime import datetime as _dt
    body = await request.json()
    title = body.get("title", "").strip()
    if not title:
        return JSONResponse({"error": "title is required"}, status_code=400)
    now = _dt.utcnow().isoformat()
    _content = body.get("content", "")
    page_id = _fs_add("alex_wiki", {
        "title": title,
        "content": _content,
        "tags": body.get("tags", []),
        "auto_generated": body.get("auto_generated", False),
        "created_at": now,
        "updated_at": now,
    })
    # Add to BM25 search index
    _wiki_search_index.add(page_id, title, _content)
    return {"ok": True, "id": page_id, "title": title}


@app.put("/api/wiki/{page_id}")
async def api_wiki_update(page_id: str, request: _Request):
    """Update a wiki page."""
    from datetime import datetime as _dt
    existing = _fs_get("alex_wiki", page_id)
    if not existing:
        return JSONResponse({"error": "Wiki page not found"}, status_code=404)
    body = await request.json()
    update_data = {"updated_at": _dt.utcnow().isoformat()}
    if "content" in body:
        update_data["content"] = body["content"]
    if "tags" in body:
        update_data["tags"] = body["tags"]
    if "title" in body:
        update_data["title"] = body["title"]
    _fs_set("alex_wiki", page_id, update_data, merge=True)
    # Update BM25 search index
    _updated_title = body.get("title", existing.get("title", ""))
    _updated_content = body.get("content", existing.get("content", ""))
    _wiki_search_index.add(page_id, _updated_title, _updated_content)
    return {"ok": True, "id": page_id}


@app.delete("/api/wiki/{page_id}")
async def api_wiki_delete(page_id: str):
    """Delete a wiki page."""
    existing = _fs_get("alex_wiki", page_id)
    if not existing:
        return JSONResponse({"error": "Wiki page not found"}, status_code=404)
    _fs_delete("alex_wiki", page_id)
    # Remove from BM25 search index
    _wiki_search_index.remove(page_id)
    return {"ok": True, "id": page_id}


@app.get("/api/wiki/{page_id}/backlinks")
async def api_wiki_backlinks(page_id: str):
    """Find all wiki pages that link to this page via [[Page Title]] pattern."""
    import re as _re_bl
    target = _fs_get("alex_wiki", page_id)
    if not target:
        return JSONResponse({"error": "Wiki page not found"}, status_code=404)
    target_title = target.get("title", "")
    if not target_title:
        return {"backlinks": []}
    all_pages = _fs_all("alex_wiki", limit=500)
    backlinks = []
    pattern = _re_bl.compile(r"\[\[" + _re_bl.escape(target_title) + r"\]\]", _re_bl.IGNORECASE)
    for p in all_pages:
        pid = p.get("_id", "")
        if pid == page_id:
            continue
        content = p.get("content", "")
        if pattern.search(content):
            backlinks.append({
                "id": pid,
                "title": p.get("title", ""),
                "tags": p.get("tags", []),
                "updated_at": p.get("updated_at", ""),
            })
    return {"backlinks": backlinks, "target_title": target_title}


@app.post("/api/wiki/semantic-search")
async def api_wiki_semantic_search(request: _Request):
    """Semantic search over wiki pages using BM25 ranking."""
    body = await request.json()
    query = body.get("query", "").strip()
    limit = min(int(body.get("limit", 5)), 20)
    if not query:
        return JSONResponse({"error": "query is required"}, status_code=400)

    # Rebuild index if empty (lazy init)
    if not _wiki_search_index.docs:
        _rebuild_wiki_index()
    _log.info(f"Wiki search index: {len(_wiki_search_index.docs)} docs")

    results = _wiki_search_index.search(query, limit=limit)
    return {
        "ok": True,
        "query": query,
        "results": [
            {"id": doc_id, "score": round(score, 3), "title": title, "preview": preview}
            for doc_id, score, title, preview in results
        ],
        "total": len(results),
    }


def _wiki_semantic_search_for_chat(query: str, limit: int = 5) -> str:
    """Run semantic search and return formatted results for chat context."""
    if not _wiki_search_index.docs:
        _rebuild_wiki_index()
    results = _wiki_search_index.search(query, limit=limit)
    if not results:
        return ""
    lines = []
    for doc_id, score, title, preview in results:
        lines.append(f"  [{round(score, 1)}] **{title}**: {preview[:200]}")
    return "\n".join(lines)


def _wiki_query_match(doc: dict, filter_str: str, collection: str) -> bool:
    """Check if a document matches a dataview filter string."""
    if not filter_str.strip():
        return True
    parts = [f.strip() for f in filter_str.split(",") if f.strip()]
    for part in parts:
        if part.startswith("tag:"):
            tag_val = part[4:].strip().lower()
            tags = [t.lower() for t in (doc.get("tags") or [])]
            if tag_val not in tags:
                return False
        elif part.startswith("title:"):
            title_val = part[6:].strip().lower()
            if title_val not in (doc.get("title") or "").lower():
                return False
        elif part.startswith("content:"):
            content_val = part[8:].strip().lower()
            if content_val not in (doc.get("content") or "").lower():
                return False
        elif part.startswith("created_after:"):
            date_val = part[14:].strip()
            if (doc.get("created_at") or "") < date_val:
                return False
        elif part.startswith("updated_after:"):
            date_val = part[14:].strip()
            if (doc.get("updated_at") or "") < date_val:
                return False
        elif part.startswith("status:"):
            status_val = part[7:].strip().lower()
            if (doc.get("status") or "").lower() != status_val:
                return False
        elif "completeness" in part and ("<" in part or ">" in part):
            import re as _re_q
            m = _re_q.match(r"completeness\s*([<>]=?)\s*(\d+)", part)
            if m:
                op, val = m.group(1), int(m.group(2))
                comp = int(doc.get("completeness_pct", doc.get("completeness", 0)) or 0)
                if op == "<" and not (comp < val):
                    return False
                elif op == "<=" and not (comp <= val):
                    return False
                elif op == ">" and not (comp > val):
                    return False
                elif op == ">=" and not (comp >= val):
                    return False
    return True


def _wiki_upsert(title: str, content: str, tags: list = None, auto_generated: bool = True):
    """Create or update a wiki page by title (used by auto-populate hooks)."""
    from datetime import datetime as _dt
    try:
        all_pages = _fs_all("alex_wiki", limit=500)
        existing = None
        existing_id = None
        for p in all_pages:
            if p.get("title", "").strip().lower() == title.strip().lower():
                existing = p
                existing_id = p.get("_id")
                break
        now = _dt.utcnow().isoformat()
        if existing and existing_id:
            _fs_set("alex_wiki", existing_id, {
                "content": content,
                "tags": tags or existing.get("tags", []),
                "updated_at": now,
                "auto_generated": auto_generated,
            }, merge=True)
            # Update BM25 search index
            _wiki_search_index.add(existing_id, title, content)
            return existing_id
        else:
            page_id = _fs_add("alex_wiki", {
                "title": title,
                "content": content,
                "tags": tags or [],
                "auto_generated": auto_generated,
                "created_at": now,
                "updated_at": now,
            })
            # Add to BM25 search index
            _wiki_search_index.add(page_id, title, content)
            return page_id
    except Exception as _e:
        _log.warning(f"Wiki upsert failed for '{title}': {_e}")
        return None


def _wiki_append_log(title: str, entry: str, tags: list = None):
    """Append a timestamped entry to a wiki log page (e.g., Activity Log)."""
    from datetime import datetime as _dt
    try:
        all_pages = _fs_all("alex_wiki", limit=500)
        existing = None
        existing_id = None
        for p in all_pages:
            if p.get("title", "").strip().lower() == title.strip().lower():
                existing = p
                existing_id = p.get("_id")
                break
        now = _dt.utcnow().isoformat()
        timestamp = _dt.utcnow().strftime("%Y-%m-%d %H:%M")
        new_entry = f"- [{timestamp}] {entry}"
        if existing and existing_id:
            old_content = existing.get("content", "")
            # Keep last 100 log entries to avoid unbounded growth
            lines = old_content.strip().split("\n") if old_content.strip() else []
            lines.insert(0, new_entry)
            lines = lines[:100]
            _fs_set("alex_wiki", existing_id, {
                "content": "\n".join(lines),
                "updated_at": now,
            }, merge=True)
        else:
            _fs_add("alex_wiki", {
                "title": title,
                "content": new_entry,
                "tags": tags or ["activity", "log"],
                "auto_generated": True,
                "created_at": now,
                "updated_at": now,
            })
    except Exception as _e:
        _log.warning(f"Wiki append log failed for '{title}': {_e}")


def _wiki_daily_digest():
    """Create/update a Daily Digest wiki page with summary stats for today."""
    from datetime import datetime as _dt, timedelta as _td
    try:
        today = _dt.utcnow().strftime("%Y-%m-%d")
        today_start = today + "T00:00:00"
        all_subs = _fs_all("form_submissions", limit=5000)

        # New cases today
        new_today = [s for s in all_subs if (s.get("created_at") or "") >= today_start]
        # Completed today
        completed_today = [s for s in all_subs
                          if int(s.get("completeness_pct", 0) or 0) >= 100
                          and (s.get("submitted_at") or s.get("updated_at") or "") >= today_start]
        # Overdue: incomplete and older than 4 days
        four_days_ago = (_dt.utcnow() - _td(days=4)).isoformat()
        overdue = [s for s in all_subs
                  if int(s.get("completeness_pct", 0) or 0) < 100
                  and s.get("status") not in ("closed", "validated", "forwarded")
                  and (s.get("created_at") or "") < four_days_ago]
        # Top 5 needing attention: lowest completeness, oldest
        attention = sorted(
            [s for s in all_subs if s.get("status") not in ("closed", "validated", "forwarded")
             and int(s.get("completeness_pct", 0) or 0) < 100],
            key=lambda x: (int(x.get("completeness_pct", 0) or 0), x.get("created_at", ""))
        )[:5]
        # Reminders sent today
        reminders_today = [s for s in all_subs
                          if (s.get("last_reminder_at") or "") >= today_start
                          or (s.get("reminder_count", 0) or 0) > 0 and (s.get("updated_at") or "") >= today_start]

        # Build content
        attention_lines = []
        for s in attention:
            _tk = s.get("ticket_code") or s.get("reference_number") or "?"
            _nm = s.get("client_name") or "Unknown"
            _comp = int(s.get("completeness_pct", 0) or 0)
            _created = (s.get("created_at") or "?")[:10]
            attention_lines.append(f"- [[Case: {_tk}]] — {_nm} — {_comp}% — created {_created}")
        attention_section = "\n".join(attention_lines) if attention_lines else "- (None)"

        content = (
            f"## Daily Digest — {today}\n\n"
            f"### Summary Stats\n"
            f"| Metric | Count |\n"
            f"|--------|-------|\n"
            f"| New cases today | {len(new_today)} |\n"
            f"| Completed today | {len(completed_today)} |\n"
            f"| Total overdue (>4 days) | {len(overdue)} |\n"
            f"| Reminders sent today | {len(reminders_today)} |\n"
            f"| Total active cases | {len([s for s in all_subs if s.get('status') not in ('closed', 'validated', 'forwarded')])} |\n\n"
            f"### Top 5 Cases Needing Attention\n"
            f"{attention_section}\n\n"
            f"### Overdue Cases ({len(overdue)})\n"
        )
        for od in overdue[:10]:
            _tk = od.get("ticket_code") or od.get("reference_number") or "?"
            _nm = od.get("client_name") or "Unknown"
            _comp = int(od.get("completeness_pct", 0) or 0)
            content += f"- [[Case: {_tk}]] — {_nm} — {_comp}%\n"
        if not overdue:
            content += "- (None)\n"

        _wiki_upsert(
            title=f"Daily Digest — {today}",
            content=content,
            tags=["digest", "daily", "auto", today],
        )
        _log.info(f"Daily digest created for {today}: {len(new_today)} new, {len(completed_today)} completed, {len(overdue)} overdue")
        return {
            "date": today,
            "new_today": len(new_today),
            "completed_today": len(completed_today),
            "overdue": len(overdue),
            "attention": len(attention),
            "reminders_today": len(reminders_today),
        }
    except Exception as _e:
        _log.warning(f"Daily digest generation failed: {_e}")
        return {"error": str(_e)}


# ── 3. Activity Tracking — email opens, form views ───────────────────────────

@app.get("/api/track/email/{sub_id}")
async def track_email_open_submission(sub_id: str):
    """1x1 tracking pixel for form submission email opens."""
    try:
        _now = __import__("datetime").datetime.utcnow().isoformat()
        existing = _fs_get("form_submissions", sub_id)
        if existing and not existing.get("email_opened_at"):
            _fs_set("form_submissions", sub_id, {
                "email_opened_at": _now, "last_activity_at": _now
            }, merge=True)
    except Exception:
        pass
    gif_bytes = b'\x47\x49\x46\x38\x39\x61\x01\x00\x01\x00\x80\x00\x00\xff\xff\xff\x00\x00\x00\x21\xf9\x04\x00\x00\x00\x00\x00\x2c\x00\x00\x00\x00\x01\x00\x01\x00\x00\x02\x02\x44\x01\x00\x3b'
    return Response(content=gif_bytes, media_type="image/gif")

@app.post("/api/track/form-view/{sub_id}")
async def track_form_view(sub_id: str):
    """Track when client opens the form link."""
    try:
        _now = __import__("datetime").datetime.utcnow().isoformat()
        existing = _fs_get("form_submissions", sub_id)
        if existing and not existing.get("form_viewed_at"):
            _fs_set("form_submissions", sub_id, {
                "form_viewed_at": _now, "last_activity_at": _now
            }, merge=True)
    except Exception:
        pass
    return {"ok": True}

@app.get("/api/scheduler/status")
async def api_scheduler_status():
    """Return the status of all scheduled jobs."""
    jobs = []
    for job in _scheduler.get_jobs():
        jobs.append({
            "id": job.id,
            "next_run": str(job.next_run_time) if job.next_run_time else None,
            "trigger": str(job.trigger),
        })
    return {"running": _scheduler.running, "jobs": jobs}


